INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (18, '125807', '풍수원성당', 32, 18, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '횡성 풍수원 천주교회(풍수원 성당)는 1800년대 초, 박해를 피해 경기도 용인에서 신태보(베드로)를 중심으로 한 40여 명의 신자들이 피난처를 찾아 정착한 곳이다. 풍수원 본당은 한때 춘천, 원주, 화천, 양구, 홍천, 횡성, 평창, 양평 등 12개 군의 29개 공소를 관할하였으며, 1896년 원주 본당의 분리를 시작으로 1920년에는 춘천 본당, 1948년에는 홍천 본당이 각각 분리되었다. 강원도 횡성군 서원면 유현리에 위치한 풍수원 성당은 1982년 강원도 유형문화유산으로 지정되었다. 나지막한 언덕 위에 서남 방향으로 자리 잡은 본 성당 건물은 열주(列柱) 아케이드와 천장 구조에 의해 신랑과 측량이 구분되는 삼랑식 평면으로 구성되어 있다. 전면 중앙에 돌출되어 위치한 주현관과 2층의 원형 창, 3층의 2연 아치창 및 2연 비늘창으로 이루어진 종루의 구성은 위로 갈수록 좁아지는 부벽과 함께 수직성을 강조하며 중앙 입면을 인상적으로 보이게 한다.', '2026-06-29 14:34:12.481');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (20, '128748', '운암정', 32, 18, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '운암정은 강원특별자치도 횡성군 횡성읍 읍하리 산 7-2번지에 위치한 정자로, 횡성교를 건너자마자 오른쪽에 자리하고 있다. 아래로는 섬강이 흐르며 주변의 산수와 어우러져 아름다운 경치를 자랑하는 지역 주민들의 휴식처이다. 이 정자는 1937년 횡성 출신의 김한갑과 이원직이 공동으로 건립하였다. 두 사람은 같은 동네에서 가난하게 자라났으나 노력 끝에 성공하여 부를 이루었고, 회갑을 맞아 입지의 결실을 기념하고자 정자를 세웠다. 공사비는 두 사람이 절반씩 부담하였으며, 아호인 ‘운수’(김한갑)와 ‘청암’(이원직)에서 한 자씩 따서 ‘운암정’이라 이름 지었다. 정자는 단층 목조기와집으로, 정면 3칸, 측면 2칸의 팔작지붕 구조를 갖추고 있다. 건물 내부에는 1944년에 작성된 ‘운암정기’ 현판이 걸려 있다. 운암정은 건축미뿐 아니라 건립자의 삶과 지역사회 기여 정신을 보여주는 유산으로 평가된다. 1984년 6월 2일 강원도 문화유산자료로 지정되었다. 오늘날에도 많은 이들이 이곳을 찾아 경치를 즐기며 쉼을 얻고 있다.', '2026-06-29 14:34:12.481');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (13, '2992891', '사직단', 1, 23, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '종묘는 역대 국왕과 왕비의 신위를, 사직은 토지신과 곡신을 모신다는 점이 다르다. 경복궁을 중심으로 왼쪽에는 종묘, 오른쪽에는 사직이 위치하며 이는 유교 국가이자 농업 국가인 조선의 근본을 상징하는 의미가 크다. 따라서 조선시대에 종묘사직은 국가 혹은 왕실의 전통을 상징하는 대명사처럼 쓰였다. 사직단은 그 이름에서 드러나듯 제사를 지내는 제단을 의미하므로 사직단을 찾으면 다른 유적지처럼 중심에 건물이 있는 것이 아니라 텅 빈 제단이 놓여있는 점이 눈에 띈다. 왕릉에도 하나만 세우는 홍살문이 무려 8개나 있는 것만 봐도 이곳이 얼마나 신성한 장소였는지 짐작할 수 있다. 조선시대에는 임금과 왕족, 관련 직무를 맡은 사람만 출입할 수 있었을 정도로 엄격하게 출입이 통제되던 곳이기도 하다.', '2026-06-29 14:34:12.479');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (17, '3489648', '횡성호수길축제', 32, 18, '강원특별자치도 횡성군 갑천면 구방리', 37.549782, 128.062607, 'https://tong.visitkorea.or.kr/cms/resource/06/4063806_image2_1.jpg', NULL, NULL, '횡성호수길 축제는 횡성호수길 5구간에서 이루어지는 축제로 횡성호의 아름다움과 자연속에서 잠시 쉬어가는 “쉼의 축제”다. 횡성댐에 인공으로 조성된 호수를 중심으로 조성된 31.5km 6개 코스 중 9km 길이로 조성된 5구간은 세곳의 전망대와 아기자기한 조형물들이 어우러져 시간의 느림을 만끽할수 있다. 더불어 구방한과 및 갑천에서 생산되는 신선한 농산물을 만날 수 있는 축제이다.', '2026-06-29 14:34:12.481');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (29, '4075415', '고구려대장간마을', 31, 6, '경기도 구리시 우미내길 41 (아천동)', 37.5608078747, 127.1109491707, 'https://tong.visitkorea.or.kr/cms/resource/35/4075435_image2_1.jpg', NULL, NULL, '아차산 자락에 위치한 고구려대장간마을은 지난 2008년 개장한 이래, 2009년 4월 공립박물관으로써 등록을 마쳤으며, 지금까지 아차산 출토 고구려 유물을 상설전시하고, 정기적으로 교체전시를 마련하는 등 명실공히 고구려 전문박물관으로 자리 잡고 있다. 또한, 어린이들뿐 아니라 청소년, 성인, 다문화, 문화소외계층에게 우리 역사를 재미있고 신나게 학습할 수 있도록 고구려 역사와 관련된 체험 학습프로그램을 운영하여 큰 호응을 받고 있다.

(출처 : 고구려대장간마을 홈페이지)', '2026-06-29 14:34:12.485');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (7, '3352874', '국립무형유산원', 37, 12, '전북특별자치도 전주시 완산구 서학로 95 (동서학동)', 35.8098619464, 127.1596491581, NULL, NULL, NULL, '국립무형유산원은 인류의 무형유산을 체계적으로 보호하고, 후손들에게 온전히 전승하기 위해 설립된 세계 최초의 무형유산 복합행정기관이다. 무형유산 전시, 공연, 교육 등 보존과 전승에 앞장서는 한편, 국내·외 교류협력 등 무형유산의 활용 및 지원기능을 담당하고 있다. 우리나라 무형유산의 의미와 가치에 대해 알아볼 수 있는 상설전시실, 다양한 주제들로 꾸며진 기획전시실, 전통의 멋과 흥을 느낄 수 있는 공연장, 해외 무형유산과의 활발한 교류가 이루어지는 국제회의장, 무형유산의 즐거움을 온몸으로 체험할 수 있는 교육 공간 등 분야별 특성에 맞는 시설들을 갖추고 있다.', '2026-06-29 14:34:12.477');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (42, '125906', '보은 법주사 [유네스코 세계유산]', 33, 3, NULL, NULL, NULL, NULL, '- 하절기 04:00~20:00 (입장 마감 18:00)- 동절기 05:00~20:00 (입장 마감 18:00)', '연중무휴', '부처님의 법이 머문다는 뜻의 법주사는 속리산 자락에 위치하고 있으며 신라 진흥왕 14년(서기 553)에 의신조사가 창건하고 성덕왕과 혜공왕이 중창하였는데 이때부터 대찰의 규모를 갖추기 시작하였다. 고려 홍건적의 침입 때는 공민왕이 안동으로 피난을 왔다가 환궁하는 길에 들르기도 하였고 조선 태조는 즉위하기 전 백일기도를 올리기도 하였으며 병에 걸렸던 세조는 복천암에서 사흘 기도를 올리기도 하였다고 한다. 조선 중기에 이르러서는 60여 동의 건물과 70여 개의 암자를 거느린 대찰로서 위용을 떨치게 되었지만, 임진왜란으로 인해 사찰의 거의 모든 건물이 전소되어 1624년 인조 2년에 이르러 벽암스님에 의해 다시 중창하였고 이후에도 여러 차례 중수를 거친 후 오늘에 이른다. 
예전 법주사 가람배치는 대웅보전을 중심으로 하는 화엄신앙축과 용화보전을 중심으로 하는 미륵신앙축이 팔상전에 직각으로 교차하고 있었으나, 1990년 높이가 33미터에 이르는 청동 미륵불을 조성하면서 그 배치가 흩어져 버렸다. 경내에는 대웅보전을 중심으로 용화전, 원통보전, 명부전, 능인전, 조사각, 진영각, 삼성각 등 전각과 종무소를 포함한 10여 채의 요사채들이 남아 있다. 이곳 법주사를 비롯한 속리산 일대에는 보은의 지정 문화재 절반 이상이 몰려 있는데 그중 법주사에는 국보가 3점이나 된다. 또, 천왕문과 사도세자의 어머니 영빈 이 씨의 위패를 모셨던 선희궁 원단, 16 나한을 모시고 있는 능인전, 자기 몸을 태워 부처님께 공양한 희견보살상, 그리고 쌀 80 가마는 너끈히 들어가는 석조와 쇠솥 등이 그것이다. 법주사는 천 년이 넘는 역사를 통한 미륵신앙이 전해져 내려왔던 곳으로써 기도와 예불 수행 등 기초적인 불교문화 체험을 할 수 있도록 템플스테이를 진행하고 있다.
팔상전은 5층 목탑으로서 우리나라 목탑 연구에 중요한 자료가 되며, 신라 진흥왕 때에 의신이 세웠고 776년 병진이 중창해 1597년 정유재란 때 소실된 것을 1605년에 재건하여 오늘에 이르고 있다. 벽면에 부처의 일생을 8장면으로 구분하여 그린 팔상도가 그려져 있어 팔상전이라 이름 붙였다. 팔상전은 1984년에 쌍봉사의 대웅전으로 쓰이고 있던 3층 목조탑이 소실됨으로써 한국 목조탑의 유일한 실례가 된 중요한 건축물로 전체높이가 상륜까지 22.7m이며 현존하는 한국의 탑파 중 제일 높은 것이다. 
또한 석연지는 8각의 지대석 위에 3단의 굄과 한 층의 복련대를 더하고 그 위에 구름무늬로 장석을 놓아 거대한 석련지를 떠받쳐 마치 연꽃이 구름 위에 둥둥 뜬 듯한 모습을 조식한 걸작품으로 8세기경에 제작된 통일신라시대의 작품으로 보고 있으며, 쌍사자 석등은 신라 석등 중 뛰어난 작품 중의 하나로 그 조성 연대는 성덕왕 19년(720)으로 추정되고 있다. 석등의 간주석을 석사자로 대치한 이 석등은 전형적인 양식에서 벗어난 것으로 8각의 지대석 위에 하대 연화석과 쌍사자 연화대 방석을 모두 하나의 돌에 조각한 것으로 다른 석등에 비해 화사석과 옥개석이 큰 것이 특징이다.', '2026-06-29 14:34:12.49');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (10, '126508', '경복궁', 1, 23, NULL, NULL, NULL, NULL, '[1월~2월/11월~12월]09:00~17:00 (입장마감 16:00)[3월~5월/9월~10월]09:00~18:00 (입장마감 17:00)[6월~8월] 09:00~18:30 (입장마감 17:30)', '매주 화요일 ※ 단, 정기휴일이 공휴일 및 대체공휴일과 겹칠 경우에는 개방하며, 그 다음의 첫 번째 비공휴일이 정기휴일임', '경복궁은 1392년 조선 건국 후 1395년(태조 4)에 창건한 조선왕조 제일의 법궁이다. 경복궁은 백악산(북악산)을 주산으로 넓은 지형에 건물을 배치하였고 정문인 광화문 앞으로 넓은 육조거리가 펼쳐진 한양의 중심이었다. ‘경복’의 이름은 ‘새 왕조가 큰 복을 누려 번영할 것’이라는 의미가 담겨있으며, 이곳에서 세종 대에 훈민정음이 창제되어 반포되기도 하였다. 또한, 동궐(창덕궁)이나 서궐(경희궁)에 비해 위치가 북쪽에 있어 ‘북궐’이라 불리기도 했다.
경복궁 근정전에서 즉위식을 가진 왕들을 보면 제2대 정종, 제4대 세종, 제6대 단종, 제7대 세조, 제9대 성종, 제11대 중종, 제13대 명종 등이 있다. 
경복궁은 1592년(선조 25) 임진왜란으로 소실되었는데, 그 후 복구되지 못하였다가 270여 년이 지난 1867년(고종 4)에 다시 지어졌다. 고종 대에 들어 건청궁과 태원전, 집옥재 등이 조성되었으며, 특히 건청궁 옥호루는 1895년 을미사변으로 명성황후가 시해되는 비운의 장소이기도 하다.
1910년 경술국치 후 경복궁은 계획적으로 훼손되기 시작하여 1915년 조선물산공진회를 개최한다는 명분으로 대부분의 전각들이 철거되었고, 1926년에는 조선총독부 청사를 지어 경복궁의 경관을 훼손하였다. 이후 1990년대부터 본격적으로 경복궁 복원공사가 진행되었고, 1995년부터 1997년까지 조선총독부 청사를 철거하였으며 흥례문 일원, 침전 권역, 건청궁과 태원전, 그리고 광화문 등이 복원되어 현재에 이르고 있다.
경복궁에는 조선시대의 대표적인 건축물인 경회루와 향원정의 연못이 원형대로 남아 있으며, 근정전의 월대와 조각상들은 당시의 조각미술을 대표한다. 현재 흥례문 밖 서편에는 국립고궁 박물관이 위치하고 있고, 경복궁 내 향원정의 동편에는 국립민속 박물관이 위치하고 있다.
경복궁의 주요 문화재로는 사적 경복궁, 국보 경복궁 근정전, 국보 경복궁 경회루, 보물 경복궁 자경전, 보물 경복궁 자경전 십장생 굴뚝, 보물 경복궁 아미산굴뚝, 보물 경복궁 근정문 및 행각, 보물 경복궁 풍기대 등이 있다. 

◎ 한류의 매력을 만나는 여행 정보
미국의 국민 TV 쇼 ‘더 투나잇 쇼 스타링 지미 팰런’에서는 ‘BTS위크’라는 이름을 붙여 닷새간 BTS 특별 방송을 진행했는데, 그중 BTS가 ‘맵 오브 더 솔 : 페르소나’ 미니앨범 수록곡 ‘소우주’와 ‘IDOL’을 부른 장소가 화제다. 그 장소는 바로 조선시대의 궁궐 중 하나인 ‘경복궁’의 경회루와 근정전이다. 보랏빛 조명에 아름답게 빛나던 경복궁에서 한국의 과거를 체험해 보길 추천한다.', '2026-06-29 14:34:12.478');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (150, '130071', '서울시립미술관 서소문본관', 1, 24, '서울특별시 중구 덕수궁길 61', 37.5641082438607, 126.97367754109, 'https://tong.visitkorea.or.kr/cms/resource/90/3510490_image2_1.jpg', NULL, NULL, '서울시립미술관(서소문본관)은 시대와 미술의 변화에 부응하고 서로를 채우며 성장해 가는 네트워크 미술관이다.
서울 도심 한복판 덕수궁 돌담길을 따라 자리 잡은 서울시립미술관은 1920년대 건축양식으로 지어진 옛 대법원 건물을 전면부만 그대로 보존한 채 신축하였다. 로비를 지나 계단을 오르면서 하늘을 볼 수 있도록 설계되었으며, 2층에서 3층으로 오르는 나무 계단을 통해 건물의 전면부와 유리로 이어지는 실내공간의 독특한 멋을 느낄 수 있다. 충분한 자연광이 들어오는 밝은 실내는 관람객들의 촬영 장소로도 많은 관심을 받고 있다.
총 6개의 전시실이 있는데 1층 전시실의 경우 가장 큰 전시실이며 2층에는 상설전시실인 천경자 컬렉션 전시실과 가나 아트 컬렉션 전시실이 있다. 지하에는 미술 교육 프로그램을 진행하는 교육실과 강당 세마홀이 자리하고 있다. 미술 도서를 수집·정리하여 열람서비스를 제공하는 미술 전문 자료실인 도서자료실도 갖추고 있으며, 예술 서점, 카페 등의 편의시설도 운영하고 있다. 서울시립미술관은 정동극장, 정동제일교회가 있는 고전미 넘치는 장소를 품은 정동길 옆에 있어 미술관 관람의 여운을 이어갈 수 있다.', '2026-06-29 14:42:03.901');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (59, '1941440', '아라리오뮤지엄 인 스페이스', 1, 23, '서울특별시 종로구 율곡로 83', 37.577707, 126.988456, 'https://tong.visitkorea.or.kr/cms/resource/31/3488531_image2_1.jpg', NULL, NULL, '아라리오뮤지엄은 아라리오의 창업자가 남다른 안목과 열정으로 수집한 컬렉션을 바탕으로 탄생한 컨템포러리 아트 뮤지엄이다. 서울과 제주에 위치한 아라리오뮤지엄은 사무실, 영화관, 모텔 등으로 사용되던 건물들을 활용해, 기존 건물의 역사적 가치에 현대미술의 문화적 가치를 더함으로써 과거와 현재가 교차하는 독창적인 문화 공간으로 재탄생시켰다. 아라리오뮤지엄은 시대적, 사회적, 문화적으로 다양한 가치를 지닌 국내외 현대미술 작품들을 지속적으로 소개하며, 관람객과 예술적 경험을 함께 나누고 소통하는 문화예술 공간이 되고자 한다.', '2026-06-29 14:38:30.612');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (71, '2761709', '봉은사', 1, 1, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '봉은사는 충북 충주시 소태면 청계산 기슭에 자리한 대한불교법륜종 소속 사찰이다. 석가모니불을 본존불로 삼는 대한불교 법륜종 사찰이다. 웅장한 일주문 지나 사찰로 들어가면 종각, 극락보전, 지장전, 관음보전, 적멸보궁, 산신각 등을 둘러볼 수 있다. 여러 시설이 계단식으로 배치되어 있다. 편안한 분위기와 아름다운 풍경은 많은 이들의 마음을 사로잡는 곳이다. 사찰은 동충주 IC와 가까운 거리에 있다. 주변에는 청룡사지, 올데이 컨트리클럽이 있어 연계 관광에 나서기 수월하다.', '2026-06-29 14:38:30.617');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (122, '2783558', '필운동 홍건익 가옥', 1, 23, NULL, NULL, NULL, NULL, '- 화요일~목요일, 주말 10:00~18:00<br>
- 금요일 12:00~20:00', '매주 월요일 / 공휴일', '필운동 홍건익 가옥은 목조 와즙 5동의 건물과 후원의 일각문 1기, 원형의 석조 우물 1기 등으로 구성되어 있다. 본 가옥은 백사(白沙) 이항복(李恒福, 1556~1618)의 저택으로 구전되어 왔으나 1934년 동 필지에 있던 기존 가옥을 허물고 1934년~1936년 홍건익(洪建翊)에 의해 신축한 건물로 사료된다. 본 가옥이 홍건익에 의해 신축되기 이전에 해당 대지(총 467평)에는 역관(譯官) 출신의 개화사상가인 고영주(高永周, 1839~)와 을사늑약의 체결에 끝까지 반대하였던 대한제국의 참정대신 한규설의 외손자인 심재홍(沈載弘)이 거주하였고, 1934년 홍건익(洪建翊)이 부지를 매입한 후로 1936년까지 현재의 건물들을 신축하였다. 홍건익 가옥은 얕은 구릉으로 좁게 이루어진 대지를 적절하게 단을 나누어 건물이 배치되어 있다. 앞에서부터 뒤로 대문과 문간채, 행랑채, 사랑채와 중문간채, 안채, 별채 등의 건물이 순서대로 놓여있다. 

(출처 : 국가유산청)', '2026-06-29 14:42:03.893');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (86, '2790984', '장흥조각공원(양주시립장욱진미술관)', 31, 18, '경기도 양주시 장흥면 권율로 193', 37.732870481, 126.9492661845, 'http://tong.visitkorea.or.kr/cms/resource/67/3331967_image2_1.jpg', NULL, NULL, '양주시립장욱진미술관은 한국 근현대미술을 대표하는 장욱진의 업적과 정신을 기리며, 한국현대미술의 발전에 이바지하는 미술작품과 자료를 전시, 연구, 수집을 목적으로 한다. 양주시립장욱진미술관은 순수한 이상적 내면세계를 추구한 장욱진 화백의 정신을 기리며, 장욱진 정신과 관련된 작가 및 후대작가의 주제기획전시를 통한 한국현대미술 연구하고자 한다. 또한, 우리 미술관은 시민들이 공감할 수 있는 다양한 전시와 교육프로그램, 미술창작스튜디오 운영 등을 통해 지역사회 및 대중과 호흡하는 시립미술관으로 자리하고자 한다. 현재 양주시립장욱진미술관은 신진 및 중견작가의 창작활동을 지원하는 양주시립미술창작스튜디오를 두고 있다. 양주시립미술창작스튜디오는 회화, 사진, 복합매체 작가들을 위한 777레지던스가 운영 중이며 개인전시, 워크숍, 오픈스튜디오, 기획전 등 다양한 프로그램을 제공하고 있다.', '2026-06-29 14:38:30.622');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (100, '231899', '용흥궁', 2, 1, NULL, NULL, NULL, NULL, '09:00~18:00', '연중무휴', '조선 제25대 왕인 철종(재위 1849∼1863)이 왕위에 오르기 전에 살던 집으로 철종이 왕위에 오르자 강화유수 정기세가 건물을 새로 짓고 용흥궁이라 이름을 붙였다. 지붕 옆면이 여덟 팔(八)자 모양인 팔작지붕집이고, 기둥머리에서 보와 도리가 직교하여 직접 결구되는 민도리양식이다. 용흥궁은 창덕궁의 연경당, 낙선재와 같이 살림집의 유형을 따라 지어져 소박하고 순수한 느낌이 든다. 경내에는 철종이 살았던 옛 집임을 표시하는 비석과 비각이 있다.

(출처 : 국가유산청)', '2026-06-29 14:38:30.628');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (167, '2764323', '은평역사한옥박물관', 1, 22, '서울특별시 은평구 연서로50길 8 (진관동)', 37.6403865997, 126.9380226193, 'http://tong.visitkorea.or.kr/cms/resource/89/3337389_image2_1.JPG', NULL, NULL, '2014년 개관한 은평역사한옥박물관은 통일신라시대부터 근현대에 이르는 은평의 역사, 한옥의 전통과 미래를 아우르는 은평의 대표 문화예술 공간이다. 은평의 역사가 담긴 지역 고유의 생활양식과 문화유산을 보존하여 구민과 학생들에게 지역문화에 대한 이해와 긍지를 심어주고, 은평구의 정체성을 살려 애향심을 갖게 하고자 건립되었다. 주요 시설인 상설전시실은 은평의 역사와 뉴타운발굴 유물이 전시된 은평역사실과 실제 한옥과 한옥의 건축과정 및 한옥의 과학성, 자연 친화성 등이 전시된 한옥전시실로 이루어져 있다. 박물관 내부에는 기획전시실, 작은도서관, 체험학습실, 교육실, 희망장난감도서관 등의 부대시설이 있으며, 외부는 다양한 이동선을 따라 통일신라시대의 기와가마터를 비롯한 석물 전시장과 옥상정자인 용출정이 설치되어 있어 관람객들이 전시 관람과 휴식을 동시에 접할 수 있는 개방형 구조로 되어 있다.', '2026-06-29 14:43:18.717');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (88, '130742', '조명박물관', 31, 18, '경기도 양주시 광적면 광적로 235-48', 37.83670173013368, 126.9691679636495, 'https://tong.visitkorea.or.kr/cms/resource/97/3559497_image2_1.jpg', NULL, NULL, '조명박물관은 2004년에 (주)필룩스가 설립하여 2005년에 등록된 조명을 주제로 하는 박물관이다. 전통 조명, 인더스트리얼 조명, 바우하우스 조명, 근현대 조명, 엔틱 조명, 라이트아트 등의 조명 유물과 작품을 소장하고 있으며, 빛과 색, 조명과 관련된 교육, 체험, 공연, 축제를 개최하며 관람객과 소통하고 있다.
조명은 인류의 생활양식이 담긴 고유한 역사 문화적 산물이자 미래 첨단 산업의 중요한 분야이기도 하며 현대 예술가들의 창작에 영감을 주는 요소이기도 하다. 많은 사람들이 조명박물관에서 빛과 조명이 갖는 다양한 문화적 함의를 유추하고 과거로부터 현재까지의 조명 문화를 돌아보며 미래의 조명을 생각해 보는 시간을 가져보기를 기대한다.', '2026-06-29 14:38:30.623');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (90, '2751265', '옥정호수공원', 31, 18, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', 'tvN에서 방영된 ‘사이코지만 괜찮아’ 제7회분에서 김수현(문강태 역)과 서예지(고문영 역) 커플이 걷던 호수 위 산책로가 있는 공원이다. 음악분수와 함께 아름다운 야경이 장관을 이루어 드라마에서도 데이트 장면에 삽입되었다. 옥정호수공원은 광장 내 무궁화 언덕, 김삿갓 광장, 쉼터, 음악분수, 공연장 등으로 구성돼 있고 축제를 위한 복합휴게공간도 마련되어 있다. 특히 여름철에 운영하는 음악분수는 그 물줄기가 다양한 조명에 어울리며 리듬에 맞춰 춤사위를 펼치는 환상적인 경관을 연출한다.', '2026-06-29 14:38:30.624');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (21, '129792', '세종대왕박물관', 1, 11, '서울특별시 동대문구 회기로 56', 37.5909339998234, 127.042670043565, 'https://tong.visitkorea.or.kr/cms/resource/32/4062532_image2_1.jpg', NULL, NULL, '세종대왕박물관은 조선 세종대왕을 기념하는 전시관으로 동대문구 회기동에 위치해 있다. 조선 세종의 성덕과 위업을 추모하고 보존하기 위해 세종대왕기념사업회에서 1970년 11월 준공하고 1973년 10월 개관하였다. 지하 1층, 지상 2층의 현대식 건물로, 전시실, 강당, 연구실, 자료준비실 등이 갖추어져 있으며, 전시관은 한글실, 과학실, 국악실, 일대기실, 옥외 전시로 구성된다. 한글실은 세종 당시 펴낸 도서류를, 과학실은 조선 시대의 과학에 관련된 자료로 금속활자 판자기, 측우기, 천문도 등을 전시하고 있으며, 국악실은 각종 국악 악기류를 전시하고 있다. 일대기실은 세종대왕의 어진과 김학수가 수년 동안 그린 세종대왕 일대기 그림이 전시되어 있어 세종의 치덕을 살펴볼 수 있다. 옥외에는 세종대왕신도비(서울특별시 유형문화재)와 구영릉석물(서울특별시 유형문화재), 수표(보물) 등이 전시되어 있다. 수도권 지하철 1호선 청량리역 2번 출구에서 도보 20분, 6호선 고려대역 3번 출구에서 도보 10분 거리에 있다.', '2026-06-29 14:34:12.482');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (93, '127110', '강진 전라병영성', 38, 1, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '전라병영성[全羅兵營城]은 조선 태종 17년(1417년)에 설치되어 고종 32년(1895년) 갑오경장까지 조선조 500여 년간 전라남도와 제주도를 포함한 53주 6진을 총괄한 육군의 총지휘부이다. 그러나 1894년 갑오농민전쟁(동학)을 맞아 병화로 소실되었고, 이어 1895년 갑오경장의 신제도에 의해 폐영되고 말았다. 병영성 성곽의 총 길이는 1,060m이며, 높이는 3.5m, 면적은 93.139㎡(28.175평)인데, 현재 사적 397호로 지정되어 있다.

(출처 : 강진군 문화관광 홈페이지)', '2026-06-29 14:38:30.625');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (121, '2751248', '남한산성행궁', 31, 5, NULL, NULL, NULL, NULL, '[동절기(11월~3월)]<br> 
- 10:00~17:00<br>
[하절기(4월~10월)] <br>
- 10:00~18:00<br>
※ 관람 종료 30분 전까지 매표 가능', '매주 월요일', '임금이 서울의 궁궐을 떠나 도성 밖으로 행차하는 경우 임시로 거처하는 곳을 행궁이라 한다. 남한산성 행궁은 전쟁이나 내란 등 유사시 후방의 지원군이 도착할 때까지 한양 도성의 궁궐을 대신할 피난처로 사용하기 위하여 조선 인조 4년(1626)에 건립되었다. 실제로 인조 14년(1636) 병자호란이 발생하자 인조는 남한산성으로 피난하여 47일간 항전하였다. 이후에도 숙종, 영조, 정조, 철종, 고종 등이 여주, 이천 등의 능행길에 머물러 이용하였다. 남한산성 행궁은 1909년까지 잘 남아 있었으나 일제강점기에 일본에 의해 훼손되었다. 1999년부터 발굴 조사를 시작하여 2002년에 상궐에 해당하는 내행전을 준공하고 2004년 행궁 좌전을 준공하였다.

(출처 : 경기도남한산성세계유산센터 홈페이지)', '2026-06-29 14:42:03.893');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (200, '1754832', '서울풍물시장', 1, 11, '서울특별시 동대문구 천호대로4길 21 (신설동)', 37.5727654781, 127.0255193372, 'http://tong.visitkorea.or.kr/cms/resource/63/3107663_image2_1.jpg', NULL, NULL, '서울풍물시장은 원래 청계천이 복원되기 전 황학동을 중심으로 우리나라를 대표하는 벼룩시장 또는 만물시장이라는 이름으로 운영을 하고 있었다. 전국 각지에서 수집된 오래된 물건이나 상품을 판매하는 점포와 거리로 황학동 벼룩시장이 형성되었다. 
청계천 복원 사업과 함께 황학동과 청계천변 노점 상태로 운영 중이던 황학동 벼룩시장은 (구) 동대문운동장 내 동대문 풍물벼룩시장으로 이전하여 영업을 해왔다. 그러던 중 (구) 동대문운동장 공원화 선행사업으로 관광산업과 연계한 우리나라를 대표하는 풍물시장 개발을 위해 청계천과 인접한 청계 8가 숭인여중 자리에 세계적인 풍물시장을 목표로 새로운 쇼핑의 명소가 될 서울풍물시장(Seoul Folk Flea Market)을 개장하였다.
서울풍물시장은 골동품, 근현대사 상품, 우리 고유의 옛것에부터 생활잡화, 가방, 구제의류까지 구매할 수 있는 다양한 상품을 판매하고 있다. 또한 전통생활용품 전시장등 다양한 볼거리, 먹거리, 즐길거리가 한 공간에 함께 있어 특색 있는 시장이다. 특히 지난 2015년도에는 ‘서울시 미래유산’으로 선정되었다.', '2026-06-29 14:43:18.726');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (135, '3433766', '석문공원', 38, 1, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '남도의 소금강이라 불리는 석문공원은 석문(石門)이라는 이름 그대로 긴 세월과 비바람이 조각한 기암괴석들이 병풍처럼 펼쳐져 있으며, 만덕산과 석문산의 단절된 등산로를 연결하는 사랑 구름다리가 있다. 길이는 111m, 폭 1.5m로 산악현수형 출렁다리인 사랑 구름다리는 만덕산과 석문산의 단절된 등산로를 연결하고 구름다리 양끝에는 하트모양의 게이트 겸 포토존 조형물이 설치되어 등산객들에게는 만남의 장소로 연인들에게는 사랑이 이뤄지는 장소이다. 구름다리에서 보는 석문산과 만덕산의 빼어난 경관은 보는 이에게 절로 감탄사가 나오게 한다.

(출처: 강진군 문화관광 홈페이지)', '2026-06-29 14:42:03.897');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (146, '3019162', '서순라길', 1, 23, NULL, NULL, NULL, NULL, '상시', '연중무휴', '서순라길은 서울 종로구 종로 150-3에서 권농동 26까지를 잇는 도로로, 옛 조선의 치안을 담당하는 순라군이 다니던 길이다. 종묘를 순찰하던 순라청의 서쪽에 위치한다고 하여 ‘서순라길’로 부른다. 주위에 익선동, 인사동, 북촌, 삼청동 등 전통적인 인기 관광 지역 있고, 서순라길 내에는 식당, 카페, 공방 등 즐길 거리가 많다. 특히 봄에 꽃이 피고, 가을에 단풍이 들면 돌담의 풍경이 아름다워 데이트 코스, 가족 나들이로 많이 찾는다. 거리를 걸으면서 멋진 사진을 남길 수 있는 곳들이 많다.', '2026-06-29 14:42:03.9');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (30, '129550', '장자호수공원', 31, 6, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '장자호수공원은 한때 오폐수로 인해 악취가 심했던 곳이었으나, 근처에 아파트를 건설하면서 수질 개선 사업을 통해 근린공원으로 복원되었다. 공원 내에는 산책로와 황톳길, 자전거도로가 잘 정비되어 있으며, 장미원, 숲놀이원, 장자호수생태체험관 등의 시설이 있다. 황톳길은 맨발 걷기를 즐기는 시민들이 즐겨 찾는 명소가 되었다. 장미원에서는 초여름에 만발한 장미의 장관을 볼 수 있다. 야외무대에는 각종 음악회, 전시회 등이 주말에 열리고, 주민 휴식 공간으로 널리 활용되고 있다. 장자호수생태체험관을 운영하면서 학생들과 시민들을 상대로 생태 교육 프로그램을 운영하고 있다.', '2026-06-29 14:34:12.485');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (194, '264394', '화홍문(華虹門)', 31, 13, NULL, NULL, NULL, NULL, '- 하절기(3월~10월) 09:00~18:00- 동절기(11월~2월) 09:00~17:00', '연중무휴', '화성에는 수원천이 남북으로 가로질러 흐르는데 성의 연결 부분에는 수문을 설치하여 북쪽에는 북수문, 남쪽에는 남수문을 두었다. 화홍문은 화성의 북수문으로 7개의 무지개 모양의 수문이 설치되어 있다. 특징이라면 7개의 수문의 크기가 다르다는 것이다. 가운데 수문이 좌우의 수문보다 넓고 크게 설치되어 우량[雨量]을 효과적으로 조절할 수 있다. 화홍문 동쪽 언덕에는 화려한 건축미를 자랑하는 방화수류정[訪華隨柳亭]이 있다. 

◎ 한류의 매력을 만나는 여행 정보 - 드라마 
화홍문은 수문을 밝히는 조명과 산책길 덕분에 야경 명소로 유명하다. 솔이에게 선재가 마음을 고백했던 화홍문 앞 다리는 지금도 팬들이 찾아와 사진을 찍을 만큼 인기 있는 포토존이다.', '2026-06-29 14:43:18.724');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (170, '1102845', '이화벽화마을', 1, 23, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '이화벽화마을은 혜화역과 동대문역 사이의 낙산공원 밑에 위치한 마을로 2006년 ‘공공미술추진위원회’에서 소외지역 생활환경 개선의 일환으로 70여 명의 작가가 참여한 ‘낙산프로젝트’가 추진된 곳이다. 이화동은 ‘낙산프로젝트’가 진행되고 방송 매체에 여러 번 소개된 후 시민들이 찾는 명소가 되었다. 이화벽화마을은 과거와 현재가 공존하는 골목길과, 오랜 세월 터를 닦고 살아온 사람들의 진솔한 삶의 모습이 잘 녹아들어 있는 곳이자 벽화마을 관광지로 사랑을 받아 왔다.

(출처 : 서울미래유산)', '2026-06-29 14:43:18.718');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (180, '1605036', '창경궁 대온실', 1, 23, NULL, NULL, NULL, NULL, '09:00~20:45※ 12월~2월에는 18:00부터 대온실 내부 비개방함', '매주 월요일', '대온실(大溫室)은 1909년(융희 3)에 완공한 우리나라 최초의 서양식 온실로 철골구조와 목조가 혼합된 구조체를 유리로 둘러싼 서양식 온실이다. 준공 당시에는 열대지방의 관상식물을 비롯한 희귀한 식물을 전시하였다. 1986년 창경궁 복원 이후에는 국내 자생 식물을 전시하고 있으며 2004년 국가등록유산으로 지정되었다.

(출처 : 국가유산청 궁능유적본부)', '2026-06-29 14:43:18.72');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (198, '132183', '광장시장', 1, 23, '서울특별시 종로구 창경궁로 88', 37.5701653166, 126.9997217621, 'http://tong.visitkorea.or.kr/cms/resource/81/2668981_image2_1.jpg', NULL, NULL, '구한말 국내 정세가 혼미를 거듭하던 중 일본, 중국 등 열강세력의 각축장으로 국운은 풍전등화격이었다.  1905년 고종 42년  을사조약 체결 후 실질적으로 주권행사는 일본이 장악했고 따라서 경제침략 정책을 기도한 바 그 한 예로서 남대문시장 경영권  장악하였고 경제적인 돌파구로 새롭게 문을 연 것이 종로의 광장시장이다. 1905년  우리 나라 최초의 상설 시장 이 탄생한 순간이다. 원래 광장시장은 광교(너른 다리)와  장교(긴 다리) 사이를 복개하여 만들려고 했기 때문에 그 다리 이름의 첫머리를 따서  ‘너르고 긴’이라는 뜻의 광장(廣長)시장이라 이름 지었으나 배오개로 터를 옮기며  이전 이름의 한글 발음은 그대로 둔 채 ‘널리 모아 간직한다’는 뜻을 새로 담아 현재의  광장(廣藏)시장이 되었다. 시장개설시 주요 거래 상품으로는 주로  농수산물, 신탄 등인데 가평·뚝섬 이천, 철원 등지에서 우마차로 반입하는 소규모의 단조로운 원시적인 시장 기능일 뿐이었으나 100년이 훌쩍 넘은 현재의 주거래 품목으로는 주단, 포목(한복), 직물(양복,양장지), 여성의류제품, 커텐지, 침구, 수예,  나전칠기, 주방용품, 수입품코너, 청과, 건어물, 제수용품, 생선, 정육, 야채 등으로 상당량 거래 규모를 자랑하는 종합적인 면모를 갖춘  시장이 되었다. 또한 광장시장에서 가장 번화한 곳은 동문과 북2문, 남1문이 만나는  거리에 형성된 먹거리장터이다. 광장시장의 먹거리장터는 학생, 중장년층, 연세 지긋한 어르신까지 모든 연령을 아우른다. 현재 세계 관광코스로 지정되어 우리나라를 여행하는 많은 외국 관광객들의 경유지로 되어 있음을  자랑할 수 있다.', '2026-06-29 14:43:18.725');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (24, '337508', '연화사(서울)', 1, 11, NULL, NULL, NULL, NULL, '08:00~19:00 (휴게시간 11:30~12:00)', '연중무휴', '연화사는 서울시 동대문구 회기동 천장산 자락에 자리한 대한불교 조계종 직할 말사이다. 서울 동부 도심 한복판에 자리한 회기동은 연산군의 생모인 폐비 윤씨의 묘소인 회릉이 있었다고 하여 붙여진 이름으로 현재 그 터에는 그녀의 원찰로 지어진 조그마한 절이 있다. 일체중생의 근본이 진흙 속에서 피어나는 청정한 연꽃과 같다는 의미에서 연화사라 불렸는데, 이후 묘련이라 불리기도 했다. 이는 모두 연꽃의 청정함을 상징하는 것으로 연산군이 생모 윤씨의 명복을 빌고 비명에 간 원혼을 천도하기 위한 도량으로서, 연꽃의 기능 중 화생의 의미로 붙인 이름인 듯하다. 현재는 회릉이 서삼릉으로 이전되고 그 자리에 경희여중·고등학교가 설립되면서 옛 모습은 찾을 수 없지만 그 터 아래 조그마한 사찰로 명맥을 이어가고 있다. 지금은 울창한 수풀에 둘러싸인 전형적인 사찰의 모습이 아니라 도심 속 사찰로 변모했지만 사찰에는 폐비 윤씨는 물론 선의왕후의 원찰로서 많은 상궁이 조성한 불화들이 남아 있어 왕실 원찰로서의 흔적을 찾을 수 있다.', '2026-06-29 14:34:12.483');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (27, '129833', '경희대학교 중앙박물관', 1, 11, '서울특별시 동대문구 경희대로 26 (회기동)', 37.5971, 127.0527, 'https://tong.visitkorea.or.kr/cms/resource/63/3505463_image2_1.jpg', NULL, NULL, '경희대학교 중앙박물관은 1956년 개관한 이래 고고역사민속 중심의 제1종 종합 박물관으로서 학술, 교육, 전시, 문화재 지표 및 발굴조사 등 다양한 활동을 통하여 대학 문화를 선도하고 있다. 박물관 전시실은 고고역사실, 무속실·시베리아실 , 옹관실, 중앙전시실, 기획전시실, IAUP기념관으로 구성되어 있다. 중앙박물관을 방문하면 가장 먼저 중앙 전시실을 접하게 된다. 고고역사실은 선사실, 삼국실, 금관실, 고려시대실, 도자기실, 신라실, 와당실로 구분되어 있으며 구석기시대부터 삼국시대에 이르기까지 다양한 유물들이 전시되어 있다. 무속실은 무속 관련 도구와 무신도들을 전시해 두었으며 시베리아실에서는 시베리아 지역의 민속 유물들을 전시하고 있다. 옹관실은 영암 내동리 출토 옹관과 동반 유물들을 전시하고 있으며 IAUP 기념관에는 세계대학총장회의 관련한 자료들을 전시하고 있다.', '2026-06-29 14:34:12.484');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (28, '125545', '구리 동구릉 [유네스코 세계유산]', 31, 6, NULL, NULL, NULL, NULL, '[2월~5월]- 06:00~18:00 (입장 마감 17:00)[6월~8월]- 06:00~18:30 (입장 마감 17:30)[9월~10월]- 06:00~18:00 (입장 마감 17:00)[11월~1월] - 06:30~17:30 (입장 마감 16:30)', '매주 월요일 (단, 정기휴일이 공휴일 및 대체공휴일과 겹칠 경우에는 개방하며, 그 다음의 첫 번째 비공휴일이 정기휴일임)', '동구릉(東九陵)은 ‘동쪽에 있는 9기의 능’이라는 뜻으로, 약 450여 년간 7명의 왕과 10명의 왕비가 잠들어 있는 조선 최대의 왕릉군이다. 1408년(태종 8) 조선을 건국한 태조의 건원릉(健元陵)이 처음으로 조성되고 이후 문종의 현릉(顯陵), 선조의 목릉(穆陵), 현종의 숭릉(崇陵), 장렬왕후의 휘릉(徽陵), 단의왕후의 혜릉(惠陵), 영조의 원릉(元陵), 헌종의 경릉(景陵)이 차례로 조성되었다. 능이 조성될 때마다 동오릉(東五陵), 동칠릉(東七陵) 등으로 불리다가 문조의 수릉(綏陵)의 옮겨지면서 지금의 동구릉이 되었다.
동구릉은 조선 전기부터 후기까지의 왕릉을 모두 볼 수 있는 곳으로, 왕이나 왕후의 능을 단독으로 조성한 단릉, 나란히 조성한 쌍릉, 하나의 정자각을 두고 서로 다른 언덕에 능침을 조성한 동원이강릉, 한 능에 왕과 왕후를 같이 모신 합장릉, 왕과 두 왕후의 능을 나란히 조성한 삼연릉 등 다양한 형태로 조성된 능이 모여있다.

(출처 : 국가유산청 궁능유적본부)', '2026-06-29 14:34:12.485');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (177, '2739454', '박노수미술관', 1, 23, '서울특별시 종로구 옥인1길 34 (옥인동)', 37.58131920855933, 126.9668185498949, 'https://tong.visitkorea.or.kr/cms/resource/02/3350702_image2_1.jpg', NULL, NULL, '2013년 타계한 고 박노수 화백이 40여 년간 거주하던 가옥에 만들어진 박노수미술관은 서울시 1종 등록미술관으로 지정된 종로구립 미술관이다. 박노수 화백의 기증작품과 컬렉션(고미술품, 수석, 고가구) 등 총 천여 점의 풍부한 예술품을 바탕으로 2013년 9월에 설립되었다. 
박노수미술관 건축물은 1937년경 절충식 기법으로 지어진 가옥이다. 주로 한식으로 지어졌으며 1층은 온돌과 마루, 2층은 마루방 구조이고, 3개의 벽난로가 설치되어 있다. 현관은 벽돌 포치로 아늑한 느낌을 주며, 지붕은 서까래를 노출한 박공지붕으로 되어 있어 장식적인 요소와 단순함이 어우러져 독특한 분위기를 자아내고 있다. 문화재적 가치를 인정받아 1991년에 서울특별시 문화유산자료로 지정되었다.
박노수미술관은 품격 있는 소장품을 바탕으로 매해 기획전시를 개최하고 정원음악회, 명사초청 특강, 어린이·청소년 예술교육프로그램 등을 기획하는 등 시민들에게 문화향유 기회를 제공하고 있다.', '2026-06-29 14:43:18.72');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (33, '3090931', '구리전통시장', 31, 6, '경기도 구리시 검배로6번길 31 (수택동)', 37.59954276883985, 127.1399041501313, 'https://tong.visitkorea.or.kr/cms/resource/21/3090921_image2_1.JPG', NULL, NULL, '구리전통시장은 1960년대 후반 골목시장 형태로 형성되어, 1977년 시장 개설 등록한 구리시 핵심 상권에 있는 유일한 전통시장이다. 시내 중심가에 있어 접근성이 좋아 구리시민 뿐만 아니라 인근 주민들이 많이 이용하는 시장이다. 또한, 주차장, 아케이드, 야외무대, 간판 정비 등 현대화된 시설로 안전하고 쾌적하다. 약 393개의 점포가 입점해 있으며, 농·수산물, 축산물, 의류, 잡화 등 다양한 상품을 판매하고 있다. 가장 큰 특징 중 하나는 보통의 재래시장에서 볼 수 없는 장보기 서비스다. 이 서비스는 장보기 도우미가 장을 대신 봐주거나 무거운 물건의 배송을 도와주는 것인데, 매주 평일 오전 10시부터 오후 6시까지 무료로 운영하고 있다. 이외에도 ICT보이는 라디오를 운영하며 음악 방송을 진행하고 있다. 구리전통시장은 문화관광형시장으로 다양한 볼거리와 즐길거리를 제공하고 있다.', '2026-06-29 14:34:12.486');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (35, '130667', '단종역사관', 32, 8, '강원특별자치도 영월군 영월읍 단종로 190', 37.1951799631, 128.4546816177, 'http://tong.visitkorea.or.kr/cms/resource/02/3557202_image2_1.JPG', NULL, NULL, '단종 관련 유적 및 유품을 한눈에 볼 수 있는 단종역사관이 2002년 4월 5일 영월읍 영흥 12리 장릉 경내에 개관되었다. 단종역사관은 잊히고 왜곡된 단종의 역사를 바로 잡고 이를 널리 알리고자 하는 자각과 재인식에서 계획되었으며, 단종과 지역의 우수성을 지역 주민과 전국의 관람객들에게 이해시키는 교육의 장(場)이다.
세종실록과 문종실록, 단종실록, 세조실록, 조선시대 관복인 대관복과 관복, 내관복, 단종의 세자책봉과 왕위책봉, 단종의 죽음과정에 대한 기록물, 단종의 죽음을 서술한 책인 『단종애사』와 관련된 여러 서적, 단종의 일대기를 그린 그래픽패널, 생육신과 사육신의 충절을 기린 위패, 족쇄와 신장, 태, 장, 착고 등 조선시대 형구, 태형과 장형, 유형, 사형 등 형벌의 종류, 단종어보와 정순왕후 어보, 조선시대 궁중복식모형인 조복과 영복, 조례복, 단종의 유배재현 영상물, 단종유배행렬 디오라마, 단종의 비인 정순왕후의 유물과 왕후의 능인 사릉(思陵) 디오라마 등이 1층과 지하 1층에 주제별로 나뉘어 전시되어 있다.', '2026-06-29 14:34:12.487');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (38, '2700323', '영월의 젊은달와이파크와 함께 SNS 인생 사진 코스', 32, 8, '강원특별자치도 영월군 주천면 송학주천로 1467-9', 37.2740146038, 128.2691404013, 'http://tong.visitkorea.or.kr/cms/resource/97/2634797_image2_1.jpg', NULL, NULL, '2020년 한국 관광의 별을 수상한 젊은달 와이파크와 SNS에서 큰 인기를 누리고 있는 영월 지역 카페인 제이큐브 뮤지엄&카페에서 사진 찍는 재미를 느껴 보자. 또 늦가을부터 겨울까지만 볼 수 있는 판운면 섶다리, 영월 여행에서 빼 놓을 수 없는 한반도지형, 날씨가 좋으면 일몰과 야경 감상하기 좋은 별마로천문대에서 자연과 인간이 만들어낸 아름다운 조화를 감상하는 것도 좋다.', '2026-06-29 14:34:12.488');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (37, '126887', '선돌 (강원고생대 국가지질공원)', 32, 8, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '선돌에 가면 거대한 기암괴석이 ㄱ자로 굽은 강줄기와 함께 나타난다. 선돌은 일명 신선암이라고도 하는데 선돌은 푸른 강과 층암절벽이 어우러져 마치 한폭의 그림을 보는 듯한 느낌을 준다. 선돌은 영월읍 방절리 서강 안에 절벽을 이룬 곳에 위치해있는데 마치 큰 칼로 절벽을 쪼개 내리다 그친 듯한 형상을 이룬 입석을 말한다. 선돌은 기반암인 석회암이 물에 의한 용식작용으로 절리틈이 녹아서 형성된 지형으로 추측되고 있다.
(출처 : 강원고생대 국가지질공원)', '2026-06-29 14:34:12.488');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (46, '126009', '보은 속리 정이품송', 33, 3, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '속리산 법주사로 가는 길 한가운데 서 있는 속리의 정이품송은 나이가 약 600년 이상으로 추정되는 소나무로 높이는 15m, 가슴둘레 4.5m, 가지의 길이는 동쪽 10.3m, 서쪽 9.6m, 북쪽 10m이며 총면적은 1158.3㎡에 이른다. 벼슬품계인 정 2품을 받은 나무로 속리산의 상징으로 널리 알려졌다. 
이 소나무가 정이품송이라는 이름을 얻게 된 데에는 다음과 같은 이야기가 있다. 세조 10년(1464)에 왕이 법주사로 행차할 때 타고 있던 가마가 이 소나무 아래를 지나게 되었는데, 가지가 아래로 처져 있어 가마가 가지에 걸리게 되었다. 이에 세조가 "가마가 걸린다"고 말하니 소나무가 자신의 가지를 위로 들어 왕이 무사히 지나가도록 하였다 한다. 또 세조가 이곳을 지나다가 이 나무 아래에서 비를 피했다는 이야기도 있다. 세조는 이 소나무의 충정을 기리기 위하여 정2품(현재의 장관급) 벼슬을 내렸고, 이 소나무를 정이품소나무라 부르게 되었다.
이 소나무는 살아오는 동안 각종 재해를 입었는데, 특히 1980년대 초 솔잎혹파리의 피해 때문에 많은 비용을 들여 대규모 방충망을 설치하기도 했다. 이 소나무는 원래 삿갓 또는 우산을 편 모양으로 단정하고 아름다운 모습이었는데, 1993년 강풍으로 서쪽 큰 가지가 부러져 그 모습이 많이 상하였다.
하지만 전체적인 나무의 모양이 매우 아름다우며, 크고 오래된 나무여서 생물학 및 생물유전자원으로서의 가치가 매우 크고, 임금을 섬기는 그 시대상을 잘 전해주는 전설을 가지고 있는 등 문화적인 가치 또한 크기 때문에 천연기념물로 지정하여 보호하고 있다.', '2026-06-29 14:34:12.491');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (40, '770251', '한반도 뗏목마을', 32, 8, NULL, NULL, NULL, NULL, '09:00~17:00', '동절기 (12월~2월)※ 기상악화 시 운영중단', '한반도 뗏목마을은 강원도 영월군 선암마을 내에 위치한 체험형 관광 공간으로, 한반도 지형을 닮은 자연경관을 배경으로 전통 뗏목 문화를 체험할 수 있는 곳이다. 과거 물자 운반 수단으로 사용되던 뗏목을 현대적으로 재현해 방문객들이 직접 체험할 수 있도록 구성되어 있으며, 주변의 한반도 지형 전망과 어우러져 색다른 관광 경험을 제공한다. 자연 속에서 여유로운 시간을 보내며 지역의 전통과 문화를 함께 느낄 수 있는 공간으로 활용되고 있다.', '2026-06-29 14:34:12.489');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (45, '2650370', '세조길', 33, 3, '충청북도 보은군 속리산면 법주사로 405', 36.5411407332, 127.8329032953, 'http://tong.visitkorea.or.kr/cms/resource/17/3556717_image2_1.jpg', NULL, NULL, '세조길은 보은군 속리산에 위치한 역사적인 탐방로이다. 이 길은 조선 7대 임금 세조가 아버지 세종대왕을 도와 한글 창제를 주도했던 신미대사를 만나기 위해 왕래하던 옛길을 재현한 것이다. 2016년 개통 이후, 세조길은 매년 많은 관광객이 찾는 명소로 자리 잡았다. 길을 따라 걷다 보면 아름다운 자연경관과 함께 역사적 의미를 느낄 수 있다. 또한, 이곳은 힐링과 산책을 즐기기에 적합한 장소로 알려져 있다. 세조길은 보은군의 중요한 문화유산으로, 방문객들에게 특별한 경험을 제공하는 곳이다.', '2026-06-29 14:34:12.491');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (41, '2616104', '요선암 돌개구멍 (강원고생대 국가지질공원)', 32, 8, NULL, NULL, NULL, NULL, '상시 개방', '연중 무휴', '요선암 돌개구멍(Pothole)에 가보면 암석에 구멍이 동그랗게 파여져 있는 것을 볼 수 있다. 그런 지형을 포트홀이라고 하는데 하천이 흐르면서 바닥의 작은 틈으로 모래와 자갈이 들어가서 빠르게 흘러내리는 물과 함께 소용돌이치면서 암석을 깎아 만들어진다. 주로 사암이나 화강암과 같은 단단한 암석에 잘 만들어지며, 이곳은 흑운모 화강암으로 이루어져 있다. 포트홀의 크기가 큰 것은 지름과 깊이가 수 미터에 달하기도 한다. 대부분의 포트홀은 깊은 항아리 모양을 이룬다. 

(출처 : 강원고생대 국가지질공원)', '2026-06-29 14:34:12.49');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (9, '1849416', '대한민국역사박물관', 1, 23, '서울특별시 종로구 세종대로 198 (세종로)', 37.5741339024, 126.977573668, 'http://tong.visitkorea.or.kr/cms/resource/89/3082989_image2_1.JPG', NULL, NULL, '대한민국역사박물관은 19세기말 개항기부터 오늘날까지의 대한민국의 행보를 기록한 박물관으로, 2012년 12월 26일에 개관한 최초의 국립 근현대사 박물관이다. 박물관은 고난과 역경을 딛고 발전한 대한민국의 역사를 전시, 교육, 조사∙연구, 자료의 수집을 통해 국민과 공유하고자 설립되었다. 박물관은 대한민국의 역사를 시대별로 4개의 전시실로 나누어 설명하고 있다. 제1전시실에서는 ‘대한민국의 태동’, 제2전시실에서는 ‘대한민국의 기초 확립’, 제3전시실에서는 ‘대한민국의 성장과 발전’, 그리고 제4전시실에서는 ‘대한민국의 선진화, 세계로의 도약’을 주제로 전시가 구성되어 있다. 어린이 박물관에서는 어린이가 직접 체험하면서 근현대사를 배울 수 있다. 또한, 근현대사 전반에 걸친 다양한 주제의 특별 전시를 통해 대한민국 근현대사에 대한 심층적인 내용을 살펴볼 수 있다. 박물관에서 다양한 교육 프로그램과 문화행사도 운영하고 있다.', '2026-06-29 14:34:12.478');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (3, '147684', '전주향교', 37, 12, NULL, NULL, NULL, NULL, '- 동절기 10:00~17:00<br>
- 하절기 09:00~18:00', '매주 월요일<br>※ 단, 월요일이 공휴일일 경우 익일 휴관', '향교는 훌륭한 유학자의 위패를 모시고 제사를 지내며 지방민의 교육과 교화를 위해 설립된 고려·조선시대의 국립 교육기관이다. 전주향교에는 훌륭한 분들의 위패를 모신 대성전을 비롯해 동무·서무, 계성사, 학생들을 가르치던 곳인 명륜당 등의 여러 건물이 있다. 
대성전은 효종 4년(1653)이 고쳐 세웠는데, 이기발이 중건기를 남겼다. 이후 융희 원년(1907)에 군수 이중익이 다시 고쳤으며, 규모는 앞면 3칸, 옆면 2칸이다. 대성전 앞뜰의 400년이 넘은 은행나무를 비롯해 곳곳에 은행나무가 많아 1년 중 가을이 가장 아름답다고 알려져 있고, ‘구루미 그린 달빛’, ‘성균관 스캔들’ 등 각종 드라마와 영화의 배경지로 유명하다. 향교와 주위를 둘러싼 돌담을 배경으로 고즈넉한 분위기의 기념사진을 남길 수 있다.', '2026-06-29 14:34:12.475');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (5, '126621', '오목대와 이목대', 37, 12, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '한벽당과 전주향교의 북쪽 4차선 노변, 벼랑같이 솟은 언덕에 세워진 오목대는 고려 말 우왕 6년(1380년)에 이성계가 운봉 황산에서 왜군을 무찌르고 돌아가던 중 조상인 목조가 살았던 이 곳에 들러 승전을 자축한 곳으로, 그 후 고종 황제가 친필로 쓴 태조고황 제주필유지비를 세웠다. 여기서 육교를 건너서 이목대가 있는데, 천주교의 성지 치명자산이 있는 승암산 발치에 위치한다. 오목대에서 육교를 건너면 70m 위쪽으로 이목대가 있는데 건물이 있는 80m 아래쪽에 비석과 비각을 세웠다. 이 비 속에는 목조대왕 구거유지라 새겨져 있는데 고종 황제의 친필이다. 목조는 조선조를 건국한 이태조의 5대 조로, 목조가 어릴 때 이곳에서 진법놀이를 하면서 살았던 유적지로 알려져 있으며, 그러한 내용이 용비어천가에도 나타나 있다. 목조가 당시의 전주 부사와의 불화로 이곳에서 함경도로 옮겨간 것이 이성계로 하여금 조선조를 건국할 수 있었던 계기가 되었으므로, 이를 하늘의 뜻이라고 여겼다 한다.', '2026-06-29 14:34:12.476');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (2, '250331', '전주전동성당', 37, 12, NULL, NULL, NULL, NULL, '09:00~17:00', '연중무휴', '전주 전동성당은 사적으로 조선시대 천주교도의 순교 터에 세워졌다. 이 건물은 천주교 신자들을 사형했던 전라북도 전주시 전동 풍남문 밖에 지어진 성당이다. 조선시대의 전주는 전라감영이 있었으므로 천주교회사에서 전동은 자연히 순교지의 하나가 됐다. 정조 15년(1791)에 최초의 순교자 윤지충(바오로)과 권상연(야고보), 순조 원년(1801)에 호남 첫 사도 유항검(아우구스티노)과 윤지헌(프란치스코) 등이 이곳에서 박해를 받고 처형됐다. 신유박해(1801년) 때는 이곳에서 유항검과 유관검 형제가 육시형을, 윤지헌, 김유산, 이우집 등이 교수형을 당했다. 이들의 순교의 뜻을 기리고자 1891년(고종 28)에 프랑스 보두네(Baudenet) 신부가 부지를 매입하고 1908년 성당 건립에 착수해 1914년에 완공했다. 이 성당 건물은 일제강점기에 지어졌으며 서울 명동성당을 설계한 프와넬 신부에게 설계를 맡겨 23년 만에 완공한 것이다. 회색과 붉은색 벽돌을 이용해 지은 건물은 겉모습이 서울의 명동성당과 비슷하며 초기 천주교 성당 중에서 매우 아름다운 건물로 손꼽힌다. 비잔틴 양식과 로마네스크 양식을 혼합한 건물로 국내에서도 가장 아름다운 건축물 중의 하나이다. 처음 이 성당은 천주교 순교지인 풍남문 밖에 세웠으나 후에 현재의 자리에 확장해 지은 것이다. 호남지역에서 최초로 지어진 로마네스크 양식의 건물로 장방형의 평면에 외부는 벽돌로 쌓았으며 중앙과 좌우에 비잔틴 양식의 종탑이 있다. 내부 천장은 아치형이며 양옆의 통로 위 천장은 십자 형태로 교차된 아치형이다. 성당 건축에 사용된 일부 벽돌은 당시 일본 통감부가 전주 읍성을 헐면서 나온 흙을 벽돌로 구웠으며 전주 읍성의 풍남문 인근 성벽에서 나온 돌로 성당의 주춧돌을 삼았다고 한다.', '2026-06-29 14:34:12.474');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (6, '126622', '전주 풍남문', 37, 12, NULL, NULL, NULL, NULL, NULL, '연중무휴', '풍남문은 옛 전주읍성의 남쪽문으로 정유재란 때 파괴된 것을 영조 10년(1734) 성곽과 성문을 다시 지으면서 명견루라 불렀으며, 풍남문이라는 이름은 관찰사 홍낙인이 영조 44년(1768) 다시 지으면서 붙인 것이다. 순종 때 도시계획으로 성곽과 성문이 철거되면서 풍남문도 많은 손상을 입었는데 지금 있는 문은 1978년부터 시작된 3년간의 보수공사로 옛 모습을 되찾은 것이다. 규모는 1층이 앞면 3칸, 옆면 3칸, 2층이 앞면 3칸, 옆면 1칸이며, 지붕은 옆면에서 볼 때 여덟 팔(八)자 모양을 한 팔작지붕이다. 지붕 처마를 받치기 위해 장식하여 짠 구조가 기둥 위에만 있다. 평면상에서 볼 때 1층 건물 너비에 비해 2층 너비가 갑자기 줄어들어 좁아 보이는 것은 1층 안쪽에 있는 기둥을 그대로 2층까지 올려 모서리 기둥으로 사용하였기 때문이다.', '2026-06-29 14:34:12.476');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (8, '3497454', '의정부지 상설 전통문화행사', 1, 23, '서울특별시 종로구 종로1길 45 (세종로)', 37.57461832188537, 126.978384931809, 'https://tong.visitkorea.or.kr/cms/resource/13/4056513_image2_1.jpg', NULL, NULL, '의정부지 상설 전통문화행사는 의정부지 역사유적광장을 찾는 시민 및 관광객들에게 우리의 전통문화를 널리 알려 역사도시 서울 이미지를 높이고, 평소에 경험하기 어려운 전통무예행사를 통해 문화 향유 기회를 제공하기 위해 서울시 주최로 진행되는 행사이다. 행사는 의정부를 포함한 육조거리에 주둔하였던 삼군부 군사들의 ''열무閱武'' 재현과 승경도 놀이 체험, 전통무예체험으로 구성된다.', '2026-06-29 14:34:12.477');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (55, '128871', '흥국사(고양)', 31, 2, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '흥국사의 창건은 지금으로부터 1300여 년 전 전인 서기 661년(신라 문무왕 원년)에 당대 최고의 고승인 원효스님이 북한산 원효암에서 수행 중 북서쪽에서 상서로운 기운이 일어나는 것을 보고 산을 내려와 이곳에 이르게 되었다. 서기를 발하고 계신 석조 약사여래 부처님을 보신 원효스님이 인연도량이라 생각하여 본전에 약사부처님을 모시고 ‘상서로운 빛이 일어난 곳이라 앞으로 많은 성인들이 배출될 것이다’하시며 절이름을 흥성암이라 하고 오늘의 흥국사를 창건했다.
그 이후 사찰의 역사를 가늠해 볼 수 있는 자료가 없어 자세한 자취는 알 수 없으나 서기 1686년(숙종 12)에 중창한 사실과 영조시대에 크게 발전하였다는 기록이 있다. 특히, 서기 1758년(영조 34)에 미타전 아미타불을 개금 중수(복장연기문)하였고, 서기 1770년(영조 46) 생모 숙빈 최씨 묘원인 소녕원에 행차하다가 많은 눈을 만나게 되어 이곳에 들르게 된 영조대왕이 하루를 머물고 아침에 일어나 지었던 시가 비문에 전해진다.
이후 서기 1785년에 승도대장·관선·가선·법헌스님 등이 중창하였고, 1792년(정조 16)에는 관선·법선스님 등이 후불탱을 조성·봉안했다. 1867(고종 4)년에는 화주 곽명스님이 약사전을 중건하였으며, 1876년(고종 13)에는 화주 설허스님이 칠성각을 중건하였다.', '2026-06-29 14:38:30.611');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (54, '127219', '수국사(서울)', 1, 22, NULL, NULL, NULL, NULL, '09:00~18:00 (전화문의)', '연중 무휴', '수국사는 1459년에 세조의 큰 아들 승(덕종으로 추존)의 왕생을 위해 고양군 동쪽 봉현에 능침사찰로 창건을 명한 정인사(正因寺)의 후신이다. 하지만 재목이 부실하다 하여 1471년 덕종의 부인이자 성종의 모후인 인수대비(仁粹大妃) 한씨가 판내시부 이효지에게 중창할 것을 명하여 총 119칸의 규모로 중창하는데, 당시 사격이 봉선사(奉先寺)와 쌍벽을 이루었다고 한다. 1721년에는 서오릉에 소재하는 숙종과 인현왕후(仁顯王后)가 안장된 명릉(明陵)의 능침사찰로 지정되면서 이름도 수국사로 바뀌었다. 순종이 태자 시절 북한산성을 관리하는 승병의 최고책임자인 총섭 월초스님의 기도로 쾌차되어 이를 계기로 고종의 후원을 얻어 1900년 수국사를 중창하였다. 그 뒤 6·25 전쟁으로 옛 모습은 잃었지만, 역대 주지스님들이 계속하여 중창을 거듭해 오다 1995년 황금법당을 지었다. 현재 수국사에는 고려 후기 불상인 보물 목조아미타여래좌상 및 복장유물과 서울특별시 유형문화유산으로 지정된 1907년에 제작된 불화 6점이 남아있다.', '2026-06-29 14:38:30.61');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (196, '127643', '서울 효창공원', 1, 21, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '서울 효창공원은 조국의 독립을 위해 몸 바친 애국지사들의 유해를 모시는 곳이다. 이곳은 원래 조선 후기 정조의 맏아들 문효세자를 비롯하여 그의 어머니 의빈 성씨, 순조의 후궁인 숙의 박씨, 숙의 박씨의 자녀인 영온공주의 무덤인 효창원이 있던 자리이다. 청일전쟁 때 일본군이 불법으로 주둔하면서 훼손되었으며 일제강점기에는 골프장이 들어서는 등 공원화되었다. 1940년에 조선총독부가 공원으로 고시한 이후 1944년에는 일제의 침략전쟁에서 전사한 군인들을 위한 충령탑 건립을 위해 무덤들을 고양시에 있는 서삼릉으로 옮겼다. 광복 이후 대한민국 임시정부 주석인 백범 김구 선생이 항일투쟁에 목숨을 바친 이봉창, 윤봉길, 백정기 삼의사의 유해를 모셨고, 안중근 의사의 가묘를 이곳에 썼다. 이어 1948년에는 임시정부 의장과 주석을 지낸 이동녕, 국무원비서장 차리석, 군무부장 조성환을 이곳에 모셨다. 1949년에 돌아가신 김구 선생의 유해도 국민장으로 안장하였다.', '2026-06-29 14:43:18.725');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (51, '2554262', '한국항공대학교 항공우주박물관', 31, 2, '경기도 고양시 덕양구 항공대학로 76-9 (화전동)', 37.5998685786, 126.8652606119, 'https://tong.visitkorea.or.kr/cms/resource/51/4070851_image2_1.jpg', NULL, NULL, '한국항공대학교 항공우주박물관은 국내 청소년과 일반인들에게 항공우주 과학 기술에 대한 이해를 보급하고자 한다. 지난 50여 년간 국내 항공우주 전문 인력을 양성해 온 한국항공대학교의 전문가들이 그간 축적한 역량을 바탕으로 독창적이며 참신한 아이디어를 이 항공우주박물관을 통해 구현하고자 했다. 교수와 대학원생, 그리고 직원들이 참여하여 직접 멀티미디어 영상물을 만들었으며 국내 유수의 벤처기업과 협동으로 가상체험 시설을 구축하고 콘텐츠를 개발했다. 또한, 많은 항공기 전시 모델의 제작에는 교내의 대학생 동아리가 참여했다. 유물 전시를 위주로 하는 기존 박물관의 고루한 개념에서 벗어나 과학적 이해와 간접 체험을 위주로 전시 내용을 구성했다. 또한, 첨단 정보기술 및 멀티미디어 시설을 이용하여 학습 효과를 높이는 새로운 체계를 구현하고자 했다. 이러한 점에서 이곳은 내용적으로 과학관이라 할 수 있으며 관람객들은 다른 박물관들과 차별화된 경험을 할 수 있다.', '2026-06-29 14:38:30.609');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (62, '129501', '낙산공원', 1, 23, NULL, NULL, NULL, NULL, '상시 개방 ※ 낙산 전시관 09:00~17:00', '연중무휴', '낙산공원은 대학로와 동대문으로부터 이어지며 역사와 문화를 함께 즐길 수 있는 공원이다. 낙산은 지형이 낙타의 등처럼 생겨 낙타산이라고도 했고, 궁에 우유를 보급하던 왕실 목장이 있어 타락산이라고도 불렀다. 1960년대 이후 시민아파트와 밀집된 주택으로 낙산 본래의 모습이 사라지게 되었고, 서울시가 낙산 복원계획을 수립하였다. 이 계획의 일환으로 공원화 사업이 진행되어 2002년 7월 낙산공원으로 개원하였다. 낙산공원 중앙광장에는 낙산전시관과 중앙무대, 매점 등이 있어서 쉬어가기 좋고 광장 바로 아래 주차장이 있어서 중앙광장으로 오기도 편하다. 낙산전시관은 낙산공원 입구에 있는 시설물로 낙산의 유래, 역사적 인물, 한양도성의 사진 자료 및 모형이 전시되어 낙산공원을 방문하는 시민들에게 다양한 정보를 제공한다. 주말에는 낙산과 서울한양도성에 관한 공원 이용 프로그램이 운영되며, 누구나 무료로 이용할 수 있다. 광장 한쪽으로는 낙산정이 있다. 낙산정은 낙산을 복원하면서 만든 정자로 서울의 전경이 한눈에 보이는 전망 좋은 곳이다.  
서울한양도성과 푸른 숲이 어우러져 아름다운 정취를 느낄 수 있는 시민의 휴식 공간으로 자리매김하였으며, 서울에서 가장 아름다운 야경을 볼 수 있는 곳으로 각광받고 있다. 언덕 정상에서 주택과 벽화가 있는 이화동 벽화마을로 갈 수 있고 흥인지문과 한양도성길로 가는 동대문 코스, 외부 성곽 벽면 전체를 보면서 걸을 수 있는 한성대 입구 방면 코스 등 다양한 코스가 있다. ◎ 한류의 매력을 만나는 여행 정보 - 애니메이션 
넷플릭스 애니메이션 ‘케이팝 데몬 헌터스’에서 루미와 진우가 대화를 나누며 걷던 장소 중 하나가 바로 이곳이다. 성곽 너머로 펼쳐지는 서울의 도시 풍경이 인상적으로 담겨, 애니메이션 속 감성을 더욱 깊이 있게 전한다. 실제로 방문하면 고즈넉한 성곽길과 함께 서울의 전경을 한눈에 내려다볼 수 있어 특별한 경험을 선사한다.', '2026-06-29 14:38:30.613');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (162, '3056152', '열린송현 녹지광장', 1, 23, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '열린송현 녹지광장은 종로구 송현동 부지에 있는 공간으로, 경복궁과 종로 사이에 위치하고 있는 광장이다. 송현동 부지는 일제강점기 식산은행 사택, 해방 후 미군 숙소, 미대사관 숙소 등으로 활용되어 오다가 1997년 우리 정부에 반환되었다. 하지만 이후 별다른 쓰임 없이 폐허로 방치되어 높은 벽에 둘러싸여 있었다. 2022년 7월 한국주택공사로 소유권이 넘어오고 서울시로 다시 소유권이 넘어가면서 쉼과 문화가 있는 열린송현 녹지광장으로 단장하고 시민에게 개방되었다. 높이 4m 담장에 둘러싸여 오랜 기간 닫혀있던 공간은 돌담을 낮추고 야생화로 어우러진 녹지로 조성하였다. 이로 인해 율곡로, 감고당길에서 드넓은 녹지광장을 한눈에 담을 수 있다. 돌담장 안으로 들어가면 광장 중앙에 서울광장 잔디보다 넓은 중앙잔디광장이 펼쳐진다. 광장 주변으로는 코스모스, 백일홍과 같은 야생화 군락지가 조성되어 있다. 경복궁과 북촌은 송현동 부지가 열리면서 광장 내부로 난 지름길로 연결된다. 광장을 가로지르며 걷다 보면 청와대, 광화문광장, 인사동 그리고 북촌 골목길로 자연스레 이어진다.', '2026-06-29 14:43:18.715');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (60, '1934593', '국립현대미술관 서울', 1, 23, '서울특별시 종로구 삼청로 30', 37.5786500878, 126.9800038741, 'http://tong.visitkorea.or.kr/cms/resource/02/2991502_image2_1.jpg', NULL, NULL, '국립현대미술관(서울관)은 동시대 현대미술을 중점적으로 다루는 미술관이다. 1986년 개관한 과천관, 1998년에 개관한 덕수궁관에 이어 2013년 개관한 서울관은 조선시대 소격서, 종친부, 규장각, 사간원이 있던 자리에 자리 잡고 있다. [마당] 개념을 도입하여 건축한 국립현대미술관(서울관)은 누구나 즐기고 휴식을 취할 수 있는 공간으로 꾸며져 있다. 건물의 내외부가 유기적으로 연결되어 있으며, 주변 명소와도 조화를 이루도록 설계되었다. 국립현대미술관(서울관)은 전시실을 비롯하여 디지털정보실, 멀티미디어홀, 영화관 등 다양한 시설을 갖춘 복합예술문화센터로서 한국 현대 미술품 전시 및 신매체 융복합 전시를 진행한다.', '2026-06-29 14:38:30.613');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (57, '127642', '창덕궁과 후원 [유네스코 세계유산]', 1, 23, NULL, NULL, NULL, NULL, '[2월~5월]- 09:00~18:00 (입장 마감 17:00)[6월~8월]- 09:00~18:30 (입장 마감 17:30)[9월~10월]- 09:00~18:00 (입장 마감 17:00)[11월~1월]- 09:00~17:30 (입장 마감 16:30)', '매주 월요일 (단, 월요일이 공휴일인 경우 개방하며, 그 다음 첫 번째 평일에 휴관)', '창덕궁(昌德宮)은 1405년(태종 5) 법궁인 경복궁의 이궁(離宮)으로 창건되었다. 1592년(선조 25) 임진왜란으로 소실되었다가 1610년(광해군 2) 궁궐 중 처음으로 다시 지어졌다. 이후 역대 왕들이 1867년 경복궁이 중건될 때까지 약 270여 년 동안 창덕궁을 더 많이 사용하여 실질적인 법궁의 역할을 하였다. 특히 대조전 부속 건물인 흥복헌은 1910년 경술국치가 결정되었던 비운의 장소이기도 하며, 낙선재 권역은 광복 이후 대한제국의 마지막 황실 가족인 순정황후(순종의 두 번째 황후), 의민황태자비(이방자 여사), 덕혜옹주(고종의 딸)가 생활하다가 세상을 떠난 곳이기도 하다.
창덕궁은 창경궁(昌慶宮)과 경계 없이 ‘동궐(東闕)’이라는 별칭으로 불렀다. 창덕궁은 다른 궁궐에 비해 인위적인 구조를 따르지 않고 주변 지형과 조화를 이루도록 자연스럽게 건축하여 가장 한국적인 궁궐이라는 평가를 받아 1997년 유네스코 세계유산에 등재되었다.

창덕궁 후원은 1406년(태종 6) 창덕궁 북쪽에 처음 조성된 후원은 세조 대에 확장하였고, 성종 대에 건립된 창경궁까지 그 영역이 확장되었다. 후원 권역은 임진왜란 때 대부분의 소실되었고, 1610년(광해군 2)에 다시 조성되었다. 이후 인조, 숙종, 정조, 순조 등 여러 왕들이 개수하고 증축하여 현재의 모습이 되었다.
창덕궁 후원은 자연 지형을 그대로 살리면서 골짜기마다 아름다운 정자를 만들었다. 4개의 골짜기에는 각각 부용지(芙蓉池), 애련지(愛蓮池), 관람지(觀纜池), 옥류천(玉流川) 영역이 펼쳐진다. 왕가의 휴식과 산책을 위한 곳이지만, 여러 가지 다른 용도로도 사용하였다. 자연 풍광을 느끼면서 시를 짓고 학문을 논하는 것을 포함하여 군사훈련 등의 활쏘기 행사, 연못에서 낚시를 하거나 배를 띄우기도 하고 꽃구경을 하였으며, 화약을 이용한 불꽃놀이도 하였다. 또 대비를 모시는 잔치, 종친이나 신하를 위로하는 잔치 등 임금이 주관하는 잔치도 자주 열렸다. 또한 왕은 이곳에 곡식을 심어 농사를 직접 체험하고, 왕비는 양잠을 직접 시행하는 친잠례(親蠶禮)를 열었다.', '2026-06-29 14:38:30.612');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (69, '2657245', '망향대', 2, 1, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '교동도 망향대는 한국 전쟁 때 황해도 연백에서 피난 와서 정착한 실향민들이 고향 땅을 바라보며 제사를 지내는 곳이다. 교동면 북서쪽 해안의 밤머리산에 위치하고 있는 망향대에서는 물길 건너로 북녘땅이 아주 가깝게 보인다. 분단 전에 교동도와 북한의 연백군은 생활권이 같아 뱃길로 왕래가 잦았지만 분단 이후 연백군 등 황해도에서 온 내려온 피난민들은 고향에 돌아갈 수 없게 되었다. 이후 실향민들은 고향 땅이 바라다보이는 이곳에 1960년에 비를 세우고 추석 등에 매년 망향대를 찾아 제를 올리며 망향의 한을 달래고 있다.', '2026-06-29 14:38:30.616');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (106, '127110', '강진 전라병영성', 38, 1, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '전라병영성[全羅兵營城]은 조선 태종 17년(1417년)에 설치되어 고종 32년(1895년) 갑오경장까지 조선조 500여 년간 전라남도와 제주도를 포함한 53주 6진을 총괄한 육군의 총지휘부이다. 그러나 1894년 갑오농민전쟁(동학)을 맞아 병화로 소실되었고, 이어 1895년 갑오경장의 신제도에 의해 폐영되고 말았다. 병영성 성곽의 총 길이는 1,060m이며, 높이는 3.5m, 면적은 93.139㎡(28.175평)인데, 현재 사적 397호로 지정되어 있다.

(출처 : 강진군 문화관광 홈페이지)', '2026-06-29 14:42:03.888');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (68, '2552255', '해든뮤지움', 2, 1, '인천광역시 강화군 길상면 장흥로101번길 44', 37.6121239304, 126.5088570712, 'http://tong.visitkorea.or.kr/cms/resource/20/3549020_image2_1.jpg', NULL, NULL, '해든뮤지움은 2013년 개관한 사립미술관으로 교육·문화·예술을 함께 누릴 수 있는 아름다운 자연 속에 위치한 예술 공간이다. 그동안 샤갈, 프랭크 스텔라, 로이 리히텐슈타인, 백남준, 김환기, 이우환 등 국내·외 작가들의 소장품 기획전과 한국 거장 작가들의 작품세계를 소개함으로써 대중들이 현대미술과 친숙한 기회의 장이 되도록 노력해 왔다. 전시회뿐만 아니라 문화생산의 역할을 다하기 위해 기존 92석 세미나실 외에 창작 프로그램과 강연이 가능한 144석 교육관을 신설하고 교육프로그램도 확충했다. 강화도의 수려하고 아름다운 자연과 어우러진 뮤지엄의 모던한 건축물도 눈길을 끈다. 자연과 어울림, 소통을 콘셉으로 한 뮤지엄은 건축물 자체가 하나의 예술 작품으로 평가받아 2013년에는 한국건축가협회에서 시상하는 <한국에서 가장 뛰어난 건축물 베스트 7>에  선정됐다.', '2026-06-29 14:38:30.616');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (112, '127184', '고려궁지', 2, 1, NULL, NULL, NULL, NULL, '09:00~18:00 (입장마감 17:00)', '연중무휴', '고려가 몽골군의 침략에 대항하기 위해 고종 19년(1232)에 강화도로 수도를 옮기고 1234년에 세운 궁궐과 관아건물이다. 정궁 이외에도 행궁·이궁·가궐을 비롯하여 많은 궁궐이 있었다. 정문은 승평문이었고 양쪽에 삼층루의 문이 두 개가 있었으며 동쪽에 광화문이 있었다. 39년 동안 사용되었고 1270년 강화조약이 맺어져 다시 수도를 옮기면서 허물어졌다. 조선시대에도 전쟁이 일어나면 강화도를 피난지로 정했다. 조선 인조 9년에 옛 고려 궁터에 행궁을 지었으나 병자호란 때 청군에게 함락되었다. 그 후 다시 강화유수부의 건물을 지었으나 병인양요 때 프랑스군에 의해 거의 불타 없어져 지금은 동헌과 이방청만이 남아있다. 이곳은 끊임없는 외세의 침략에 저항한 우리 민족의 자주정신과 국난 극복의 역사적 교훈을 안겨주는 곳이다.

(출처 : 국가유산청)', '2026-06-29 14:42:03.89');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (67, '3061177', '강화 화개산 모노레일', 2, 1, NULL, NULL, NULL, NULL, '- 평일 09:30~17:30- 주말 08:30~18:30', '연중무휴', '화개산 전망대를 가기 위한 이동 수단으로  외줄 레일을 따라 무인으로 운행된다. 모노레일에  탑승하면  연산군 유배지가 있는 화개정원과 탁 트인 교동도를 한눈에 볼 수 있다. 정상 승강장에 도착하면  북녘땅의 예산강을 따라 펼쳐진 연백평야를 볼 수 있는 망원경, 한반도 모양의 포토존 등이 설치되어 있다. 모노레일이 통과하는 화개정원과 화개산 전망대가 주변에 있어 자연경관도 즐길 수 있다. 모노레일은 상하행 각각 20분으로 왕복 40분이 소요된다.', '2026-06-29 14:38:30.615');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (26, '231977', '서울약령시한의약박물관', 1, 11, '서울특별시 동대문구 약령중앙로 26 (제기동)', 37.58061163308967, 127.0372098415386, 'https://tong.visitkorea.or.kr/cms/resource/54/3505454_image2_1.jpg', NULL, NULL, '서울약령시한의약박물관은 서울특별시 동대문구에서 2006년 9월에 설립한 공립박물관이다. 조선초기에 가난하고 병든 백성들을 돌보던 구휼기관인 보제원이 있던 유서 깊은 곳이다. 현재는 우리나라 최대의 한약유통 중심지인 서울약령시에 자리하고 있다. 2017년 10월 27일 서울약령시한의약박물관은 서울한방진흥센터 2층으로 이전하여 전통 한방의 우수성을 홍보하고 다양한 프로그램 등을 개발하여 우리나라의 대표적 한방문화공간으로 자리매김하고 있다.', '2026-06-29 14:34:12.484');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (73, '130226', '포스코미술관', 1, 1, '서울특별시 강남구 테헤란로 440', 37.505876575, 127.056076785, 'http://tong.visitkorea.or.kr/cms/resource/54/684154_image2_1.jpg', NULL, NULL, '포스코미술관은 1995년 9월 포스코센터 포스코갤러리로 설립되었으며 포스코홀딩스가 추구하는 배려와 공조, 공생의 가치를 예술을 매개로 나누고 실천하는 포스코 그룹의 아트 플랫폼이다. 포스코미술관은 주로 회화, 조각, 설치, 미디어 아트 등 다양한 장르의 전시를 개최하고 있다. 또한, 전시와 연계된 교육 프로그램, 강연, 워크숍 등을 운영하여 대중들의 문화예술 향유 기회를 확대하고 있다. 포스코미술관은 이외에도 일반인과 포스코 그룹사 임직원등을 위한 포스코미술관 프로그램을 운영하고 있다.', '2026-06-29 14:38:30.617');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (74, '130926', '도산안창호기념관', 1, 1, '서울특별시 강남구 도산대로45길 20 (신사동)', 37.52395084515243, 127.0356031666723, 'https://tong.visitkorea.or.kr/cms/resource/38/3507938_image2_1.jpg', NULL, NULL, '도산안창호기념관은 독립운동가이자 선각자인 도산안창호선생의 생애와 업적 및 유품을 전시하고 있는 곳이다. 각종 프로그램을 실시하여 기념관을 찾는 시민들에게 도산선생의 민족경륜사상과 나라사랑정신을 널리 전파하고자 1998년 정부의 지원과 시민들의 정성을 모아 민족교육의 장으로 활용하고자 건립되었다. 이 기념관은 도산선생 내외분의 묘소가 자리 잡고 있는 도산공원 내에 건립되었다는 것에 그 의미가 더욱 크다고 할 수 있다. 
도산기념관은 도산선생의 얼을 새기고 자라나는 청소년들에 도산선생이 보여주신 무실(務實), 역행(力行), 충의(忠義), 용감(勇敢)의 정신을 본받아  스스로의 삶의 길을 찾고, 나라사랑정신을 함양하는 산 교육의 장이 되기를 바란다.', '2026-06-29 14:38:30.618');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (139, '127220', '북한산국립공원(서울)', 1, 3, NULL, NULL, NULL, NULL, '상시 개방※ 단, 기상 여건에 따라 통제 가능', '연중무휴※ 단, 기상 여건에 따라 통제 가능', '북한산국립공원은 세계적으로 드문 도심 속의 자연공원이다. 수려한 자연경관과 문화자원을 온전히 보존하고 쾌적한 탐방 서비스 제공을 위하여 우리나라의 15번째 국립공원으로 지정되었다. 서울특별시와 경기도에 걸쳐 약 76.922㎢의 면적을 차지하며 우이령을 중심으로 남쪽의 북한산 지역과 북쪽의 도봉산 지역으로 구분된다. 중생대 때 관입된 화강암이 주된 암석을 이루고 있다. 북한산을 구성하고 있는 화강암 지반은 시간의 흐름에 따라 풍화 침식되면서 보른하르트(Bornhardt), 토르(tor), 판상절리, 수직절리, 타포니(tafoni), 나마(gnama), 그루브(groove) 등 다양한 미지형으로 나타나고 있다. 지질학적으로 고생대부터 화강암의 지반이 융기 및 침식되어 지금으로부터 약 2억만 년 전 중생대 쥐라기 중엽의 대보조산(大寶造山) 운동에 의해 형성되었다. 대표적인 지질명소로는 인수봉, 사모바위, 구천계곡 등 능선과 계곡을 따라 위치하여 다양한 볼거리를 제공함과 동시에 수도권 최고의 야외 지질교육의 장이 되고 있다. 거대한 화강암이 빚어낸 선인봉, 자운봉, 만장봉, 우이암, 오봉은 도봉산을 대표하는 봉우리로 장관을 이룬다. 이처럼 북한산국립공원은 거대한 화강암으로 이루어진 주요 암봉 사이로 수십 개의 맑고 깨끗한 계곡이 형성되어 산과 물의 조화를 빚어내고 있으며 아름다운 자연환경 속에서 1,300여 종의 동식물이 서식하고 있다. 또한 삼국시대 이래 과거 2,000년의 역사가 담긴 북한산성을 비롯한 수많은 역사 ·문화유적과 100여 개의 사찰, 암자가 곳곳에 위치하여 다양한 볼거리와 생태, 문화, 역사 학습장소를 제공한다.', '2026-06-29 14:42:03.898');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (80, '125552', '고양 서오릉 [유네스코 세계유산]', 31, 2, NULL, NULL, NULL, NULL, '[2월~5월/9월~10월]- 07:00~18:00- 입장 마감 17:00[6월~8월]- 07:00~18:30- 입장 마감 17:30[11월~1월]- 07:00~17:30- 입장 마감 16:30※ 기관 사정에 따라 관람 시간이 단축 및 조정이 있을 수 있으므로 자세한 사항은 홈페이지 참조 및 전화 문의 요망', '매주 월요일(단, 월요일이 공휴일인 경우 개방하며 그 다음 첫 번째 평일에 휴관)', '서오릉(西五陵)은 ‘서쪽에 있는 5기의 능’이라는 뜻으로 경릉(敬陵), 창릉(昌陵), 익릉(翼陵), 명릉(明陵), 홍릉(弘陵)의 다섯 능을 말한다. 서오릉은 구리 동구릉(東九陵) 다음으로 규모가 큰 조선왕실의 왕릉군이다. 1457년(세조 3) 세조의 첫째 아들 의경세자(추존 덕종)의 의묘(懿墓, 경릉)가 처음 조성되었고 1470년(성종 1) 예종의 창릉(昌陵)이 왕릉으로서 최초로 조성되었다. 이후 순회세자의 순창원(順昌園), 인경왕후의 익릉(翼陵), 숙종의 명릉(明陵), 정성왕후의 홍릉( 弘陵)이 차례로 조성되어 조선시대에는 5기의 능과 1기의 원이 조성되었다. 그러다가 1970년대 영빈 이씨의 수경원(綏慶園)과 옥산부대빈 장씨의 대빈묘(大嬪墓)가 옮겨져 지금의 서오릉이 되었다.', '2026-06-29 14:38:30.62');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (83, '2568681', '공릉천', 31, 2, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '고양시에 위치한 공릉천이 시작되는 곳은 덕양구 고양동, 신도동과 양주시 장흥면의 경계선이며, 관산동, 사리현동, 지영동을 거쳐 파주시 교하면에서 한강과 만난다. 파주 삼릉에 있는 공릉의 명칭을 따서 공릉천으로 부른다. 주변의 퇴적 평지대는 화훼단지와 논으로 이용되고 있다. 경기도 양주시, 고양시, 파주시에 흐르는 하천으로 한강의 제1지류이다. 공릉천의 물소리를 따라 걷다 보면 백로와 기러기떼 등 겨울 철새와 원앙, 비오리 등 천연기념물을 쉽게 만날 수 있다.', '2026-06-29 14:38:30.621');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (82, '2892126', '고양아람누리 아람미술관', 31, 2, '경기도 고양시 일산동구 중앙로 1286 고양아람누리', 37.660973360108, 126.772797186522, 'https://tong.visitkorea.or.kr/cms/resource/17/2892117_image2_1.jpg', NULL, NULL, '아람미술관은 정발산역 3번 출구에 있는 고양시립 미술관이다. 면적 1,300여 m²(400평), 높이 4m의 전시 공간을 갖추고 있으며 국내 신인 작가들을 발굴, 육성하고 세계 미술계의 경향을 국내에 소개하는 징검다리 역할을 하고 있다. 또한 회화, 사진을 비롯해 최첨단 미디어아트 전시까지 장르를 넘나드는 다양한 전시를 개최하고 있다. 주변에 아람 도서관과 공연장이 있어서 전시회 관람 후 연계해서 공연을 보거나 도서관에 들르기 좋다. 정발산역 인근에 식당과 카페도 많아서 가족 나들이 코스로도 좋다.', '2026-06-29 14:38:30.621');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (203, '630741', '경안천 습지생태공원', 31, 5, NULL, NULL, NULL, NULL, '- 하절기(3월~10월) 05:00~20:00<br>
- 동절기(11월~2월) 07:00~18:00', '연중무휴', '봄, 여름, 가을에 신록과 갈대가 어우러지는 경안습지생태공원은 일 년 내내 온갖 철새가 노니는 장소이다. 호숫가 갈대숲 사이로 보이는 몇 그루의 나무들이 운치를 더한다. 이곳은 1973년 팔당댐이 건설되면서 일대 농지와 저지대가 물에 잠긴 이후 자연적으로 습지로 변한 독특한 곳이다. 다양한 수생식물과 갖가지 철새와 텃새가 서식하게 되어 이제 조류관찰과 자연학습의 장으로 거듭났다. 공원을 휘휘 돌아 잘 정돈된 산책로가 조성되어 가족단위로 산책 나온 시민들과 자전거를 타는 사람들에게 휴식처를 제공하기도 한다. 습지는 자연정화기능이 탁월해 수질환경개선에 큰 도움이 되고 있어 점차 그 범위를 확대 조성할 계획에 있으며, 이곳 공원은 습지상태 자연 학습장으로 개인 및 단체 관람객들이 많이 찾아오고 있다.

(출처 : 광주시 문화관광 홈페이지)', '2026-06-29 14:43:18.727');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (199, '126522', '서울 동관왕묘', 1, 23, NULL, NULL, NULL, NULL, '※ 자세한 사항은 전화문의 요망', '연중무휴', '서울 동관왕묘는 중국의 고전인 삼국지에 나오는 명장 관우의 사당이다. 조선 선조 34년(1601년)에 동묘, 서묘 및 북묘를 세웠으나 지금은 동묘만 남아 있다. 임진왜란 때 왜병을 격퇴하는 데 관우의 힘이 컸다고 하여 명의 신종이 임진왜란 후에 비용과 친필로 쓴 편액을 보내와서 창건하였고, 영조 15년(1739년)에 중수하였다. 중국 묘사 건축의 영향을 받아 그 평면과 외관이 우리나라 건축과 비교할 때 매우 색다른 모습을 이루고 있다. 흙 돌담으로 둘러싸여 있고 각종 정원수와 의자가 있어 시민들의 휴식처 역할을 하고 있다.', '2026-06-29 14:43:18.725');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (15, '125587', '치악산국립공원', 32, 9, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴※ 기상여건에 따라 통제될 수 있으므로 방문 시 전화문의 요망', '치악산은 최고봉인 비로봉을 중심으로 삼봉, 향로봉, 남대봉, 천지봉 등 1,000m가 넘는 봉우리가 병풍처럼 남북으로 걸쳐 있다. 주봉인 비로봉에서 남대봉까지 남북으로 뻗은 치악 능선은 14km에 달하며, 총면적 182.09㎢로 1984년에 국립공원이 되었다. 구룡사, 상원사 등 신라 고찰을 비롯하여 영원산성, 해미산성 등 전란사가 담긴 유서 깊은 곳으로 기암괴석과 울창한 산림이 절경을 이루고 있으며 적악산으로 불리던 꿩의 보은 전설이 연유되어 치악산이 되었다. 구룡계곡, 금대계곡, 부곡계곡 등 기이한 암석들이 이룬 아름다운 계곡과 태종대, 구룡소, 세렴폭포, 구룡사, 상원사 등의 수많은 관광명소가 곳곳에 산재해 있으며 울창한 숲과 깨끗한 물, 가을 단풍과 특히 겨울 설경이 아름다워 등산객이 많이 방문하고 있다.', '2026-06-29 14:34:12.48');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (87, '2670558', '나리농원', 31, 18, NULL, NULL, NULL, NULL, '09:00~20:00', '매주 주말', '양주시에서 운영하는 나리농원은 전국 최대 규모의 천일홍꽃 군락지가 조성되어 있는 자연 친화형 힐링 공간이다. 매년 9월경이면 ‘천만송이 천일홍 축제’가 열려 많은 관광객들의 발길이 끊이지 않는다. 축제가 열리는 9월~10월 두 달 동안은 농원 입장 시간이 정해져 있으나 축제가 종료된 후에는 기존처럼 산책 및 통행이 가능하다. 깊어져 가는 선선한 가을날, 가족과 함께, 연인과 함께 행복한 시간을 만끽할 수 있다.', '2026-06-29 14:38:30.622');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (47, '2782912', '속리산테마파크모노레일', 33, 3, NULL, NULL, NULL, NULL, '- 평일 10:00~17:00<br>
- 주말 및 공휴일 09:20~17:00', '연중무휴', '속리산 풍경을 즐기며 할 수 있는 레포츠 중 하나이다. 솔향공원 주차장 이용이 가능하고 스카이 바이크, 집라인, 스카이 트레이 등과 함께 즐길 수 있다.  하부 승차장에서 전망카페까지 총 왕복 866m를 운행하며, 전망대에는 베이커리와 음료 등을 판매하는 카페도 있다. 당일 현장 접수만 하고 있으며, 1대당 수송 인원이 20명 정도로 적은 편이라 대기가 발생할 수 있다. 선착순 접수를 하니 미리 접수부터 하고 주변을 둘러보는 것이 좋다. 탑승 후 전망대에 도착해서도 먼저 하행 시간을 선착순 접수해 놓는 것이 편리하다. 남는 대기 시간에는 주변의 도깨비공원이나 속리산 자생 식물원을 구경할 수 있다.', '2026-06-29 14:34:12.492');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (61, '126537', '북촌한옥마을', 1, 23, NULL, NULL, NULL, NULL, '10:00~17:00<br>
※ 방문 제한시간(특별관리지역(레드존) 방문 금지) : 17:00~익일 10:00', '연중무휴', '북촌은 경복궁과 창덕궁, 종묘 사이에 위치한 곳으로 전통한옥이 밀집되어 있는 서울의 대표적인 전통 주거지역이다. 그리고 많은 사적들과 문화재, 민속자료가 있어 도심 속의 거리 박물관이라 불리어지는 곳이기도 하다. 청계천과 종로의 윗동네라는 뜻에서 ‘북촌(North Village)’이라고 이름으로 불리었으며, 가회동과 송현동, 안국동, 그리고 삼청동이 있다. 사간동과 계동, 소격동 그리고 재동에는 역사의 흔적이 동네이름으로 남아 수백 년을 지켜온 곳이기도 하다. 

북촌은 조선시대에 조성된 양반층 주거지로서 1920년대까지 그다지 큰 변화가 없었는데, 1930년대에 서울의 행정구역이 확장되고, 도시구조도 근대적으로 변형되면서 변화가 일어났다. 주택경영회사들이 북촌의 대형 필지와 임야를 매입하여, 그 자리에 중소 규모의 한옥들을 집단적으로 건설하였는데, 현재 한옥들이 밀집되어 있는 가회동 11번지와 31번지, 삼청동 35번지, 계동 135번지의 한옥주거지들이 모두 이 시기에 형성되었다. 대청에 유리문을 달고, 처마에 잇대어 함석 챙을 다는 등, 새로운 재료를 사용한 북촌의 한옥은 전통적인 한옥이 갖고 있는 유형적 성격을 잃지 않으면서, 근대적인 도시조직에 적응하여 새로운 도시주택유형으로 진화했다는 점에 주목할 수 있다. 

북촌 지역이 모두 한옥으로 이루어져 있던 1960년대와 달리, 1990년대 이후 급속하게 들어선 다세대가구 주택 때문에 많은 수의 한옥이 사라졌지만, 일부지역은 양호한 한옥들이 군집을 이룬 채 많이 남아 있다. 여러 채의 한옥이 지붕처마를 잇대고 벽과 벽을 이웃과 함께 사용하고 있는 풍경은 우리가 잊고 살았던 따뜻한 정과 살아갈 맛을 느끼게 해 준다. 북촌 지역을 걷다 보면 이어진 처마선의 아름다운만큼이나 골목길의 정겨움을 느낄 수 있다. 북촌한옥마을이 지속가능한 관광지가 될 수 있도록 침묵관광을 하도록 주의를 요한다.
※ 침묵관광이란 외부 관광객들의 관광지 방문으로 인해 주민들의 생활권과 환경권이 침해받지 않도록 큰 소리로 떠들지 않고 조용히 여행하는 관광형태를 말한다.

※ <strong>북촌마을 방문 시 지켜야 할 ‘에티켓’ </strong>
- 단체관광객 방문 시 반드시 가이드 동행
- 관광버스 불법주차 금지
- 무단 침입, 무단 촬영, 무단 투기, 노상방뇨, 소음 금지
- 마을 방문시간 준수', '2026-06-29 14:38:30.613');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (97, '125555', '수원 화성 [유네스코 세계유산]', 31, 13, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '수원화성은 조선왕조 제22대 정조대왕이 세자에 책봉되었으나 당쟁에 휘말려 왕위에 오르지 못하고 뒤주 속에서 생을 마감한 아버지 사도세자의 원침을 양주 배봉산에서 조선 최대의 명당인 수원 화산으로 천봉하고 화산 부근에 있던 읍치를 수원 팔달산 아래 지금의 위치로 옮기면서 축성되었다. 정조의 효심이 축성의 근본이 되었을 뿐만 아니라 당쟁에 의한 당파정치 근절과 강력한 왕도정치의 실현을 위한 원대한 정치적 포부가 담긴 정치구상의 중심지로 지어진 것이며 수도 남쪽의 국방요새로 활용하기 위한 것이었다. 수원화성은 중국, 일본 등지에서 찾아볼 수 없는 평산성의 형태로 군사적 방어기능과 상업적 기능을 함께 보유하고 있으며 시설의 기능이 가장 과학적이고 합리적이며, 실용적인 구조로 되어 있는 동양 성곽의 백미라 할 수 있다.

(출처 : 수원문화재단 홈페이지)', '2026-06-29 14:38:30.627');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (166, '2739477', '윤동주문학관', 1, 23, '서울특별시 종로구 창의문로 119', 37.5921816175, 126.9671657723, 'http://tong.visitkorea.or.kr/cms/resource/15/3302915_image2_1.jpg', NULL, NULL, '시인 윤동주는 연희전문학교 문과 재학시절, 종로구 누상동에 있는 소설가 김송(金松, 1909~1988)의 집에서 문우(文友) 정병욱과 함께 하숙생활을 하면서 종종 인왕산에 올라 자연 속에서 시정(詩情)을 다듬었다고 전해진다. <별 헤는 밤>, <자화상>, <또 다른 고향> 등 시인의 대표작들이 이 시기에 만들어졌다. 
윤동주문학관은 한국인이 사랑하는 민족 저항 시인 윤동주의 발자취와 세상을 향한 그의 시선을 기억하고자 2012년 세워졌다. 인왕산 자락에 버려져 있던 청운수도가압장과 물탱크를 의미 있게 리모델링한 곳이다. 2012년 대한민국 공공건축상, 2014년 서울시 건축상을 수상하고, 2015년에는 현충시설로 지정되면서 공간의 가치와 더불어 그 의미도 주목받고 있다.', '2026-06-29 14:43:18.716');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (65, '2657249', '교동제비집', 2, 1, NULL, NULL, NULL, NULL, '[하절기]- 10:00~18:00[동절기]- 10:00~17:00', '매월 셋째 화요일', '교동제비집은 인천광역시 강화군 교동면에 자리한 복합문화공간으로 교동도의 문화에 대해 알 수 있는 곳이다. 입구부터 교동도의 마스코트인 제비를 볼 수 있다. IT를 기반으로 한 관광 안내 콘텐츠가 있는 이곳은 교동도 관광 명소 VR(가상현실) 체험, 교동신문 제작 체험이 가능하다. 카페, 기념품 판매장 등을 함께 운영하며, 다양한 프로그램이 진행된다. 인근에 대룡시장이 자리하여 함께 관광하기 좋다.', '2026-06-29 14:38:30.615');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (66, '1953948', '교동향교', 2, 1, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '향교는 성현의 위패를 모시고 제사를 지내며, 지방 백성의 교육을 담당하기 위해서 국가에서 세운 교육기관이다. 고려 인종 5년(1127)에 화개산 북쪽에 지었으나 조선 영조 17년(1741)에 조호신이 현재의 위치로 옮겼으며 1966년에 수리하였다. 고려 충렬왕 12년(1286)에 안향이 원나라에 갔다가 돌아오는 길에 공자상을 들여와 모셨다고 전하며 이후 서울의 각 읍에 조상이나 성현의 위패를 모시는 문묘를 설치했다고 한다. 현재 남아있는 건물은 교육공간인 명륜당과 동재·서재가 있고, 제사공간을 형성하는 대성전과 동무·서무가 있다. 이외에도 내삼문·외삼문과 제기고 등이 있다. 조선시대에는 국가로부터 토지·노비·책 등을 지급받아 학생들을 가르쳤으나, 갑오개혁(1894) 이후 교육의 기능은 없어지고 제사의 기능만 남아있다. 

(출처 : 국가유산청)', '2026-06-29 14:38:30.615');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (96, '126517', '서울 문묘와 성균관', 1, 23, NULL, NULL, NULL, NULL, '- 하절기(3월~10월) 09:00~18:00- 동절기(11월~2월) 09:00~17:00', '연중무휴', '서울 문묘와 성균관은 종로구 명륜동 성균관대학교 안에 있는 유적으로 1398년 조선 태조가 창건했다. 문묘는 유교를 집대성한 성인 공자를 비롯하여 옛 성현들의 위패를 모시고 제사를 드리는 사당이고 성균관은 고려시대 국자감의 전통을 이어받은 조선시대 최고의 국립 교육기관이다. 중국 당나라 때 공자가 문선왕으로 추봉 됨에 따라 문선왕묘라고 부르다가 원나라 이후 문묘라고 하였다. 전묘후학의 건물 배치 형식으로 제사를 드리는 제향 구역인 문묘는 앞에, 교육을 실시하는 강학 구역인 성균관은 뒤에 두었다. 제사를 담당한 제향 관련 건물로는 대성전을 비롯하여 동무·서무, 비각, 삼문(신삼문), 동삼문, 제기고, 전사청, 수복청, 향관청, 포주 등이 있다. 교육을 담당한 강학 관련 건물로는 명륜당을 비롯하여 동재·서재, 존경각, 육일각, 진사식당, 정록청, 비복청, 서리청, 비천당 등이 있다. 주요 건물인 대성전, 명륜당, 동무·서무, 삼문(신삼문)은 보물로 지정되고 나머지 유적들은 1964년 11월 10일 사적으로 지정되었다. 명륜당 앞쪽에는 천연기념물로 지정된 은행나무가 있다. 조선시대에 제향과 유학 교육을 담당한 유교의 중심지로, 역사적으로 중요한 의미가 있으며 건축사 연구를 위한 자료로도 가치가 큰 유적이다.', '2026-06-29 14:38:30.626');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (102, '129811', '국립고궁박물관', 1, 23, '서울특별시 종로구 효자로 12 (세종로)', 37.57659156422034, 126.9749748635226, 'https://tong.visitkorea.or.kr/cms/resource/35/4054035_image2_1.png', NULL, NULL, '1992년 궁중유물전시관으로 설립되었다. 조선시대와 대한제국기의 격조 높은 왕실유물을 전시하여 조선왕조에 대한 올바른 이해와 역사관을 정립하고자 조선왕조 정궁인 경복궁과 연계한 문화 공간으로 조성되어 광복 60주년이던 2005년 8월 15일에 국립고궁박물관으로 명칭을 변경하였고,  2007년 11월에 전면 개관하였다. 조선시대 최고 수준의 문화와 정신이 집약되어 있는 왕실 유물의 과학적이고 체계적인 보존과 복원을 통해 다양하고 시의성 있는 왕실 문화 전시를 기획하고, 왕실 소장품을 꾸준히 확충하여 전시 유물을 확대해나가고 있다. 또한 왕실 문화를 주제로 한 다양한 교육 프로그램을 운영하고, 국내‧외의 왕실 문화 기관과의 교류 활성화에도 많은 노력을 하고 있다. 이를 통해 품격 있는 왕실 문화유산의 의미를 관람객에게 전달하며 조선 왕실과 대한제국 황실의 가치를 전달하고자 한다.', '2026-06-29 14:42:03.887');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (91, '2733962', '수성동계곡', 1, 23, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '수성동계곡은 인왕산에서 흘러 내려와 청계천으로 합류하는 계곡으로, 계곡의 물소리가 크고 맑아 동네 이름이 조선 시대에 수성동(水聲洞)으로 불렸다고 한다. 겸재 정선이 북악산과 인왕산의 경승 8경을 그려 담은 ‘장동팔경첩’에 속할 만큼 아름다운 곳으로 조선 시대 역사 지리서인 『동국여지비고』, 『한성지략』 등에 ‘명승지’로 소개된 곳이다. 또한 안평대군과 겸재 정선이 자주 찾아와 아름다운 수성동계곡을 바라보며 한문과 예술을 즐겼다고 한다. 1971년 옥인시범아파트가 들어서면서 수려한 경관을 잃어버렸으나 그로부터 40년 후, 아파트를 철거하고 문화재보호 구역으로 지정되면서 본래의 아름다움을 되찾게 되었다. 역사와 자연이 어우러져 멋진 숲과 시원한 계곡을 도심 속에서 만나 볼 수 있는 큰 매력이 있는 장소이다. 아름다운 인왕산 풍경을 그리는 사람들의 모습을 볼 수 있고, 시원한 물에 발을 담그며 즐거운 시간을 보내는 사람들도 있다.', '2026-06-29 14:38:30.624');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (101, '2756396', '덕수궁 밤의 석조전', 1, 24, '서울특별시 중구 세종대로 99 (정동)', 37.5650549194, 126.9765746344, 'https://tong.visitkorea.or.kr/cms/resource/03/4073903_image2_1.jpg', NULL, NULL, '은 전문 해설사와 함께하는 ''석조전 야간 탐방''과 클래식 연주를 들으며 고종이 사랑했던 가배차(커피)와 디저트를 즐기는 ''테라스 카페 체험'', 대한제국 황실의 이야기를 담은 뮤지컬 공연 관람으로 구성되어 있는 덕수궁 야간 관람 프로그램이다. 2021년 시범 사업을 시작으로 높은 만족도와 호응에 힘입어 2022년 정식 개최되었으며, 2023년부터 반기별로 운영되고 있다. 궁인의 안내에 따라 대한제국 황실의 이야기를 품은 덕수궁 석조전으로 시간 여행을 떠나는 특별함을 경험하고, 개화기 소품을 활용한 ''인생궁컷'' 사진과 기념품을 통해 덕수궁 석조전에서의 밤을 오래 기억할 수 있는 복합 문화 체험 프로그램이다.', '2026-06-29 14:42:03.886');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (107, '128819', '대한성공회 강화성당', 2, 1, NULL, NULL, NULL, NULL, '10:00~18:00', '매주 월요일', '강화성당은 고요한 (Charies Jone Corfe) 초대주교가 1900년에 축성한 건물로 성베드로와 바우로 성당으로 명명되었다. 당시 건축공사는 궁궐 도편수가 주도하였고 이후 몇 차례 보수가 있었으나 처음 모습이 그대로 보존되고 있다. 성당터는 세상을 구원하는 방주로서의 의미를 분명히 하기 위해 배의 형상을 따랐다. 성당 건물은 장방형(넓이 4칸, 길이 10칸) 중층구조로 전체적인 건축양식은 한국전통양식을 따르고 있으며,  배치와 내부구조는 서양식 바실리카 건축양식을 응용하여 조화의 아름다움과 토착정신을 드러나게 하였다. 성공회 강화성당은 1981년 경기도 지방유형문화유산으로 처음 지정된 이래 강화군이 인천광역시로 편입되면서 인천지방유형 문화유산으로 변경되었다가 2001년 1월에 국가사적으로 변경 지정되었다.', '2026-06-29 14:42:03.888');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (144, '402994', '삼청동수제비', 1, 23, '서울특별시 종로구 삼청로 101-1', 37.5846049848, 126.9819035323, 'http://tong.visitkorea.or.kr/cms/resource/12/3082712_image2_1.jpg', NULL, NULL, '삼청동수제비는 삼청동사무소 바로 옆에 자리 잡고 있으며 1982년부터 지금까지 영업을 이어오고 있는 곳이다. 이곳의 대표메뉴는 호박을 송송 썰어 넣고 조갯살과 감자를 넣어 항아리에 담아져 나오는 수제비와 아무것도 넣지 않고 100% 감자만을 이용해 부쳐 내오는 감자전이다. 최근 일본 잡지에도 소개가 되어 이곳을 찾는 일본인도 심심찮게 볼 수 있으며 항상 줄 서서 먹는 맛집이다. 
인근에 북촌한옥마을, 국립현대미술관, 경복궁, 덕수궁 등 서울의 관광명소가 있다.', '2026-06-29 14:42:03.899');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (145, '130152', '서대문형무소역사관', 1, 14, '서울특별시 서대문구 통일로 251', 37.5743038949563, 126.955534576211, 'https://tong.visitkorea.or.kr/cms/resource/29/3520329_image2_1.jpg', NULL, NULL, '서대문형무소는 대한제국 말에 일제의 강압으로 감옥이 지어져 80여 년 동안 우리 근현대사 격동기의 수난과 역사의 현장이자 우리 민족의 항일 독립운동에 대한 일본 제국주의의 대표적인 탄압기관이었다. 1908년 10월 21일에 경성감옥이란 이름으로 문을 연 뒤 일제에게 우리의 국권이 빼앗기자 이에 항거하는 민족독립운동이 전국에서 거세게 일어나고 일제는 수많은 우리의 애국지사들을 체포 투옥시켰다. 수용인원이 증가하자 그들은 마포 공덕동에 또 다른 감옥을 지었고 이 때문에 1912년 9월 3일에 서대문감옥으로 이름이 바뀌었다. 이름의 변화만큼이나 많은 민족수난의 역사를 간직한 채 1992년 8월 15일에 현재의 ‘서대문독립공원’으로 개원하였다. 서대문구에서는 1995년부터 서대문독립공원 사적지에 대한 성역화사업을 시작하였다. 조국 독립을 위해 일제의 침략에 맞서 싸우다 투옥되어 모진 고문과 탄압을 받고 순국하신 애국선열들의 넋을 기리고 후손들에게 우리 선열들의 자주독립 정신을 일깨워 주는 역사의 산 교육장으로 삼기 위해 새롭게 단장하여 서대문형무소역사관으로 개관하였다.', '2026-06-29 14:42:03.9');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (36, '125785', '영월 청령포', 32, 8, NULL, NULL, NULL, NULL, '09:00~18:00 (입장 마감 17:00)', '매주 월요일 (단, 월요일이 공휴일인 경우 그 다음 날 휴무) /  설·추석 당일', '청령포는 영월군 남면 광천리 남한강 상류에 있는 이곳은 왕위를 빼앗기고 영월로 유배된 단종이 머무르던 곳이다. 조선 제6대 왕인 단종은 숙부인 수양대군에게 왕위를 선위하고 상왕으로 있다가 그다음 해인 1456년 성삼문 등 사육신들의 상왕복위의 움직임이 사전에 누설됨으로써 상왕은 노산군으로 강봉 되었다. 이후 첨지 중추원사 어득해가 거느리는 군졸 50인의 호위를 받으며 원주, 주천을 거쳐 이곳 청령포에 유배되었다. 청령포는 동, 남, 북 삼면이 물로 둘러싸이고 서쪽으로는 육육봉이라 불리는 험준한 암벽이 솟아있어 나룻배를 이용하지 않고는 밖으로 출입할 수 없는 곳이었으며 단종은 이 적막한 곳에서 외부와 두절된 유배 생활을 했고, 당시에는 이곳에 거처할 수 있는 집이 있어 호장 엄흥도는 남몰래 밤이면 이곳을 찾아 문안을 드렸다고 전한다. 

(출처 : 영월군 문화관광 홈페이지)', '2026-06-29 14:34:12.488');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (161, '129610', '강화 연미정', 2, 1, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '강화군 강화읍 월곶리에 위치한 연미정은 자연경관을 보며 풍류를 즐기거나 학문을 공부하던 정자로, 최초 건립연대는 정확히 알지 못하나 임진왜란, 병자호란, 6.25 전쟁을 거치며 여러 차례 시련을 겪고 파손된 것을 현재와 같이 복원하였다. 정자는 지붕 옆면이 여덟 팔(八) 자 모양인 팔작지붕집의 겹처마로 돌기둥 위에 10개의 기둥을 얹어 건축한 민도리집이다. 한강과 임진강의 합해진 물줄기가 강화도 동북단에 이르러 서쪽과 남쪽으로 나뉘어 흐르는데, 이 모양이 마치 제비꼬리 같다고 하여 연미정이라 이름이 붙여졌다.', '2026-06-29 14:43:18.715');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (108, '125564', '강화산성', 2, 1, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '강화읍을 에워싸고 있는 고려시대의 산성이다. 몽골의 침입으로 백성과 국토가 수난을 당하자, 당시 실권자인 최우는 1232년 강화도로 수도를 옮겼다. 왕궁과 성·관아 시설은 1234년 본격적인 공사가 시작되었다. 이때 개경의 궁궐과 비슷하게 지어 산의 이름도 송악이라 지었다. 성은 흙으로 쌓았고, 내성·중성·외성으로 이루어져 있고, 내성은 주위 약 1,200m로 지금의 강화성이다. 중성은 내성을 지키기 위해 쌓았으며, 외성은 1233년 강화 동쪽해안을 따라 쌓았다. 이 외성은 몽골군이 바다를 건너 공격하지 못하게 한 가장 중요한 방어시설이자, 정부가 39년간 육지로부터 물자를 지원받았던 곳이기도 하다. 고려 원종 11년(1270) 개경으로 수도를 다시 옮기면서 몽골과 강화조약의 조건으로 성을 모두 헐게 되었다. 조선 전기에 내성이었던 강화성을 축소하여 다시 지었다. 1637년 병자호란 때 청군에 의해 다시 파괴당하였고, 숙종 3년(1677)에 성을 보수하면서 모두 돌로 쌓고 넓혀 지었다. 남문인 안파루·북문인 진송루·서문인 첨화루와 동문인 망한루가 있으며, 비밀통로인 암문 4개 그리고 수문이 2개 남아있다. 높은 곳에서 망을 보기 위한 장대와 성위에서 몸을 감추기 위한 여장 등의 방어시설도 갖추고 있었으나 여장은 모두 무너졌다. 현재 성의 동쪽 부분은 없어졌으나, 남북 쪽 산자락은 복원 정비되어 있다. 조선 후기 병인양요·신미양요와 일본 침략에 의한 강화조약을 체결한 수많은 외세침략의 역사적인 현장이다.

(출처 : 국가유산청)', '2026-06-29 14:42:03.888');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (109, '129810', '강화역사박물관', 2, 1, '인천광역시 강화군 하점면 강화대로 994-19', 37.7737399035, 126.4352815292, 'http://tong.visitkorea.or.kr/cms/resource/21/3383821_image2_1.JPG', NULL, NULL, '강화역사박물관은 강화의 문화유산을 보존·연구하여 전시할 목적으로 세워진 공립박물관으로 갑곶돈대 옆에 있었던 것을 2010년 지금의 자리로 이전했다. 상설전시실, 기획전시실을 비롯하여 영상실 등 다양한 부대시설을 갖추고 있다. 상설전시실에는 강화의 선사유적지와 고려왕릉에서 출토된 유물과 향교, 전통 사찰 소장품 등의 문화재가 전시되어 있고, 기획전시실에서는 해마다 다채로운 주제의 특별전이 열린다. 강화 역사의 이해를 돕기 위해 영상실과 교육프로그램을 함께 운영하고 있어 복합문화공간으로서 역할을 다하고 있다. 강화역사박물관은 고인돌공원 옆에 자리 잡고 있어 세계문화유산으로 지정된 강화고인돌과 길이 710cm, 너비 550cm 되는 거석인 청동기시대의 대표적 유물인 강화지석묘를 볼 수 있다.', '2026-06-29 14:42:03.889');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (113, '2662855', '광교호수공원', 31, 13, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '광교호수공원은 아름다운 수변공간인 어반레비와 함께 6개의 테마를 가진 둠벙으로 어우러져 여러 가지 새로운 문화를 담은 국내 최대의 도심 속 호수공원이다. 광교산과 원천저수지 및 신대저수지의 자연을 최대한 보존함에 중점을 두었다. 바닥분수인 ‘신비한 물너미’, ‘물보석 분수’ 등 9개의 분수시설과 총 6.5㎞의 순환보행로, 도심 속 힐링 공간인 가족캠핑장, 다양한 체험이 가능한 다목적 체험장, 야외공연장, 스포츠클라이밍장, 수변 위에 5개의 원형데크와 아치형의 정다운 다리가 있는 조용한 숲, 행복한 꽃섬, 습지와 버드나무가 어우러진 먼 섬 숲등 여러 가지 특색 있는 공간이 다양하게 조성되어 있다. 또한 IFLA(세계조경가협회)상 수상, 2014년 대한민국 경관대상을 받은 공원으로 아름다운 경관을 자랑하고 있다.', '2026-06-29 14:42:03.89');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (114, '775394', '광화문광장', 1, 23, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '새로운 모습으로 단장하여 시민들에게 개방된 광화문 광장은 600년 역사를 지닌 서울의 중심거리 세종로를 차량 중심의 거리에서 인간 중심의 공간으로 전환하고 경복궁과 북악산 등 아름다운 자연경관을 조망할 수 있는 공간으로 새롭게 조성하여 세종로의 옛 모습인 육조거리 복원을 통한 역사·문화 체험 공간으로 재탄생되었다. 초입 구간인 ‘광화문의 역사를 회복하는 광장’에는 월대를 재현하고 해태 상을 복원하였으며 세종로 공원 주변 구간인 ‘육조거리의 풍경을 재현하는 광장’에는 과거 한양의 중심거리였던 육조거리의 흔적을 재현하고 이를 형상화한 축소모형도 설치하였다.', '2026-06-29 14:42:03.89');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (147, '2598331', '문화가 흐르는 서울광장', 1, 24, '서울특별시 중구 을지로 지하12 (을지로1가)', 37.56544835496842, 126.9787818353424, 'https://tong.visitkorea.or.kr/cms/resource/68/4059668_image2_1.jpg', NULL, NULL, '일상 속 문화 향유 기회를 제공하는 이 5월부터 12월까지 약 8개월 간 서울광장에서 진행된다. 2026년 5월 6일 개막공연을 시작으로 대중가요부터 힙합, 재즈, 밴드, 퍼포먼스까지 다양한 장르의 공연이 매월 진행 될 예정이다.', '2026-06-29 14:42:03.9');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (159, '3080477', '수원전통문화관', 31, 13, NULL, NULL, NULL, NULL, '09:00~18:00', '매주 월요일', '수원전통문화관은 2015년에 개관하였으며, 수원시와 수원문화재단이 공동 운영하고 있다. 전통식생활체험관과 예절교육관으로 구성되어 있으며, 음식과 예절을 주제로 다양한 교육과 체험 프로그램을 운영한다. 전통식생활체험관에서는 약과 만들기, 전통병과 체험, 김장문화 등 전통음식을 직접 만들어보는 원데이 클래스가 마련되어 있다. 예절교육관에서는 다례, 인성교육, 성년의례, 규방공예 등 전통 예절과 관련한 특성화 교육이 제공된다. 수원 장안문 인근에 위치해 있으며, 화성행궁, 수원화성, 행리단길 등 주변 관광 자원과도 연계가 가능하다.', '2026-06-29 14:43:18.715');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (169, '3044977', '이상의집', 1, 23, NULL, NULL, NULL, NULL, '10:00~17:00 (12:00~13:00 휴게시간)', '매주 월요일', '이상의 집은 모더니즘을 대표하는 작가 이상(본명 김해경 1910~1937)이 세 살부터 20여 년간 머물렀던 집터였던 곳으로, 철거될 위기에 있던 이곳을 2009년 [문화유산국민신탁]이 시민 모금과 기업 후원으로 매입하여 보전·관리하고 있다. 이곳은 이상의 큰아버지 댁의 일부로 본채, 행랑채, 사랑채까지 있던 300평 규모의 넓은 집이었지만 10개의 필지로 나눠져서 한옥들이 들어섰다고 한다. 그중 집터의 일부를 매입한 것이다. 
실내에는 이상의 흉상과 초상화가 있고 그의 작품을 연대별로 보관한 아카이브가 한쪽 벽면에 설치되어 있어 이상의 작품들을 만나 볼 수 있다. 실내의 왼편으로 콘크리트 사각 문틀이 육중하게 설치되어 있고 검은색으로 도색된 큰 철문을 열고 들어가면 빛이 없는 어두운 공간 속 옥상으로 올라가는 계단이 나온다. 높지 않은 계단 끝에 외부로 통하는 문을 열면 환한 빛이 실내로 밀려 들어온다. 어두운 시대상과 그가 처한 현실 상황에 한 줄기 자유를 갈망하는 감정을 공간으로 잘 표현했다고 극찬 받는 상징적인 공간이다.', '2026-06-29 14:43:18.717');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (157, '2992822', '세종마을 음식문화거리', 1, 23, NULL, NULL, NULL, NULL, '점포별 상이', '점포별 상이', '인근 먹자골목으로 과거 금천교 시장으로 불리던 것이 2011년 ‘세종마을 음식문화거리’라는 공식 명칭을 얻었다. 실제로 ‘세종마을’은 세종대왕이 태어난 마을이라 붙은 이름이다. 왕의 이름이 붙은 동네지만 분위기는 왁자지껄한 서민 거리 그 자체. 금천교 시장으로 불릴 때부터 오랜 단골을 확보해 둔 손맛 좋은 노포들과 새로 유입된 청년 사장들의 톡톡 튀는 최신 핫플레이스가 사이좋게 공존하는 점이 이 거리의 매력이다. 추억을 더듬으며 그때 그 맛집을 찾는 사람과 SNS에서 핫플레이스를 검색해 새로운 맛집 리스트를 발굴하려는 사람까지 한꺼번에 만족시킬 수 있는 다양한 선택지가 있다. 입소문을 타고 가게들이 몰려들면서 이제는 메인 골목뿐 아니라 구석구석 샛길까지 독특한 맛집이 빼곡하게 들어섰으며 말 그대로 ‘골라 먹는’ 재미가 있는 종로구 대표 먹자골목으로 자리매김했다. 경복궁역 2번 출구가 시작점이다.', '2026-06-29 14:43:18.714');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (70, '126525', '서울 선릉과 정릉 [유네스코 세계유산]', 1, 1, NULL, NULL, NULL, NULL, '06:00~21:00', '매주 월요일', '선릉(宣陵)은 조선 9대 성종과 세 번째 왕비 정현왕후 윤씨의 왕릉이다. 선릉은 같은 능역에 하나의 정자각을 두고 서로 다른 언덕에 능침을 조성한 동원이강릉(同原異岡陵)의 형식이다. 정자각 앞에서 바라보았을 때 왼쪽 언덕(서쪽)이 성종, 오른쪽 언덕(동쪽)이 정현왕후의 능이다. 선릉은 1494년 성종이 세상을 떠나자 다음 해인 1495년 광주 학당리인 현재의 자리에 조성하였다. 원래 이 자리는 4대 세종의 아들 광평대군묘역이 있던 자리였으나, 선릉이 조성되면서 광평대군묘역은 현 강남구 수서동으로 옮겼다. 이후 1530년 정현왕후가 세상을 떠나자 선릉 동쪽 언덕에 능을 조성하였다. 선릉은 정릉과 함께 1592년 임진왜란 때 왜적들이 능을 파헤쳐 재궁(梓宮)까지 불에 타는 피해를 당하여 1593년 7월에 다시 장례를 치렀다.

정릉(靖陵)은 조선 11대 중종의 왕릉이다. 중종은 1544년에 세상을 떠나 다음 해인 1545년 두 번째 왕비 장경왕후의 희릉 서쪽 언덕(현 고양 서삼릉 내 철종의 예릉 자리)에 능을 조성하고 능의 이름을 희릉과 함께 정릉이라 하였다. 그러나 정릉은 1562년 세 번째 왕비 문정왕후에 의해 현재의 자리로 옮겼다. 문정왕후는 당시 봉은사 주지였던 보우와 논의하여 중종의 능을 이곳으로 옮겼는데, 이는 문정왕후 본인이 중종의 묻히기를 원해서였다. 그러나 옮긴 정릉이 지대가 낮아 비가 오면 침수되는 일이 자주 일어나자 문정왕후는 세상을 떠난 후 정릉이 아닌 현재 서울 노원구 태릉에 묻히게 되었다. 이로 인해 중종과 세 왕비(단경왕후, 장경왕후, 문정왕후)의 능은 모두 따로 흩어지게 되었다. 정릉은 선릉과 마찬가지로 1592년 임진왜란 때 능이 파헤쳐져 재궁(梓宮)이 불에 타는 피해를 입었고, 1593년 8월에 다시 장례를 치렀다.', '2026-06-29 14:38:30.616');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (158, '638913', '수원박물관', 31, 13, '경기도 수원시 영통구 창룡대로 265 (이의동)', 37.2976471504, 127.035632945, 'https://tong.visitkorea.or.kr/cms/resource/81/4056581_image2_1.jpg', NULL, NULL, '수원박물관은 지하 1층, 지상 2층으로 수원역사박물관, 한국서예박물관 등 2개의 상설전시관과 특별전시실로 구성되어 있다. 오감으로 즐기고 배우는 어린이체험실, 다채로운 교육 프로그램 등이 운영되고, 소장유물은 수원지역에서 발굴된 유물, 구입 및 기증받은 유물 등으로 48,000여 점을 소장하고 있다. 
수원역사박물관은 수원의 유구한 역사와 문화를 과거·현재·미래의 시점과 주제별로 구성하였으며, 크게 네 부분으로 구성된 전시관은 ‘수원의 자연환경’, ‘선사·역사시대의 변천사’, ‘수원로의 개설’, ‘60년대 수원 만나기’, ‘근대 수원의 문화’로 과거의 역사와 문화뿐만 아니라 현대의 발전하는 역동적인 수원의 모습을 다양하게 보여주고 있다.
한국서예박물관은 지방자치단체에서는 최초로 건립한 서예 전문 박물관으로, 우리나라 서예사를 한눈에 살펴볼 수 있다. 전시는 유물의 시기와 특성에 따라 각각의 전시 주제로 구성되어 있고 조선시대 사랑방이 재현되어 있다. 중요 작품으로는 영조와 정조가 쓴 어필첩 등이 있다.', '2026-06-29 14:43:18.714');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (149, '128611', '서울숲', 1, 16, NULL, NULL, NULL, NULL, '상시 개방※ 시설별 이용시간 상이하므로 홈페이지 참조', '연중무휴※ 시설별 쉬는날 상이하므로 홈페이지 참조', '서울숲은 1908년 설치된 서울 최초의 상수원 수원지였으며, 2005년에 뚝섬체육공원 일대를 대규모 도시 숲으로 만들기 위해 새롭게 개원하였다. 현재는 문화예술공원, 체험학습원, 생태숲, 습지생태원 네 가지의 특색 있는 공간들로 구성되어 있으며, 한강과 맞닿아 있는 다양한 문화여가공간을 제공한다. 또한 서울숲공원은 조성부터 프로그램 운영까지 시민의 참여로 이루어진 최초의 공원이다.', '2026-06-29 14:42:03.901');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (127, '1906334', '동대문역사문화공원', 1, 24, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '동대문역사문화공원은 서울특별시 중구의 옛 동대문운동장 자리에 조성한 공원이다. 서울의 옛 역사와 문화를 보여주는 테마공원이자, 현대의 디자인과 문화를 경험할 수 있는 전시관 및 행사장, 시민들의 휴식공간이다. 2008년 동대문운동장을 철거하고 공원화하는 과정에서 조선시대의 서울성곽인 이간수문과 치성, 하도감과 훈련도감 터를 비롯한 건물지 유구 44기, 조선백자와 분청사기 등의 도자류를 포함해 주요 유물 1,000여 점이 출토되었다. 발굴된 유물은 공원 곳곳에 보존해 전시하고 있다. 공원 입구에는 동대문운동장 기념관이 있다. 옛 동대문운동장의 추억과 역대 스포츠 경기 정보, 각종 스포츠 관련 유물과 옛 동대문 운동장의 모형을 전시하고 있다. 수도권 지하철 2, 4, 5호선 동대문역사문화공원역 1번 출구에서 26m에 있다. 동대문디자인플라자(DDP)와 신당동 떡볶이 거리가 도보 10분 거리에 있어 함께 둘러보기 좋다.', '2026-06-29 14:42:03.895');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (118, '132226', '낙원 악기상가', 1, 23, '서울특별시 종로구 삼일대로 428 (낙원동)', 37.5728259087, 126.9880310857, 'http://tong.visitkorea.or.kr/cms/resource/19/923719_image2_1.jpg', NULL, NULL, '인사동 전통문화의 거리 바로 옆에 있는 낙원 악기상가는 70년대 이래로 악기 및 음악 관련 제품과 정보, 서비스만을 취급하고 있는 전문 상가로, 세계 최대의 규모이다. 330여 개에 이르는 악기점에서 기타, 관현악기, 타악기, 국악기와 첨단 전자악기 및 앰프와 스피커 등 각종 음향과 방송설비의 국내외 최신 제품과 정보를 얻고 구매할 수 있으며, 고가의 최신 제품뿐만 아니라 중고품의 교환과 판매도 가능해서 피아노 등 중고품의 수리, 조율 및 교환 등의 서비스도 제공된다. 또, 각종 행사의 악기 및 음향 장비 대여 서비스도 가능하다. 같은 상가 내에 복합 상영관인 할리우드 극장도 있어 인사동 전통문화의 거리와 함께 종로의 대표적인 명소로 자리매김하고 있고, 최근의 리뉴얼 이후로 일요일에도 개장하여 더욱 쾌적한 쇼핑환경을 제공하고 있다.', '2026-06-29 14:42:03.892');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (179, '127558', '진관사(서울)', 1, 22, NULL, NULL, NULL, NULL, '09:00~18:00', '연중무휴', '진관사는 대한불교조계종 직할사찰로 동쪽의 불암사, 남쪽의 삼막사, 북쪽의 승가사와 함께 예로부터 서울 근교의 4대 명찰로 손꼽히는 이름난 사찰이다. 거란의 침입을 막아내고 국력을 수호한 고려 제8대 현종(顯宗)이 1011년에 진관대사를 위해 창건했으며, 6·25 당시 폭격으로 폐허가 되었다가 복구된 고찰로 전해진다. 
2009년도 칠성각 내부해체 과정에서 칠성각의 불단(佛壇)과 기둥 사이에서 태극기를 보자기처럼 사용하여 싸여 있는 독립신문 등 20여 점의 독립운동 관련 유물들이 발견되었다. 발견된 태극기는 1919년 3·1 운동 당시 기관이나 단체가 제작하여 사용했던 것으로 보이며 당시 일장기 위에 태극기를 그린 것으로 태극기 및 독립운동사에서 중요한 역사적 가치를 가지고 있다.

(출처 : 진관사 홈페이지)', '2026-06-29 14:43:18.72');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (184, '1957671', '종로 청계 관광특구', 1, 23, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '광화문 빌딩부터 숭인동 사거리까지 서린·관철·관수·장사·예지동 전역, 신문로 1가 일부, 종로 1~6가 일부, 창신동 일부를 아우르고 있는 종로청계관광특구는 세련된 고층 빌딩숲과 절묘하게 어우러진 조선시대 궁궐들인 경복궁, 창덕궁, 창경궁, 덕수궁, 운현궁과 종묘 등을 함께 만날 수 있다. 또한 옛 왕조의 문화재를 비롯하여 많은 박물관이 있으며, 인사동 전통문화의 거리, 관철동 젊음의 거리, 귀금속 거리, 세운전자상가, 조명 상가, 광장시장, 문구 상가 등의 특색을 갖춘 각양각색의 거리 덕분에 볼거리가 넘쳐난다. 한국을 찾는 외국인 관광객들에게도 유명한 곳으로 언론사와 관공서, 서점 등이 밀집해 문화를 가장 가까이 느낄 수 있는 공간이며 청계천을 따라 걷는 산책 코스도 잘 갖춰져 있다. 종로 일대의 특화된 거리를 따라 무려 1만 4,000여 개의 상점들이 즐비해 있고 의류와 신발 같은 패션 관련 물품은 물론이고 귀금속, 전자, 문구, 액세서리 등 품목도 다양하다. 옛 모습을 간직한 좁다란 골목들을 둘러보는 것만으로도 충분히 흥미롭지만 종로와 청계천 일대에서 상시로 열리는 여러 축제와 행사도 즐겁다.', '2026-06-29 14:43:18.721');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (125, '127425', '독립문', 1, 14, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '서대문독립공원에 있는 독립문은 갑오개혁 이후 자주독립의 의지를 다짐하기 위해 중국 사신을 영접하던 영은문을 헐고 세운 기념물이다. 갑오개혁은 내정개혁과 제도개혁을 추진하였던 개혁운동이다. 그러나 외국세력의 간섭으로 성공하지 못하였고 나라의 자주독립 또한 이루지 못하였다. 이에 국민들은 민족의 독립과 자유를 위해서는 어떠한 간섭도 허용하지 않겠다는 다짐으로, 중국사신을 맞이하던 영은문을 헐고 그 자리에 독립문을 세우게 되었다. 화강석을 쌓아 만든 이 문의 중앙에는 무지개 모양의 홍예문이 있고 왼쪽 내부에는 정상으로 통하는 돌층계가 있다. 정상에는 돌난간이 둘러져 있으며, 홍예문의 가운데 이맛돌에는 조선왕조의 상징인 오얏꽃무늬가 새겨져 있다. 그 위의 앞뒤에는 한글과 한자로 ‘독립문’이라는 글씨와 그 양옆에 태극기가 새겨져 있다. 바로 인근에는 서대문형무소가 있어 독립문과 더불어 민주주의와 자유의지에 대한 갈망을 되새겨 보는 역사 여행을 할 수 있다.', '2026-06-29 14:42:03.894');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (126, '2470006', '동대문디자인플라자(DDP)', 1, 24, NULL, NULL, NULL, NULL, '10:00~20:00<br>
※ 프로그램에 따라 일부공간 탄력운영', '1월 1일 / 설·추석 당일<br>※ 시설 별로 상이하므로 자세한 사항은 홈페이지 참조', '꿈꾸고(Dream), 만들고(Design), 누린다(Play)는 뜻을 가지고 있는 DDP(동대문 디자인 플라자)는 서울특별시 동대문에 위치한 복합문화공간이다. 2014년 3월 21일 개관한 이래 굵직한 전시와 패션쇼, 신제품 발표회, 포럼과 콘퍼런스를 개최해오고 있다. 알림터, 배움터, 살림터, DDP 디자인 뮤지엄, 디자인 장터와 어울림 광장, 동대문 역사 문화공원으로 나뉘어 있다. 알림터에서는 서울패션위크, MAMA(Mnet Asian Music Awards), 반클리프 아펠전, BMW 신차 발표회 등을 개최했고, 다목적 연회 공간인 국제회의장 시설을 갖추었다. BTS 주제전과 서울도시건축 비엔날레 등이 열렸던 배움터, 누구나 디자이너가 되는 곳을 주제로 2019년 개장한 시민 라운지 ‘D-숲’과 DDP 관련 기념품을 소개하는 DDP 디자인 스토어를 아우르는 살림터까지, 규모에 걸맞은 내실로 관람객의 흥미를 북돋운다. 식당과 베이커리, 카페가 들어선 디자인 장터 역시 감성 충전을 기대하는 가족이나 연인을 만족시키고도 남을 산책 코스다.

SNS 상에 동대문디자인플라자의 야경 사진이 범람하는 데는 이유가 있는 법이다. 건축가 자하 하디드(Zaha Hadid)가 동대문디자인플라자를 설계하며 “이른 새벽부터 밤이 저물 때까지 쉴 새 없이 변화하는 동대문의 역동성에 주목해 곡선과 곡면, 사선과 사면으로 이뤄진 특유의 건축 언어로 자연물과 인공물이 이음매 없이 이어지는 공간을 만들어냈다"라고 밝혔는데, 해 질 녘 조명이 켜진 후 건축물에 오롯이 집중할게 될 때 곡선 부가 주는 역동성의 진가가 드러난다. 야경 사진을 찍기 좋은 지점은 어울림 광장 진입로로, 내부의 웅장함과 건축물의 신비로운 소재가 연출하는 분위기를 담을 수 있다. 알림터와 배움터를 나누는 살림터 문 앞은 내외부의 현란한 곡선과 조명이 정점을 이룬다.', '2026-06-29 14:42:03.894');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (137, '126537', '북촌한옥마을', 1, 23, NULL, NULL, NULL, NULL, '10:00~17:00<br>
※ 방문 제한시간(특별관리지역(레드존) 방문 금지) : 17:00~익일 10:00', '연중무휴', '북촌은 경복궁과 창덕궁, 종묘 사이에 위치한 곳으로 전통한옥이 밀집되어 있는 서울의 대표적인 전통 주거지역이다. 그리고 많은 사적들과 문화재, 민속자료가 있어 도심 속의 거리 박물관이라 불리어지는 곳이기도 하다. 청계천과 종로의 윗동네라는 뜻에서 ‘북촌(North Village)’이라고 이름으로 불리었으며, 가회동과 송현동, 안국동, 그리고 삼청동이 있다. 사간동과 계동, 소격동 그리고 재동에는 역사의 흔적이 동네이름으로 남아 수백 년을 지켜온 곳이기도 하다. 

북촌은 조선시대에 조성된 양반층 주거지로서 1920년대까지 그다지 큰 변화가 없었는데, 1930년대에 서울의 행정구역이 확장되고, 도시구조도 근대적으로 변형되면서 변화가 일어났다. 주택경영회사들이 북촌의 대형 필지와 임야를 매입하여, 그 자리에 중소 규모의 한옥들을 집단적으로 건설하였는데, 현재 한옥들이 밀집되어 있는 가회동 11번지와 31번지, 삼청동 35번지, 계동 135번지의 한옥주거지들이 모두 이 시기에 형성되었다. 대청에 유리문을 달고, 처마에 잇대어 함석 챙을 다는 등, 새로운 재료를 사용한 북촌의 한옥은 전통적인 한옥이 갖고 있는 유형적 성격을 잃지 않으면서, 근대적인 도시조직에 적응하여 새로운 도시주택유형으로 진화했다는 점에 주목할 수 있다. 

북촌 지역이 모두 한옥으로 이루어져 있던 1960년대와 달리, 1990년대 이후 급속하게 들어선 다세대가구 주택 때문에 많은 수의 한옥이 사라졌지만, 일부지역은 양호한 한옥들이 군집을 이룬 채 많이 남아 있다. 여러 채의 한옥이 지붕처마를 잇대고 벽과 벽을 이웃과 함께 사용하고 있는 풍경은 우리가 잊고 살았던 따뜻한 정과 살아갈 맛을 느끼게 해 준다. 북촌 지역을 걷다 보면 이어진 처마선의 아름다운만큼이나 골목길의 정겨움을 느낄 수 있다. 북촌한옥마을이 지속가능한 관광지가 될 수 있도록 침묵관광을 하도록 주의를 요한다.
※ 침묵관광이란 외부 관광객들의 관광지 방문으로 인해 주민들의 생활권과 환경권이 침해받지 않도록 큰 소리로 떠들지 않고 조용히 여행하는 관광형태를 말한다.

※ <strong>북촌마을 방문 시 지켜야 할 ‘에티켓’ </strong>
- 단체관광객 방문 시 반드시 가이드 동행
- 관광버스 불법주차 금지
- 무단 침입, 무단 촬영, 무단 투기, 노상방뇨, 소음 금지
- 마을 방문시간 준수', '2026-06-29 14:42:03.898');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (123, '126487', '마로니에공원', 1, 23, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '마로니에공원은 서울 시민들을 위한 문화예술의 터전으로 옛 서울대학교 문리대, 법대 자리에 있다. 이곳에는 마로니에나무가 자라고 있는데 1929년 4월 5일 서울대학교의 전신인 경성제국대학 시절에 심은 것으로, 이 나무 이름을 따서 마로니에공원이라는 이름이 붙었다.
어린이놀이터가 있고 야외무대와 분수공원, 조각품 등이 전시되어 있다. 야외무대는 가수들의 공연장과 각종 문화행사장으로 활용되고 있다. 이 공원 주위로 문예회관 대극장과 바탕골소극장, 동숭아트센터 등의 소극장이 자리하고 있다. 유명한 맛집과 다양한 컨셉의 카페들이 주위에 많다. 이 공원에서는 연중무휴 무료로 개방되는 공연과 행사들에 많아서 언제 방문하더라도 참여하고 즐길 거리가 가득하다.', '2026-06-29 14:42:03.893');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (164, '2757831', '우면산자연생태공원', 1, 15, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '우면산은 높이 293m로 서초구 우면동과 서초동, 양재동 등지의 도심에서 쉽게 오를 수 있는 산이다. 산모양이 소가 졸고 있는 모양이라 하여 우면산이라 이름이 붙여졌다. 우면산의 남쪽 기슭은 청동기시대 유적인 지석묘가 있어 이 지역이 오래전부터 우리 조상들의 삶의 터전이었음을 알 수 있다.
우면산은 서울시 도시자연공원으로 지정, 관리되고 있다. 산책로 및 등산로가 태극, 유점사, 서초약수터 등 약수터와 대성사, 정도전의 묘, 이존오의 사당, 예술의 전당 등 문화유적과 사찰, 문화공간이 부합되어 있어 도시주민의 아늑한 휴식처를 제공하고 있다. 깔끔하게 정돈된 학습장이라기보다 자연 그대로를 즐길 수 있게 되어 있다.', '2026-06-29 14:43:18.716');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (131, '2613658', '방화수류정(동북각루)', 31, 13, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '수원성 화홍문의 동쪽에 인접한 높은 벼랑 위에 있는 방화수류정(訪花隨柳亭)은 1794년(정조 18) 수원성곽을 축조할 때 세운 누각 중 하나이다. 동북각루가 공식 명칭이지만 “꽃을 찾고 버들을 따라 노닌다”라는 뜻에 걸맞게 경관이 뛰어나 방화수류정이라는 당호가 붙여졌다. 한 때 홍수로 인해 퇴락한 것을 1848년에 재건축했으며 이후 수원성복원사업의 일환으로 대대적으로 수리했다.2011년 보물로 지정된 방화수류정은 독특한 평면과 지붕형태 때문에 바라보는 위치에 따라 다른 모습을 보여준다. 이 때문에 화성에서 가장 독창적인 건축물로 평가되고 있다. 정조가 화성행차 시에 휴식을 취했다는 정자에서는 동으로는 연무대와 동북공심돈, 서로는 장안문과 팔달산이 한눈에 조망된다.', '2026-06-29 14:42:03.896');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (133, '130473', '백범김구기념관', 1, 21, '서울특별시 용산구 임정로 26 (효창동)', 37.5443314817, 126.9592678461, 'http://tong.visitkorea.or.kr/cms/resource/98/3521598_image2_1.jpg', NULL, NULL, '백범김구기념관은 세계에서 가장 아름답고 높은 문화를 가진 자주·민주·통일 조국을 건설하기 위해 일생을 분투하신 겨레의 큰 스승 백범 김구 선생(1876~1949)의 삶과 사상을 널리 알리고 계승·발전시키기 위해 2000년 6월에 기공하여 2002년 10월 22일에 개관하였다. 
근·현대사 전문 역사박물관인 백범김구기념관은 격동의 한국 근·현대사와 함께 한 김구 선생의 삶과 사상을 통해 대한민국 임시정부의 역사와 한국 근·현대를 이해하고 조국의 자주·민주·통일을 지향하며 민족의 아름다운 문화를 발전시켜 나아가는 온 거레의 문화적 삶의 공간이다.
기념관 1층과 2층에 김구 선생의 일대기와 한국 근·현대사 관련한 각종 기록 및 자료를 전시하고 있으며, 전문 자료실과 각종 교육프로그램, 문화행사 등에 활용될 수 있는 교육장, 대회의실, 컨벤션홀 등 다양한 교육·문화공간을 갖추고 있다.', '2026-06-29 14:42:03.896');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (4, '3056468', '서학동 예술마을', 37, 12, NULL, NULL, NULL, NULL, '점포 별로 상이함', '점포 별로 상이함', '서학동 예술마을은 전주시 완산구 서학로에 위치한 예술마을이다. 전주천을 사이에 두고 맞은편에는 전주한옥마을이 있다. 전주한옥마을이 관광객으로 북적이는 분위기라면 서학동 예술마을은 그에 비해 덜 알려져 인적이 드물고 조용한 분위기이지만 이미 이곳을 아는 사람들 사이에서는 입소문이 난 지 오래다. 서학동 예술마을은 과거, 교사와 학생이 많이 살고 있어 선생촌으로 불리던 곳이었으나 지역 상권의 쇠퇴와 주거시설의 낙후 등의 문제로 쇠락의 길을 걷게 되었다. 그러던 중, 2010년 음악을 하고 글을 쓰는 부부가 한옥을 고쳐 ‘벼리채’라는 문패를 달고 창작활동을 하면서 화가, 자수가, 사진작가, 도예가, 음악가 등 예술인들이 하나둘 모여들기 시작하고 갤러리가 들어서면서 자연스레 예술촌이 만들어지기 시작했으며, 지금은 30~60대의 예술가 30여 명이 마을 주민과 공존하고 있다. 1980년~1990년대 옛 골목 풍경을 그대로 간직한 이곳은 오랫동안 영업을 이어오고 있는 떡집, 쌀집, 이발소 등과 예술가들이 운영하는 갤러리와 공방이 오묘한 조화를 이루고 있다. 서학동 예술마을에서 10년 넘게 자리를 지키고 있는 한옥 갤러리 ‘서학동 사진미술관’을 비롯해 화가가 운영하는 게스트하우스, 감성 가득한 카페와 갤러리들, 개성 넘치는 공방과 소품숍에서는 즉석에서 만들기 체험도 할 수 있다. 이 외에도 독특한 외관의 갤러리 적요쉼쉬다’ 드라마 촬영지로도 유명한 게스트하우스, 한지패브릭아트샵, 뜨게공방 등 하루의 시간도 짧을 만큼 특색있고 개성 넘치는 곳들로 넘쳐난다. 홈페이지를 통해 원하는 공간을 검색해서 찾아가거나 추억을 불러일으키는 골목골목을 걷다가 마음에 드는 곳으로 불쑥 들어가도 실패할 일이 없다. 전주 여행을 계획 중이라면 이곳 서학동 예술마을에서 추억과 낭만을 재충전해 보기를 추천한다.', '2026-06-29 14:34:12.475');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (130, '126517', '서울 문묘와 성균관', 1, 23, NULL, NULL, NULL, NULL, '- 하절기(3월~10월) 09:00~18:00- 동절기(11월~2월) 09:00~17:00', '연중무휴', '서울 문묘와 성균관은 종로구 명륜동 성균관대학교 안에 있는 유적으로 1398년 조선 태조가 창건했다. 문묘는 유교를 집대성한 성인 공자를 비롯하여 옛 성현들의 위패를 모시고 제사를 드리는 사당이고 성균관은 고려시대 국자감의 전통을 이어받은 조선시대 최고의 국립 교육기관이다. 중국 당나라 때 공자가 문선왕으로 추봉 됨에 따라 문선왕묘라고 부르다가 원나라 이후 문묘라고 하였다. 전묘후학의 건물 배치 형식으로 제사를 드리는 제향 구역인 문묘는 앞에, 교육을 실시하는 강학 구역인 성균관은 뒤에 두었다. 제사를 담당한 제향 관련 건물로는 대성전을 비롯하여 동무·서무, 비각, 삼문(신삼문), 동삼문, 제기고, 전사청, 수복청, 향관청, 포주 등이 있다. 교육을 담당한 강학 관련 건물로는 명륜당을 비롯하여 동재·서재, 존경각, 육일각, 진사식당, 정록청, 비복청, 서리청, 비천당 등이 있다. 주요 건물인 대성전, 명륜당, 동무·서무, 삼문(신삼문)은 보물로 지정되고 나머지 유적들은 1964년 11월 10일 사적으로 지정되었다. 명륜당 앞쪽에는 천연기념물로 지정된 은행나무가 있다. 조선시대에 제향과 유학 교육을 담당한 유교의 중심지로, 역사적으로 중요한 의미가 있으며 건축사 연구를 위한 자료로도 가치가 큰 유적이다.', '2026-06-29 14:42:03.895');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (163, '127111', '강진영랑생가', 38, 1, NULL, NULL, NULL, NULL, '09:00~18:00', '연중무휴', '영랑 김윤식 선생은 1903년 1월 16일 이곳에서 김종호의 2남 3녀중 장남으로 태어났다. 어릴 때에는 채준으로 불렀으나 윤식으로 개명하였으며 영랑은 아호인데 문단활동시에는 주로 이 아호를 사용했다. 영랑 선생은 1950년 9월 29일 작고하기까지 주옥같은 시 80여편을 발표하였는데 그중 60여편이 광복전 창씨개명과 신사참배를 거부하며 이곳에서 생활하던 시기에 쓴 작품이다. 영랑생가는 1948년 영랑이 서울로 이거한 후 몇 차례 전매 되었으나 1985년 강진군에서 매입하여 관리해 오고 있는데 안채는 일부 변형 되었던 것을 1992년에 원형으로 보수하였고, 문간채는 철거 되었던 것을 영랑 가족들의 고증을 얻어 1993년에 복원하였다. 생가에는 시의 소재가 되었던 샘, 동백나무, 장독대, 감나무 등이 남아 있으며 모란이 많이 심어져 있다.', '2026-06-29 14:43:18.716');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (138, '1196886', '[북한산 둘레길 5구간] 명상길', 1, 22, '서울특별시 성북구 정릉동', 37.6186, 126.9965, 'https://tong.visitkorea.or.kr/cms/resource/18/3500018_image2_1.jpg', NULL, NULL, '북한산 둘레길은 기존의 샛길을 연결하고 다듬어서 북한산 자락을 완만하게 걸을 수 있도록 조성한 저지대 수평 산책로이다. 둘레길은 전체 71.5㎞ 중 서울시 구간과 우이령길을 포함하여 2010년 9월 7일 45.7㎞를 개통하고, 2011년 6월 30일에 나머지 25.8㎞ 구간을 개통하였다. 사람과 자연이 하나 되어 걷는 둘레길은 물길, 흙길, 숲길과 마을길 산책로의 형태에 각각 21가지 테마를 구성한 길이다. 누구나 쉽게 이용할 수 있는 둘레길을 우리의 소중한 자연을 보존하는 길, 그리고 역사와 문화, 생태를 체험할 수 있는 길이다.
21가지 테마 중 5구간인 명상길은 북한산 탐방안내소를 지나 정릉주차장에서 청수사 입구로 진입하면 시작된다. 호젓한 참나무길은 명상을 하기 좋은 장소이다. 명상길 구간은 탐방로와 형제봉 능선 사이를 경유하는 곳으로, 수평과 수직의 탐방이 적절히 배합된 둘레길 구간이다. 그동안 군사보호시설에 의해 통제되거나 최근에 개방된 북악하늘길과 연결되어 있어 백두대간에서 한북정맥으로 이어지는 북한산의 혈류를 잇는 의미 있는 구간이다. 거리는 총 2.4㎞이며, 약 1시간 10분이 소요된다.', '2026-06-29 14:42:03.898');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (176, '2778454', '정동길', 1, 24, '서울특별시 중구 정동', 37.5679539218, 126.9696134574, 'http://tong.visitkorea.or.kr/cms/resource/80/2795180_image2_1.jpg', NULL, NULL, '서울 정동길은 서울 시내에서 가장 유명한 산책길 중의 하나로, 정동교회 앞 사거리에서 이화여자고등학교 동문 앞을 지나 새문안길에 이르는 구간이다. 정동길 일대는 조선 시대 이후 근대 서울 역사를 기록하고 있는 커다란 박물관이다. 특히, 덕수궁과 서울시립미술관, 정동제일교회 등 근대 건축물들이 밀집해 있다. 
이 일대는 한양도성의 서부 서대문과 서소문 사이 성안에 자리하여 성벽이 보호막이 되어주면서 일찍부터 왕실과 양반 관료의 주거공간으로 발달하였고, 궁궐과 왕비능이 위치하였다. 
정동길은 벚꽃과 단풍이 아름다운 계절마다 많은 이들이 찾는 산책로로 알려져 있어 ‘낙엽 쓸지 않는 길’로 지정이 되어 있다. 또한, 1999년 서울시에서 ‘걷고 싶은 거리 1호’로 지정되었으며,  2006년 건설교통부가 선정한 ‘한국의 아름다운 길 100선’에서 최우수상을 차지한 바도 있다.', '2026-06-29 14:43:18.719');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (136, '126504', '봉은사(서울)', 1, 1, NULL, NULL, NULL, NULL, '09:00~18:00※ 자세한 사항은 전화문의 요망', '연중무휴', '봉은사는 서울의 중심지인 강남구 삼성동에 자리 잡은 천년고찰이다. 794년 연화국사가 창건하였고 처음엔 견성사라고 하였다. 이후 1498년 성종의 계비 정현왕후가 성종의 능(선릉) 동편에 있던 이 절을 크게 중창하고 절 이름을 봉은사로 바꿨다. 조선조에는 조계종을 대표하는 선종 수사찰로, 근대에는 역경사업과 도제를 양성했던 동국역경원이 세워진 터전이다. 오늘날 봉은사는 수행 중심의 사찰 운영으로 새로운 불교 역사를 만들어 가고 있다. 템플스테이를 비롯한 불교대학, 경전학교 등 다양한 프로그램을 통해 국내외적으로 양질의 한국불교문화를 널리 알리고 있을 뿐 아니라, 사회복지 또한 실현하는 도심 대찰의 위상을 이어가기 위해 노력하고 있다.', '2026-06-29 14:42:03.897');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (151, '130361', '서울역사박물관', 1, 23, '서울특별시 종로구 새문안로 55 (신문로2가)', 37.5698981615, 126.9707771853, 'http://tong.visitkorea.or.kr/cms/resource/87/2661487_image2_1.JPG', NULL, NULL, '세계도시로 성장한 서울이 어떻게 탄생했으며 어떻게 변해서 오늘에 이르렀는지를 배우고 앞으로 어떻게 바뀔 것인지를 가늠해 보는 곳이 서울역사박물관이다. 서울의 뿌리와 서울 사람의 생활, 현대 서울로의 변화를 보여주는 상설전시와 함께 서울의 역사·문화를 증언하는 다양한 기증유물이 전시되어 있다. 또한 어린이와 가족, 어른들을 위한 각종 체험교실과 문화행사들이 풍성하게 마련되어 있다.', '2026-06-29 14:43:18.712');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (128, '3351831', '만석공원', 31, 13, NULL, NULL, NULL, NULL, '24시간', NULL, '만석공원은 경기도 수원시 장안구 송죽동에 위치하고 있는 공원이다. 1998년에 조성되었으며 만석거(萬石渠)라는 저수지를 중심으로 하고 있다. 정자 이외에도 분수대, 휴게시설, 운동시설 등이 다양하게 들어서 있다.또한 공원 내에 수원미술관이 있어 예술작품을 감상할 수도 있다.', '2026-06-29 14:42:03.895');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (141, '127558', '진관사(서울)', 1, 22, NULL, NULL, NULL, NULL, '09:00~18:00', '연중무휴', '진관사는 대한불교조계종 직할사찰로 동쪽의 불암사, 남쪽의 삼막사, 북쪽의 승가사와 함께 예로부터 서울 근교의 4대 명찰로 손꼽히는 이름난 사찰이다. 거란의 침입을 막아내고 국력을 수호한 고려 제8대 현종(顯宗)이 1011년에 진관대사를 위해 창건했으며, 6·25 당시 폭격으로 폐허가 되었다가 복구된 고찰로 전해진다. 
2009년도 칠성각 내부해체 과정에서 칠성각의 불단(佛壇)과 기둥 사이에서 태극기를 보자기처럼 사용하여 싸여 있는 독립신문 등 20여 점의 독립운동 관련 유물들이 발견되었다. 발견된 태극기는 1919년 3·1 운동 당시 기관이나 단체가 제작하여 사용했던 것으로 보이며 당시 일장기 위에 태극기를 그린 것으로 태극기 및 독립운동사에서 중요한 역사적 가치를 가지고 있다.

(출처 : 진관사 홈페이지)', '2026-06-29 14:42:03.899');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (152, '3351700', '서초문화예술공원', 1, 15, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '매헌시민의 숲 제3 구역에 조성된 서초문화예술공원은 1994년 5월에 조성되었다. 조각공원, 각종 기획전시장, 야외공연장, 만남의 광장등이 공간으로 이루어져 있다. 이곳에는 지속적인 공연과 전시회등이 열리고 있어 문화자치구를 자랑하는 서초구의 새로운 명소로 각광받고 있다. 문화예술공원에서는 2곳의 메타세쿼이아 길을 볼 수 있는데 첫 번째는 어린이 교통안전교육장 맞은편에서 왼쪽으로 걷다 보면 발견할 수 있고 두 번째는 서울 사색의 길이다. 나무그늘 아래에서 시원하게 산책할 수 있으며 중간중간 자리 잡고 있는 조각 작품들을 보며 걸으면 자연스레 힐링이 되는 장소이다.', '2026-06-29 14:43:18.713');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (153, '2037020', '서촌마을', 1, 23, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '서촌은 경복궁 서쪽에 있는 마을을 일컫는 별칭이다. 서촌마을은 인근에 명동과는 다른 분위기로 오랫동안 골목을 지켜온 낡은 상점들과 한옥집 등을 구경할 수 있으며, 미로 같은 골목길을 걷다 보면 상큼한 파스텔컬러의 벽화와 앙증맞은 그림들이 눈길을 사로잡는다. 옛 느낌과 더불어 감각적이고 세련된 공간들도 함께 공존하고 있으며, 특유의 정겨움과 소박함을 유지하고 있다. 이런 분위기 덕에 영화, 드라마, 뮤직비디오 촬영지로 인기 있는 곳이다.', '2026-06-29 14:43:18.713');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (142, '127557', '삼천사(서울)', 1, 22, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '삼천사는 661년 원효대사에 의해 창건되었고, 『신증동국여지승람』과 『북한지』에 따르면 그 규모가 대단히 커서 3,000여 명이 수도할 정도로 번창했다고 한다. 사찰 이름도 이 숫자에서 유래한 것으로 추측된다고 하지만 최근의 고고학적 조사를 거치면서 ‘三千’이 아니라 ‘三川’이라고 새겨진 기와가 발견되어 삼천사를 두 가지 의미로 사용되었다는 것을 알 수 있다. 
임진왜란 당시 승병의 집결지로 사용되기도 하였다고 전해지는 등 병화(兵禍)를 피하지 못하였으나 뒷날 이 절의 암자가 있던 마애여래 길상터에 진영대사가 다시 복원하였다. 그리고 1970년대 성운스님이 주석하여 경내에 있는 천년고불 마애여래입상(보물 제657호)을 보물로 지정받으면서 순차적으로 대웅보전, 산령각, 천태각, 연수원, 요사채 등의 건물과 세존진신사리탑, 지장보살입상, 종형사리탑, 관음보살상, 5층 석탑, 중창비 등을 조성하여 현재의 모습을 갖추게 되었다.
1999년부터 2003년까지, 2005년부터 2007년까지 두 차례에 걸쳐 원래의 절터를 대상으로 지표조사 및 발굴조사를 전개해 그동안 알려지지 않은 많은 사실들을 찾아내는 성과를 얻었다.', '2026-06-29 14:42:03.899');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (143, '2992891', '사직단', 1, 23, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '종묘는 역대 국왕과 왕비의 신위를, 사직은 토지신과 곡신을 모신다는 점이 다르다. 경복궁을 중심으로 왼쪽에는 종묘, 오른쪽에는 사직이 위치하며 이는 유교 국가이자 농업 국가인 조선의 근본을 상징하는 의미가 크다. 따라서 조선시대에 종묘사직은 국가 혹은 왕실의 전통을 상징하는 대명사처럼 쓰였다. 사직단은 그 이름에서 드러나듯 제사를 지내는 제단을 의미하므로 사직단을 찾으면 다른 유적지처럼 중심에 건물이 있는 것이 아니라 텅 빈 제단이 놓여있는 점이 눈에 띈다. 왕릉에도 하나만 세우는 홍살문이 무려 8개나 있는 것만 봐도 이곳이 얼마나 신성한 장소였는지 짐작할 수 있다. 조선시대에는 임금과 왕족, 관련 직무를 맡은 사람만 출입할 수 있었을 정도로 엄격하게 출입이 통제되던 곳이기도 하다.', '2026-06-29 14:42:03.899');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (53, '2661736', '행주산성 역사공원', 31, 2, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '고양 인재개발원 주변 한강변 공원으로 2000년 고양 인재개발원 건립과 함께 조성되었다. 운동장처럼 탁 트인 이곳은 넓은 잔디밭에서 한강뷰를 감상하거나 잔디밭에 앉아 휴식을 취할 수도 있다. 2016년 전망대를 설치하고 한강 백사장에 근접할 수 있도록 한강변으로 길을 내어 정비한 곳으로 군대 초소를 정비한 자리에는 한강과 철새를 조망할 수 있는 친수공간(빨랫돌 머리) 군대 초소 전망대(행호정), 철책 포토존, 바람개비 언덕을 갖춘 역사 공원이다. 주차장에 무료로 차박이 가능해서 한강변의 야경을 보기 위해 찾는 사람들도 많다. 대덕 생태공원~행주산성 역사 공원~군 순찰로~장항 습지 18.2km 코스가 생태테마 관광 10선으로 지정되어 있다. 각종 축제 및 행사가 이루어져 시민들의 여가 공간으로 활용되며 공원 일부는 행주산성 누리길 코스로 행주산성을 한 바퀴 도는 길이다. 순환길이라 출발지와 도착지가 같고 초입은 계단이 많아 다소 힘들 수 있으나 10분 정도 후면 팔각정이 보이고 진강정, 충의정, 덕양정, 행주대첩비 등을 볼 수 있다. 1시간 반 정도면 여유 있게 둘러볼 수 있다. 또한 역사 공원 왼쪽으로 있는 방화대교는 일몰 명소로 해 질 녘이면 많은 사람들이 몰려오기도 한다. 아름다운 한강변에서 자연을 느끼고 역사를 배울 수 있는 곳이다.', '2026-06-29 14:38:30.61');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (202, '1624958', '남한산성 수어장대', 31, 5, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '수어장대는 지휘와 관측을 위한 군사적 목적에서 지은 누각으로 남한산성에 있던 5개의 장대(동장대, 서장대, 남장대, 북장대, 외동장대) 중 유일하게 남아있다. 청량산 정상(해발 482m)에 위치하고 있으며 성 안에 남아 있는 건물 중 가장 화려하고 웅장하다. 하층은 정면 5칸, 측면 3칸, 상층 정면 3칸 측면 2칸의 팔작지붕양식의 2층 누각이다. 지붕은 상하층 모두 겹처마루를 둘렀으며 사래 끝에는 토수를 달고 추녀마루에는 용두를 올렸으며 용마루에는 취두를 올렸다. 건물의 기둥은 높이 60cm의 팔각장주초석 위에 올려져 있고, 포는 주심포 양식의 이출목 익공식이다. 영조 27년(1751) 2층 누각으로 증축하고 외부에 ‘수어장대(守禦將臺)’ 내부에 ‘무망루(無忘樓)’라고 편액을 제작하여 설치하였다.

(출처 : 경기도남한산성세계유산센터)', '2026-06-29 14:43:18.726');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (201, '2515265', '강진 백운동별서정원', 38, 1, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '조선중기 처사 이담로(聃老, 1627~1701)가 들어와 계곡 옆 바위에 ‘백운동(白雲洞)’이라 새기고 조영(造營)한 원림으로, 자연과 인공이 적절히 배합된 배치와 짜임새 있는 구성을 이루며 우리 전통 원림의 원형이 그대로 보존된 별서이다. 백운동이란 ‘월출산에서 흘러 내린 물이 다시 안개가 되어 구름으로 올라가는 마을’이라는 뜻으로 약사암과 백운암이 있었던 곳으로 전해진다.
월출산 능선의 기암괴석의 바위들이 보이는 이곳에 전형적인 호남전통원림의 형태를 띄고 있으며, 마침 이곳길도 해남부터 시작하는 삼남길이 지나는 길이기도 하다.

현재의 건물은 다산선생이 1812년 이곳을 다녀간 뒤 아름다운 경치에 반해 제자 초의선사에게 <백운동도> 를 그리게 하고 백운동 원림의 12승경을 노래한 시문을 남겼는데 이를 근거로 호남의 유서깊은 전통별서의 모습을 재현하게 되었다. 이담로는 옥판봉에서 흘러내리는 물을 그냥 떠나보내기 아쉬워 아홉 굽이 유상곡수를 만들고 정자를 앉혔는데, 꽃과 나무가 어우러지는 계곡에 눈이 머물다가 봉우리로 시선을 옮기며 경치를 감상하는 것만으로도 최고의 정취를 느낄 수 있다. 백운동 계곡은 강진향토문화유산으로 지정되어 있으며 담양 소쇄원, 완도 보길도의 세연정 등과 함께 호남의 3대 정원으로 일컬으며 조선중기 선비들의 은거문화를 알려주는 중요한 문화유산이다.

[출처:강진군 문화관광 홈페이지]', '2026-06-29 14:43:18.726');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (204, '612305', '남한산성 전통음식마을', 31, 5, NULL, NULL, NULL, NULL, '매장마다 상이', '매장마다 상이', '남한산성 전통음식마을은 경기도 광주시 남한산성로 남한산성세계유산센터 인근에 조성된 전통 음식 거리이다. 삼국시대 이래로 우리 민족사의 주요 군사요충지인 남한산성은 조선 선조에서 순조에 이르기까지 국방의 보루로 제16대 인조 때 완공되어 300여 년의 역사를 가진 우리의 귀중한 문화유산이다. 유네스코 세계문화유산에 속하는 만큼 볼 것이 풍부하며 남한산성 주변에는 한국의 전통적인 분위기를 느낄 수 있는 전통 가옥과 문화를 경험할 수 있는 곳이 많이 있다.  전통 한옥으로 지은 70여 개의 음식이 한곳에 모여 있는 이곳은 쌀밥, 도토리묵, 토종닭, 닭볶음탕 등의 전통 음식을 맛볼 수 있다. 한옥의 아름다운 경치를 감상하며 한정식을 즐길 수 있으며, 사계절 아름다운 자연의 풍경을 감상하기에 좋아 여행객들의 방문이 끊이지 않는 곳이다.', '2026-06-29 14:43:18.727');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (171, '2650046', '익선동 한옥거리', 1, 23, NULL, NULL, NULL, NULL, '점포 별로 상이함', '점포 별로 상이함', '익선동은 골목과 한옥이 어우러져 아름다운 매력을 풍기는 곳으로 남녀노소 많은 관광객들이 찾고 있으며, 젊은 세대와 어르신 간 세대를 이어주는 장소이기도 하다. 익선동은 2018년 한옥보전지구 지정 후 2019년부터 레트로, 뉴트로 열풍과 맞물려 첨단 도시 서울의 기묘한 시간 여행지로 급부상했다. 아담하고 야트막한 한옥 사이로 핏줄처럼 가느다랗고 촘촘히 골목이 이어진 익선동 한옥거리는 하나의 여행 상품처럼 구역 전체가 주목받고 있다. 한옥을 개조된 카페, 음식점, 각종 샵들이 자리 잡고 있어서 볼거리도 많은 서울 대표 데이트 코스이다.', '2026-06-29 14:43:18.718');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (175, '127030', '장경사(경기)', 31, 5, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '장경사는 유네스코 세계유산에 등재된 남한산성 내에 자리하고 있는 사찰이다. 남한산성이 만들어지던 때 같이 세워졌다. 임진왜란 때 크게 활약한 승군[僧軍 ; 전쟁과 같은 나라의 위기 때 만들어지는 승려로 구성된 군대]은 전쟁 후에도 국가의 필요에 따라 여러 일을 맡았다. 남한산성 역시 당시 북쪽에서 새롭게 힘을 키우던 후금[後金]을 대비하여 벽암 각성스님을 책임자로 하여 승군을 동원해 서울의 남쪽에 새로 쌓은 대규모 산성이다. 이때 전국에서 올라온 승군이 머무를 수 있도록 하기 위해 이전부터 있던 망월사와 옥정사 외에 산성 안에 7개의 사찰을 함께 세우게 되는데, 장경사도 이 중 하나이다. 승군은 공사가 끝난 후에도 산성을 관리하고 지키는 역할을 맡게 되어 9개 사찰에 머물면서 승려이자 군인으로 생활하였다. 1907년 일제에 의해 대한제국의 군대가 해산될 때 남한산성의 군사시설과 함께 승군의 주둔지인 사찰도 대부분 파괴되었지만, 장경사는 이를 피한 유일한 사찰이었다. 1975년 화재로 큰 피해를 입었지만 복구되어 지금에 이르고 있다. 장경사는 남한산성 동문인 좌익문에서 북쪽방향 망월봉 중간쯤 되는 곳에 위치하여, 산성의 제1암문을 통해서 사람들이 많이 드나들었다. 이 사찰에는 석가모니불을 모신 대웅전을 중심으로 승려가 머무르며 생활하는 공간인 요사와 문루인 진남루, 작은 불전인 칠성각이 남아 있다. 승군이 주둔하였던 곳이기에 예불을 드리는 불전보다 요사의 규모가 큰 것이 특징이다.

(출처 : 국가유산청 홈페이지)', '2026-06-29 14:43:18.719');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (172, '132219', '인사동 문화의 거리', 1, 23, '서울특별시 종로구 인사동', 37.5739535014, 126.9850146618, 'http://tong.visitkorea.or.kr/cms/resource/86/3571886_image2_1.jpg', NULL, NULL, '인사동 문화의 거리는 전통과 현대가 조화를 이루는 서울의 대표적인 문화 명소이다. 오래된 골목길을 따라 전통 한옥과 갤러리, 다양한 공예품 상점, 고미술 상점 등이 어우러져 한국 고유의 멋을 느낄 수 있다. 특히 국내 장인들의 손길이 담딘 공예품과 고미술 상점은 구경하는 재미가 있다. 거리를 거닐며 옛 물건과 기념품을 구경하고, 한국적인 정취가 물씬 풍기는 분위기 속에서 즐거움을 만끽할 수 있다.', '2026-06-29 14:43:18.718');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (174, '130227', '일민미술관', 1, 23, '서울특별시 종로구 세종대로 152 (세종로)', 37.5699121725, 126.9776737786, 'http://tong.visitkorea.or.kr/cms/resource/25/3412025_image2_1.JPG', NULL, NULL, '일민미술관은 대중적이고 동시대적인 현대미술품을 전시하는 미술관이다. 일민문화재단이 운영하는 미술관으로 평생을 언론과 문화진흥에 바친 일민 김상만 선생(전 동아일보 명예회장)의 유지를 기리기 위하여 설립하였다. 동아일보 옛 사옥에 자리 잡고 일민문화관으로 출발하여 1996년 일민미술관으로 등록하였으며, 전면적인 리노베이션을 거쳐 2002년 대형전시실과 일민컬렉션을 갖춘 현재의 모습으로 재개관하였다. 전시 공간은 1, 2, 3층에 3개의 전시실을 갖추고 있다. 부대시설로는 미술관 1층에 카페와 각종 아트상품과 출판 인쇄물을 구매할 수 있는 기둥 서점이 있다. 고려시대와 조선시대의 도자기와 서화, 근대기의 회화 등 일민컬렉션과 동아일보 위탁 소장품, 현대미술품을 소장하고 있다. 일민컬렉션은 일민선생이 생전에 수집한 도자기와 서화 등으로 단아하고 소박한 아름다움이 돋보이며, 동아일보 소장품은 동아일보와 신동아, 여성동아의 삽화 등으로 한 시대를 반영하는 중요한 자료이다.', '2026-06-29 14:43:18.719');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (178, '1625025', '지수당', 1, 23, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '지수당은 1672년(현종 13)에 이세화(李世華)가 지은 정자(亭子)이다. 지수당이라는 이름은 ‘군자는 백성들을 잘 포용하여 잘 살도록 길러 나간다’는 뜻을 담고 있다. 건립 당시에는 정자를 중심으로 앞뒤에 3개의 연못이 있었다고 하나 현재는 2개만 남아 있다. 정자의 동쪽에는 부윤 이세화의 공덕비가 세워져 있고 제3 연못지로 추정되는 지역은 현재 논으로 바뀌어 있다. 앞면 3칸, 옆면 3칸 규모의 건물이지만, 옆면의 1칸이 반 칸 크기여서 전체모양은 앞면이 옆면보다 넓은 장방형 형태를 띠고 있다. 건물은 4면이 모두 개방되어 밖을 볼 수 있다. 그리고 지붕은 옆면에서 볼 때 八자 모양인 팔작지붕을 하고 있다.', '2026-06-29 14:43:18.72');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (181, '1605009', '창경궁 홍화문', 1, 23, NULL, NULL, NULL, NULL, '09:00~21:00 (입장마감 20:00)', '매주 월요일<br>※ 단, 정기휴일이 공휴일 및 대체공휴일과 겹칠 경우에는 개방하며, 그 다음의 첫 번째 비공휴일이 정기휴일임', '홍화문(弘化門)은 창경궁의 정문으로 ‘홍화’는 “조화를 넓힌다”, 즉 “덕을 행하여 백성을 감화시키고 널리 떨친다”는 뜻이다. 홍화문은 창경궁 창건 당시에 처음 건립되었다가 임진왜란 때 소실되어 1616년(광해군 8)에 재건되었다. 같은 동궐인 창덕궁의 정문(돈화문)은 앞면이 5칸인데 비해 홍화문은 3칸의 작은 규모로 지었다.
홍화문은 국왕이 직접 백성들을 만났던 곳이기도 하다. 영조는 1750년(영조 26)에 균역법(均役法)을 시행하기 전 홍화문에 나가 양반과 평민들을 만나 세금제도의 개편에 대한 의견을 들었다. 또 정조는 1795년(정조 19) 어머니 혜경궁 홍씨(헌경황후)의 회갑을 기념하여 홍화문 밖에서 가난한 백성들에게 쌀을 나누어 주었다고 한다. 홍화문은 1963년 보물로 지정되었다.
규모는 앞면 3칸, 옆면 2칸의 2층 건물로 동쪽을 향하고 있는 점이 특징이며, 지붕은 앞쪽에서 볼 때 사다리꼴을 한 우진각지붕이다. 지붕 처마를 받치기 위해 장식하여 만든 공포는 기둥 위뿐만 아니라 기둥 사이에도 있는 다포 양식으로 꾸몄다. 아래층은 기둥 사이마다 2짝씩 문짝을 달아 사람이 드나들게 하였으며 위층은 마루를 깔고 앞뒤 벽면에 조그만 널문들을 달아 여닫을 수 있게 만들었다. 지붕 꼭대기 양끝의 조각과 부드럽게 굽어 내린 내림마루 부분의 조각상이 건물의 위엄을 한층 더 돋구고 있다.', '2026-06-29 14:43:18.721');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (182, '127642', '창덕궁과 후원 [유네스코 세계유산]', 1, 23, NULL, NULL, NULL, NULL, '[2월~5월]- 09:00~18:00 (입장 마감 17:00)[6월~8월]- 09:00~18:30 (입장 마감 17:30)[9월~10월]- 09:00~18:00 (입장 마감 17:00)[11월~1월]- 09:00~17:30 (입장 마감 16:30)', '매주 월요일 (단, 월요일이 공휴일인 경우 개방하며, 그 다음 첫 번째 평일에 휴관)', '창덕궁(昌德宮)은 1405년(태종 5) 법궁인 경복궁의 이궁(離宮)으로 창건되었다. 1592년(선조 25) 임진왜란으로 소실되었다가 1610년(광해군 2) 궁궐 중 처음으로 다시 지어졌다. 이후 역대 왕들이 1867년 경복궁이 중건될 때까지 약 270여 년 동안 창덕궁을 더 많이 사용하여 실질적인 법궁의 역할을 하였다. 특히 대조전 부속 건물인 흥복헌은 1910년 경술국치가 결정되었던 비운의 장소이기도 하며, 낙선재 권역은 광복 이후 대한제국의 마지막 황실 가족인 순정황후(순종의 두 번째 황후), 의민황태자비(이방자 여사), 덕혜옹주(고종의 딸)가 생활하다가 세상을 떠난 곳이기도 하다.
창덕궁은 창경궁(昌慶宮)과 경계 없이 ‘동궐(東闕)’이라는 별칭으로 불렀다. 창덕궁은 다른 궁궐에 비해 인위적인 구조를 따르지 않고 주변 지형과 조화를 이루도록 자연스럽게 건축하여 가장 한국적인 궁궐이라는 평가를 받아 1997년 유네스코 세계유산에 등재되었다.

창덕궁 후원은 1406년(태종 6) 창덕궁 북쪽에 처음 조성된 후원은 세조 대에 확장하였고, 성종 대에 건립된 창경궁까지 그 영역이 확장되었다. 후원 권역은 임진왜란 때 대부분의 소실되었고, 1610년(광해군 2)에 다시 조성되었다. 이후 인조, 숙종, 정조, 순조 등 여러 왕들이 개수하고 증축하여 현재의 모습이 되었다.
창덕궁 후원은 자연 지형을 그대로 살리면서 골짜기마다 아름다운 정자를 만들었다. 4개의 골짜기에는 각각 부용지(芙蓉池), 애련지(愛蓮池), 관람지(觀纜池), 옥류천(玉流川) 영역이 펼쳐진다. 왕가의 휴식과 산책을 위한 곳이지만, 여러 가지 다른 용도로도 사용하였다. 자연 풍광을 느끼면서 시를 짓고 학문을 논하는 것을 포함하여 군사훈련 등의 활쏘기 행사, 연못에서 낚시를 하거나 배를 띄우기도 하고 꽃구경을 하였으며, 화약을 이용한 불꽃놀이도 하였다. 또 대비를 모시는 잔치, 종친이나 신하를 위로하는 잔치 등 임금이 주관하는 잔치도 자주 열렸다. 또한 왕은 이곳에 곡식을 심어 농사를 직접 체험하고, 왕비는 양잠을 직접 시행하는 친잠례(親蠶禮)를 열었다.', '2026-06-29 14:43:18.721');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (185, '690984', '청와대 사랑채', 1, 23, '서울특별시 종로구 효자로13길 45', 37.5823976600844, 126.972566016596, 'https://tong.visitkorea.or.kr/cms/resource/26/3310126_image2_1.jpg', NULL, NULL, '청와대 사랑채는 ‘누구에게나 열린 안식처’로 만남과 소통의 문화 공간으로 여행도서관 콘셉트의 공간이 곳곳에 구성되어 있으며 쉼이 있는 여행 전시로 특별함을 더한 곳이다. 청와대  주변에서 한국 전역까지 확장되는 여행을 통해 나만의 꿈을 펼쳐보는 시간을 가져볼 수 있다. 청와대사랑채는 2024년 6월 재개관 하였으며 1, 2층의 전시실과 함께 편의시설로는 수유실, 물품보관소, 장애인화장실, 기념품점 및 카페가 있다.', '2026-06-29 14:43:18.722');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (186, '2762885', '청운공원', 1, 23, '서울특별시 종로구 창의문로 119 (청운동)', 37.592096942441, 126.96706863952, 'https://tong.visitkorea.or.kr/cms/resource/36/3506736_image2_1.jpg', '상시 개방', '연중무휴', '2006년 청운동 7번지 일대의 청운아파트를 철거한 자리에 조성된 공원이며 다시 ‘윤동주 시인의 언덕’의 테마공원 형태로 2009년 7월 조성하여 현재의 모습을 갖추고 있다. 자하문 옆 윤동주 시인의 언덕부터 청운어린이집 부근까지 포괄해서 일컫는다. 인왕산 연결 산책로와 진입광장, 운동 및 휴게공간, 바닥분수 등 다양한 주민편의 시설을 갖추고 있으며 38종 22,861주의 나무가 심겨 있고, 12종 34,480본의 꽃들이 피어있는 아름다운 공원이다. 청운이라는 이름은 청풍계곡과 백운동의 이름을 딴 것으로 2007년 8월 공원 명칭을 공모하여 선정한 것이다. 청운공원은 한옥으로 지어진 청운문학도서관과 일제 강점기 저항 시인인 윤동주 시인의 언덕으로 유명하다. 서시의 시비를 비롯해 가수 이승환과 그의 팬들이 기증한 소나무 10그루, 시인의 주옥같은 시를 새겨 넣어 눈으로 감상할 수 있게 한 돌계단 등으로 모습을 갖추고 있고 인왕산과 부암동, 종로 사직동 등 서울 시내를 조망하며 아름다운 야경을 즐길 수 있다.', '2026-06-29 14:43:18.722');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (187, '126944', '침괘정', 31, 5, '경기도 광주시 남한산성면 산성리', 37.4786, 127.1835, 'https://tong.visitkorea.or.kr/cms/resource/35/3524635_image2_1.jpg', '상시 개방', '연중무휴', '침괘정은 무기제작소라 알려져 왔으나 온돌과 마루방, 회랑처럼 된 툇마루 등 건물 구조로 보아 집무실로 쓰인 것으로 보인다. 현재의 건물은 영조 27년(1751)에 광주유수 이기진이 고쳐 짓고 침괘정이라 명명하였다. 枕戈(침과)란 戈, 즉 ‘창을 베개 삼는다‘라는 뜻이다. 현재는 침괘정으로 통용되고 있으나 정확한 표기는 침과정이 옳다. 왜냐하면 戈는 ‘괘’로 읽히지 않기 때문이다. 그러나 현지의 호칭대로 적는 지명관례상 ‘침괘정’이라 표기하였다. 화약을 찧었던 돌절구들을 쉽게 찾아볼 수 있는 것으로 보아 무기제작소의 사무를 관장하던 곳으로 추정된다.

(출처 : 경기도남한산성세계유산센터)', '2026-06-29 14:43:18.722');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (188, '129534', '탑골공원', 1, 23, '서울특별시 종로구 종로 99 (종로2가)', 37.57050075478524, 126.9886081339566, 'https://tong.visitkorea.or.kr/cms/resource/43/4056543_image2_1.jpg', '- 하절기(3월~10월) 09:00~18:00- 동절기(11월~2월) 09:00~17:00', '연중무휴', '조선시대 원각사터에 세운 서울 최초의 근대식 공원이다. 조선 세조 13년에 원각사로 건립하였던 것을 고종 34년인 1897년 도지부 고문인 영국인 브라운에 의해 공원으로 조성되어 1920년에 공원으로 개원하였다. 
1919년 3·1 운동 당시 처음으로 독립선언문을 낭독하고 독립만세를 외친 3·1 운동의 출발지로서, 우리 민족의 독립 정신이 살아 숨 쉬는 유서 깊은 곳이다. 1992년 5월 28일 공원 명칭을 파고다 공원에서 탑골공원으로 개정하여 오늘에 이르고 있다. 
공원 내에는 독립운동 봉화에 불을 댕겼던 팔각정을 중심으로 국보 원각사지 10층 석탑, 보물 원각사비 등의 문화재와 3·1 운동 기념탑, 3·1 운동 벽화, 의암 손병희 선생의 동상, 한용운 선생 기념비 등이 있다.', '2026-06-29 14:43:18.722');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (189, '1590323', '통인시장', 1, 23, '서울특별시 종로구 자하문로15길 18 (통인동)', 37.5807670044059, 126.969947621917, 'https://tong.visitkorea.or.kr/cms/resource/39/3300739_image2_1.jpg', NULL, NULL, '통인시장은 1941년 6월 일제강점기 효자동 인근 일본인들을 위해 설립된 공설시장이 모태이다. 6·25 전쟁 이후 서촌 지역의 급격한 인구 증가로 인한 소비공간의 필요에 따라 공설시장 주변으로 노점과 상점이 형성되면서 점차 시장의 형태를 갖추어 나가게 되었다. 2005년 재래시장 육성을 위한 특별법(현행 전통시장 및 상점가 육성을 위한 특별법)에 따라 인정시장(認定市場)으로 등록된 뒤 현대화 시설을 갖추었고 2010년 서울시와 종로구가 주관하는 ‘서울형 문화시장’으로 선정되었다. 2011년에는 시장상인회가 마을기업으로 (주)통인커뮤니티를 법인 등록하여 통합콜센터와 배송센터를 설치하고 온라인 쇼핑몰도 개설하였다. 점포 수는 70여 개로 식당, 반찬가게 등 요식 관련 업소가 가장 많고, 채소, 과일, 생선, 정육 등 1차 생산품을 판매하는 업소가 그다음이며 그밖에 내의 등 공산품, 옷 수선 업소 등이 있다. 2012년 1월부터 도시락카페 통(通)을 운영하여 큰 호응을 얻고 있다.', '2026-06-29 14:43:18.723');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (191, '1939691', '한양도성박물관', 1, 23, '서울특별시 종로구 율곡로 283 (종로6가)', 37.57285717668249, 127.008512884216, 'https://tong.visitkorea.or.kr/cms/resource/53/3505653_image2_1.jpg', NULL, NULL, '서울 한양도성은 조선왕조 도읍지인 한성부의 경계를 표시하고 수도의 권위를 드러내며 외부의 침입을 방어하기 위해 1396년 축조된 도시 규모의 성곽유산이다. 평균 높이 약 5~8m, 전체 길이 약 18.6㎞에 이르는 한양도성은 한국의 고유 축성기법과 집단 장인 기술을 바탕으로 구축된 역사 문화 도시 서울의 랜드마크이다. 또한, 현존하는 전 세계의 도성 중 가장 규모가 크고 오랫동안 도성 기능을 수행한 문화유산으로 천만 서울 시민을 넘어서 서울을 찾는 내·외국인들이 즐겨 찾는 대표 명소이다. 흥인지문공원에 위치한 한양도성박물관은 조선시대부터 현재에 이르기까지 한양도성의 역사와 문화를 담은 박물관으로 상설전시실, 기획전시실, 한양도성 자료실과 학습실을 갖춘 문화공간이다. 한양도성박물관에서 600년 한양도성의 역사와 문화유산으로서의 미래가치를 확인할 수 있다.', '2026-06-29 14:43:18.723');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (192, '2745995', '행궁동 벽화마을', 31, 13, '경기도 수원시 팔달구 화서문로72번길 9-7 (북수동)', 37.2857125098, 127.0165476856, 'http://tong.visitkorea.or.kr/cms/resource/67/3407967_image2_1.png', '상시 개방', '연중무휴', '수원 행궁동은 수원 화성 일대의 장안동, 신풍동, 북수동, 남창동, 매향동, 남수동, 지수동 등 12개 동네를 일컫는 이름이다. 220여 년 전 화성이 축성될 당시부터 불과 수십 년 전까지 수원에서 가장 번화한 곳이었지만, 수원 화성이 유네스코 세계유산으로 지정되면서 엄격한 개발 규제로 시간이 멈춘 듯한 곳이다. 그런 행궁동에 주민과 시민 단체, 예술가들이 뜻을 모아 벽화를 그리면서 벽화마을을 완성, 지금은 수원 화성만큼이나 많은 사람이 찾는 관광 명소로 떠올라 골목에 생기가 도는 곳이다. 
행궁동 골목은 벽화마을과 공방거리, 수원 통닭거리, 지동시장 등 특색에 따라 다양하게 이어져 있고 벽화마을은 행복하 길, 사랑하다 길, 눈으로 가는 길 처음 아침 길, 로맨스 길, 뒤로 가는 길 등 테마별로 여섯 갈래의 골목길로 나뉘어 있다. 벽화 앞엔 포토존을 마련했고 벽화뿐 아니라 벽면과 지붕, 담장에도 다양한 조형물과 그림으로 가득하다. 예쁜 공방과 카페들이  많고 갤러리 카페들의 경우 수익금을 창작자들을 위해 사용하고 있다. 수원 화성을 중심으로 데이트 코스로 방문하기 좋은 곳이다.

◎ 한류의 매력을 만나는 여행 정보 - 드라마 <선재 업고 튀어>
행궁동 벽화마을은 솔이와 선재의 등굣길이다. 솔이의 박력 넘치는 벽치기에 선재가 당황하던 장면도 바로 이곳에서 촬영됐다. 벽화가 그려진 낮은 돌담길을 걷다 보면 사이좋게 등교하던 솔선 커플의 모습이 눈앞에 그려지는 듯하다.', '2026-06-29 14:43:18.723');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (193, '129437', '화성행궁', 31, 13, '경기도 수원시 팔달구 정조로 825 (남창동)', 37.2818163237, 127.0163732353, 'https://tong.visitkorea.or.kr/cms/resource/62/4078262_image2_1.jpg', '- 하절기(3월~10월) 09:00~18:00- 동절기(11월~2월) 09:00~17:00', '연중무휴', '행궁은 정조가 현륭원에 행차할 때 임시 거처로 사용하던 곳으로 그 어느 행궁보다 크고 웅장하였으며 활용도도 높아 경복궁의 ‘부궁’이라는 말까지 생겨난 곳이다. 정조 18~20년에 화성을 축성하고 팔달산 동쪽에 행궁을 건립했는데 평상시에는 유수부(지금의 시청) 관청으로 사용되던 곳이다. 화성은 창룡문(동), 화서문(서), 팔달문(남), 장안문(북) 4개의 문루로 이어져 있으며, 뛰어난 건축술로 인해 세계유산으로 선정되었을 뿐 아니라 우리나라 최초의 신도시 개발 사례로도 평가받고 있다. 조선 22대 정조는 아버지 사도 세자가 뒤주 속에서 비극적인 삶을 마감하자 그 무덤을 당시 최고의 명당이라 평가받던 수원(현재의 화성시)으로 이장하였고, 능 주위에 살던 주민들을 팔달산 아래 현재의 위치로 옮기면서 도시와 성곽을 축성하였다. 화성의 국궁 체험과 팔달산 정상의 효원의 종 타종, 행궁의 여러 가지 전통문화체험은 우리 문화재를 입체적으로 접근할 수 있도록 도와준다. 그 외에도 대장금의상 입어보기, 소원 성취 나무와 스탬프 찍기 등 다양한 체험을 할 수 있다.', '2026-06-29 14:43:18.724');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (195, '1604450', '황학정', 1, 23, '서울특별시 종로구 사직로9길 15-32 (사직동)', 37.5771000006, 126.9651024987, 'http://tong.visitkorea.or.kr/cms/resource/31/3350631_image2_1.jpg', '10:00~17:00', '매주 월요일 / 1월 1일 / 설·추석 당일', '황학정(黃鶴亭)은 1899년(광무 3) 고종 황제의 명으로 경희궁 회상전 북쪽에 궁술을 연습하도록 지은 사정(射亭, 활터에 있는 정자)이다. 1894년 갑오개혁 이후 군대 제식무기에서 활이 제외되면서 전국의 사정이 거의 사라졌다. 이를 안타깝게 여긴 고종이 ‘국민들의 심신단련을 위하여 궁술을 장려하라’는 어명을 내렸고, 궁궐 내에 황학정을 지어 일반 백성들에게 개방하였다. 고종은 이곳을 자주 방문하여 직접 활쏘기를 즐겼다고 전해진다.
1922년 일제가 경희궁을 헐면서 황학정을 옛 등과정 터인 사직동 지금의 자리로 옮겼다. 등과정은 조선시대 인왕산 아래 웃대에 있던 다섯 곳 사정 가운데 하나였다.
건물은 앞면 4칸, 옆면 2칸 규모이며, 지붕 옆면이 여덟 팔(八)자 모양인 팔작지붕집이다. 
황학정은 활터 건물의 본보기로 현재까지도 활쏘기 행사가 열리며, 국궁문화를 이어가고 있는 역사적인 장소이다.', '2026-06-29 14:43:18.724');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (103, '1254680', '갑곶돈대', 2, 1, '인천광역시 강화군 강화읍 해안동로1366번길 18', 37.7335377029, 126.5171140395, 'http://tong.visitkorea.or.kr/cms/resource/71/3364171_image2_1.jpg', '09:00~18:00 (입장마감 17:00)', '연중무휴 (전쟁박물관은 매주 월요일, 1월 1일, 설날 및 추석 당일 휴무)', '돈대는 해안가나 접경지역에 돌이나 흙으로 쌓은 소규모 관측·방어시설로, 조선시대 강화도 해안에 돌로 쌓은 돈대 53개가 설치됐다. 갑곶돈대는 1679년 5월에 완성된 48 돈대 가운데 하나이다. 강화 돈대는 황해도·강원도·함경도 승군 8,900명과 어영청 소속 어영군 4,262명이 80일 정도 걸려서 쌓았다. 갑곶돈대는 망해돈대·제승돈대·염주돈대와 함께 제물진의 관할 하에 있었으며, 포좌가 있는 본래의 갑곶돈대는 옛 강화대교 입구 북쪽 언덕에 있었다. 지금 사적으로 지정된 갑곶돈대는 제물진과 강화 외성의 일부이다. 갑곶돈대에서는 강화전쟁박물관, 강화 갑곶리 탱자나무, 홍이포, 이섭정, 비석군 등을 관람할 수 있다.
 
(출처: 강화군시설관리공단 홈페이지)', '2026-06-29 14:42:03.887');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (197, '126514', '흥인지문', 1, 23, '서울특별시 종로구 종로 288 (종로6가)', 37.5712209291, 127.0097180432, 'http://tong.visitkorea.or.kr/cms/resource/27/2536327_image2_1.jpg', '상시 개방', '연중무휴', '흥인지문은 서울성곽 8개의 문 가운데 동쪽에 있는 문으로 서울성곽은 서울 한양도성의 옛 이름이며 옛날 중요한 국가시설이 있는 한성부를 보호하기 위해 만들었다. 동쪽에 있는 큰 문이라 하여 동대문이라고도 부른다. 조선 태조 5년(1396) 도성 축조 때 건립했으며 단종 원년(1453)에 고쳐 지었고, 지금 있는 문은 고종 6년(1869)에 새로 지은 것이다. 앞면 5칸, 옆면 2칸 규모의 2층 건물이고 지붕은 앞면에서 볼 때 사다리꼴모양을 한 우진각 지붕이다. 지붕 처마를 받치기 위해 장식하여 만든 공포가 기둥 위뿐만 아니라 기둥 사이에도 있는 다포 양식인데, 그 형태가 가늘고 약하며 장식한 부분이 많아 조선 후기의 특징을 잘 나타내주고 있다. 또한 바깥쪽으로는 성문을 보호하고 튼튼히 지키기 위하여 반원 모양의 옹성을 쌓았다. 이는 적을 공격하기에 합리적으로 계획된 시설이라고 할 수 있다. 흥인지문은 도성의 8개 성문중에서 유일하게 옹성을 갖추고 있으며, 조선 후기 건축 양식을 잘 나타내고 있다.
수도권 지하철 1호선, 4호선 동대문역 9번 출구 바로 옆에 있다. 도보로 5분 거리에 성곽공원과 한양도성박물관이 있고 DDP와 동대문시장 등의 서울 명소가 있어서 같이 돌아보면 좋다.', '2026-06-29 14:43:18.725');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (183, '2765510', '청계광장', 1, 24, '서울특별시 중구 태평로1가', 37.569153924, 126.9775154812, 'http://tong.visitkorea.or.kr/cms/resource/55/3385055_image2_1.JPG', '상시 개방', '연중무휴', '서울 중구 청계천이 시작되는 세종로에 조성된 자연 친화적인 생태환경을 갖춘 광장이다. 다양한 볼거리를 제공하고 접근성이 좋아 시민들과 외국인 관광객들이 즐겨 찾는 서울의 대표적인 관광 명소이다. 삼색 조명의 캔들 분수와 2단 폭포에서 4m 아래로 떨어지는지는 물줄기, 폭포 양옆에는 전국에서 돌을 가져온 8 도석으로 제작된 ‘팔석담’을 깔아 놓았다. 밤에는 광장의 조명들과 물이 어우러지는 환상적인 모습을 연출하여 밤에도 찾는 사람들이 많다. 청계천 전 구간을 1/100로 축소한 미니어처도 볼거리로 제공하고 있으며, 연중 다채로운 시민 문화행사 및 축제가 진행되는 곳이다.', '2026-06-29 14:43:18.721');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (11, '3056152', '열린송현 녹지광장', 1, 23, '서울특별시 종로구 송현동', 37.5766, 126.9814, 'https://tong.visitkorea.or.kr/cms/resource/49/3056149_image2_1.jpg', '상시 개방', '연중무휴', '열린송현 녹지광장은 종로구 송현동 부지에 있는 공간으로, 경복궁과 종로 사이에 위치하고 있는 광장이다. 송현동 부지는 일제강점기 식산은행 사택, 해방 후 미군 숙소, 미대사관 숙소 등으로 활용되어 오다가 1997년 우리 정부에 반환되었다. 하지만 이후 별다른 쓰임 없이 폐허로 방치되어 높은 벽에 둘러싸여 있었다. 2022년 7월 한국주택공사로 소유권이 넘어오고 서울시로 다시 소유권이 넘어가면서 쉼과 문화가 있는 열린송현 녹지광장으로 단장하고 시민에게 개방되었다. 높이 4m 담장에 둘러싸여 오랜 기간 닫혀있던 공간은 돌담을 낮추고 야생화로 어우러진 녹지로 조성하였다. 이로 인해 율곡로, 감고당길에서 드넓은 녹지광장을 한눈에 담을 수 있다. 돌담장 안으로 들어가면 광장 중앙에 서울광장 잔디보다 넓은 중앙잔디광장이 펼쳐진다. 광장 주변으로는 코스모스, 백일홍과 같은 야생화 군락지가 조성되어 있다. 경복궁과 북촌은 송현동 부지가 열리면서 광장 내부로 난 지름길로 연결된다. 광장을 가로지르며 걷다 보면 청와대, 광화문광장, 인사동 그리고 북촌 골목길로 자연스레 이어진다.', '2026-06-29 14:34:12.478');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (16, '2951595', '안흥찐빵모락모락마을', 32, 18, '강원특별자치도 횡성군 주천강로 1868 모락모락찐빵관', 37.40997683930906, 128.1550493559081, 'https://tong.visitkorea.or.kr/cms/resource/99/4068599_image2_1.jpg', '09:00~18:00', '매주 월요일 / 공휴일※ 어린이날과 안흥찐빵축제 기간 제외', '2022년 개관한 안흥찐빵모락모락마을은 횡성의 대표 특산품인 안흥찐빵을 주제로 볼거리와 즐길거리를 가득 담은 복합문화공간이다. 안흥찐빵의 역사와 유래를 비롯하여 찐빵 만들기, 디저트 만들기 등 다양한 체험프로그램 운영과 VR체험 등 흥밋거리가 가득해 남녀노소 누구나 즐거운 추억을 만들어 갈 수 있는 곳이다. 안흥찐빵 만들기 등 체험을 진행하는 ‘모락모락 찐빵관’, 안흥찐빵을 홍보하고 매표소, 홍보관, 미디어아트 및 오감만족 VR체험 공간이 있는 ‘모락모락 라운지’, 나만의 컵 만들기와 팥찜질팩 만들기 등 체험을 즐길 수 있는 ‘모락모락 공방’ 그리고 건강놀이터, 모락모락 광장, 연못 등으로 구성되었다.', '2026-06-29 14:34:12.48');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (43, '2671791', '말티재 전망대(말티고개)', 33, 3, '충청북도 보은군 장안면 장재리', 36.4991475269, 127.7893194701, 'http://tong.visitkorea.or.kr/cms/resource/57/3449957_image2_1.jpg', '[11월~2월]<br>
- 09:00~18:00<br>
- 입장 마감 17:30<br>
[5월~8월]<br>
- 09:00~20:00<br>
- 입장 마감 19:30<br>
[3월~4월/9월~10월]<br> 
- 09:00~19:00 <br>
- 입장 마감 18:30<br>
※ 우천 및 강풍 등 기상 악화 시 전망대 출입 제한<br>
※ 비가 그친 후 전망대 노면이 다 마를 때까지 전망대 출입 제한', '연중무휴', '2020년 개장한 말티재 전망대는 전망대 및 조형물로 열두굽이의 말티고개를 한눈에 볼 수 있는 곳이다. 2층 규모로, 폭 16m, 높이 20m이다. 전망대에서 바라보는 말티고개는 숲과 도로가 어우러진 독특한 풍광이 한눈에 들어온다. 자전거, 바이크 동호인들 사이에서 12굽이 와인딩 코스로 유명한 곳으로, 고려 태조 왕건과 조선 세조가 속리산 행차 때 얇은 돌을 깔아 길을 냈다고 전해진다. 길이 가파르기 때문에 초보 운전자는 각별히 주의를 기울여야 한다.', '2026-06-29 14:34:12.49');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (52, '3102071', '은평한옥마을 인휴당', 1, 22, '서울특별시 은평구 연서로50길 7-10 (진관동)', 37.6413948373, 126.9392252587, NULL, NULL, NULL, '서울 북한산 아래 은평한옥마을 단지 내에 위치한 인휴당은 신축 한독 독채 스테이로, 최대 30명까지 숙박이 가능하여 기업행사, 대가족 행사, 칠순잔치, 돌잔치, 해외바이어 초청 파티 등의 장소로 많이 이용한다. 인휴당은 지하 1층, 1층, 2층으로 구성되어 있는데, 1층에는 방, 누마루, 거실, 주방이 있고, 2층에는 방 2개와 거실, 화장실이 있다. 2층은 높이가 높아 탁 트인 뷰를 자랑한다. 지하에는 주방, 미니 노래방, 화장실이 있어 크고 작은 행사를 진행할 수 있다.', '2026-06-29 14:38:30.61');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (78, '128138', '원당종마목장 (렛츠런팜 원당)', 31, 2, '경기도 고양시 덕양구 서삼릉길 233-112', 37.6615023377, 126.8683006076, NULL, '09:00~16:00 (입장 마감 15:30)', '매주 월요일~화요일 / 공휴일 / 설·추석 연휴/ 한국마사회 휴일', '서울 근교 고양시 서삼릉에 인접한 원당 종마목장은 한국마사회에서 설치하여 운영하는 곳이다. 1988년 서울 올림픽 게임이 있을 때는 크로스컨트리 종목의 경기장으로도 활용되었다. 목장의 목가적 풍경에 반한 시민들의 요청으로 1997년부터 일반인에게도 일부 시설이 개방되었고 그 이후 드라마 촬영지로 더욱 알려지게 되었다. 위험 시설이 많아 개방 지역을 제한하고 있으며 내부에는 특별한 볼거리보다는 말이 방목되어 있는 목가적인 풍경을 산책하면서 즐길 수 있다. 이곳은 승마를 배우거나 말먹이주기 체험 등을 진행하는 곳이 아닌 산책로와 그늘막, 잔디광장, 화장실 등을 개방하기 때문에 조용히 산책을 즐길 수 있는 곳이다. 주변에 높은 건물이 없어 탁 트인 초원과 높은 하늘을 마음껏 느낄 수 있고 인근에 있는 서삼릉과 함께 둘러봐도 좋다. 산책길 언덕 위쪽으로는 의자와 매점이 있어 쉬어갈 수 있는 곳이다.', '2026-06-29 14:38:30.619');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (154, '126525', '서울 선릉과 정릉 [유네스코 세계유산]', 1, 1, '서울특별시 강남구 선릉로100길 1', 37.5074206801, 127.0471803291, NULL, '06:00~21:00', '매주 월요일', '선릉(宣陵)은 조선 9대 성종과 세 번째 왕비 정현왕후 윤씨의 왕릉이다. 선릉은 같은 능역에 하나의 정자각을 두고 서로 다른 언덕에 능침을 조성한 동원이강릉(同原異岡陵)의 형식이다. 정자각 앞에서 바라보았을 때 왼쪽 언덕(서쪽)이 성종, 오른쪽 언덕(동쪽)이 정현왕후의 능이다. 선릉은 1494년 성종이 세상을 떠나자 다음 해인 1495년 광주 학당리인 현재의 자리에 조성하였다. 원래 이 자리는 4대 세종의 아들 광평대군묘역이 있던 자리였으나, 선릉이 조성되면서 광평대군묘역은 현 강남구 수서동으로 옮겼다. 이후 1530년 정현왕후가 세상을 떠나자 선릉 동쪽 언덕에 능을 조성하였다. 선릉은 정릉과 함께 1592년 임진왜란 때 왜적들이 능을 파헤쳐 재궁(梓宮)까지 불에 타는 피해를 당하여 1593년 7월에 다시 장례를 치렀다.

정릉(靖陵)은 조선 11대 중종의 왕릉이다. 중종은 1544년에 세상을 떠나 다음 해인 1545년 두 번째 왕비 장경왕후의 희릉 서쪽 언덕(현 고양 서삼릉 내 철종의 예릉 자리)에 능을 조성하고 능의 이름을 희릉과 함께 정릉이라 하였다. 그러나 정릉은 1562년 세 번째 왕비 문정왕후에 의해 현재의 자리로 옮겼다. 문정왕후는 당시 봉은사 주지였던 보우와 논의하여 중종의 능을 이곳으로 옮겼는데, 이는 문정왕후 본인이 중종의 묻히기를 원해서였다. 그러나 옮긴 정릉이 지대가 낮아 비가 오면 침수되는 일이 자주 일어나자 문정왕후는 세상을 떠난 후 정릉이 아닌 현재 서울 노원구 태릉에 묻히게 되었다. 이로 인해 중종과 세 왕비(단경왕후, 장경왕후, 문정왕후)의 능은 모두 따로 흩어지게 되었다. 정릉은 선릉과 마찬가지로 1592년 임진왜란 때 능이 파헤쳐져 재궁(梓宮)이 불에 타는 피해를 입었고, 1593년 8월에 다시 장례를 치렀다.', '2026-06-29 14:43:18.713');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (22, '126500', '홍릉시험림(홍릉숲)', 1, 11, '서울특별시 동대문구 회기로 57 (청량리동)', 37.59167677126608, 127.0426503095327, 'https://tong.visitkorea.or.kr/cms/resource/15/3500915_image2_1.jpg', '- 주중 10:00~17:00 (입장 마감 16:30)- 주말 09:00~17:00 (입장 마감 16:30)', '매주 월요일 / 5월 1일 / 설·추석 연휴', '홍릉시험림은 서울의 동쪽 천장산(天藏山, 141m)의 남서 자락에 위치하며 ‘홍릉’의 유래가 되는 명성황후의 능터와 함께 근대 임업시험 연구의 최초 시험지라는 역사적, 문화적, 학술적 가치가 높은 곳이다. 이곳은 임학적 관점에서 1922년 임업시험장을 설치하면서 우리나라 최초의 수목원을 조성한 곳으로써 여러 가지 임업시험 및 연구과제를 수행 중이며, 국내외 다양한 식물유전자원을 체계적으로 관리하고 있다. 평일에는 유치원생, 초·중·고 및 대학생의 생태학습 교육장으로서의 역할을 수행하고 있고, 1993년부터 매주 토요일과 일요일에 개방하여 도시민의 자연학습 및 환경교육을 위하여 공헌하고 있다. 현재 약 41.8ha 면적에 침엽수원, 활엽수원, 초본식물원, 관목원 등이 조성되어 있다. 
평일은 숲해설가와 함께하는 숲해설 프로그램 참여만 가능하다. 예약은 인터넷 예약으로만 가능하며, 예약인원이 4명 미만 시 예약이 취소될 수 있다. 또한, 주말에는 예약 없이 입장 및 참여가 가능하다.', '2026-06-29 14:34:12.482');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (165, '2993372', '윤동주 하숙집 터', 1, 23, '서울특별시 종로구 옥인길 57', 37.5815022773, 126.9656884317, 'http://tong.visitkorea.or.kr/cms/resource/61/3536361_image2_1.jpg', '상시 개방', '연중무휴', '비운의 천재 시인 윤동주가 머물렀던 하숙집 터이다. 시인은 1938년 연희전문학교(현 연세대학교)에 입학하면서 학교 기숙사, 북아현동, 서소문 일대에서 하숙을 했는데 1941년 5월부터 9월까지 ‘종로구 누상동 9번지’에서 살았다고 전해진다. 이곳은 평소 시인이 존경하던 소설가 김송의 집으로 불과 다섯 달 정도의 짧은 기간 머물렀지만, 이 하숙집에서 ‘별 헤는 밤’과 ‘자화상’을 포함해 주옥같은 열 편의 시를 써냈기에 오늘날 의미가 있는 공간으로 되새겨지며 방문객의 발길이 끊이질 않는다. 
실제 윤동주 시인이 머물던 당시에는 기와로 된 한옥이었으나 지금은 옛 모습은 사라지고 다세대주택 담벼락에 ‘윤동주 하숙집’이라는 안내판만 붙어 있다. 하숙집에서 180미터 정도 들어가면 인왕산 입구인 수성동 계곡이 나온다. 훗날 시인의 벗이자 당시 룸메이트였던 정병욱 서울대 교수는 “아침 식사 전에 누상동 뒷산 인왕산 중턱까지 산책을 하고, 산골짜기 아무 데서나 세수를 하고 방으로 돌아와 청소를 끝내고 조반을 마친 후 학교에 갔다.”라고 이 시절을 회고하기도 했다. 한국인이 사랑하는 국민 시인 윤동주의 속살을 잠시나마 엿보는 듯한 기분과 무엇이 어린 시인에게 영감을 주었을까 하는 호기심이 사람들의 발길을 붙잡는 이색 명소다.', '2026-06-29 14:43:18.716');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (23, '126527', '서울 영휘원(순헌황귀비)과 숭인원(이진)', 1, 11, '서울특별시 동대문구 홍릉로 90', 37.589647174, 127.0435644361, 'http://tong.visitkorea.or.kr/cms/resource/46/3055946_image2_1.JPG', '- 11월~1월 09:00~17:30 (입장 마감 16:30)<br>
- 2월~5월 / 9월~10월 09:00~18:00 (입장 마감 17:00)<br>
- 6월~8월 09:00~18:30 (입장 마감 17:30)', '매주 월요일 (단, 월요일이 공휴일일 경우 다음날 휴무)', '영휘원은 대한제국 고종황제의 후궁인 순헌황귀비 엄씨의 무덤이고, 숭인원은 대한제국 마지막 황태자인 의민황태자의 첫째 아들 이진 원손의 무덤이다. 엄씨의 위패는 현재 종로구 궁정동에 있는 칠궁에 모셔져 있다.
순헌황귀비 엄씨(1854~1911)는 엄진삼의 장녀로 8살에 입궐하여 명성황후의 시위 상궁이 되었다가, 1897년 영친왕을 낳아 고종의 후궁이 되었다. 1903년 황귀비로 책봉되고 경선궁에 살았다. 황귀비는 여성의 신교육을 위해 진명여학교와 숙명여학교를 설립하였고 양정학교가 재정난을 겪자 땅 200만 평과 내탕금을 기증하는 등 나라를 짊어지고 나갈 인재를 키우는 데 큰 역할을 하였다.  경술국치 후 1911년 덕수궁 즉조당에서 세상을 떠났다. 신주는 덕안궁에 모셨고 이후 덕안궁은 육상궁 경내로 옮겨졌다. 의민황태자의 첫째 아들 이진 원손(1921~1922)은 영친왕와 황태자비 이씨의 첫째 아들로 일본에서 태어났다. 이듬해에 영친왕 내외와 함께 잠시 귀국하였으나 일본으로 돌아가기 하루 전 덕수궁 석조전에서 급사하였다. 순종황제가 원손의 죽음을 애석하게 여겨 후하게 장례를 치르도록 명을 내려, 현재의 자리에 무덤을 조성하였다. 영휘원은 조선시대의 원소 제도에 맞게 조성하여 홍살문, 정자각, 비각을 세웠고 원침에는 호석을 둘렀다. 숭인원은 영휘원과 비슷하게 조성하였으나 원침에 호석과 석양을 생략하고 석물과 봉분의 크기도 다른 원에 비해 작게 조성하였다.', '2026-06-29 14:34:12.483');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (25, '3057945', '김희수아트센터', 1, 11, '서울특별시 동대문구 홍릉로 118 (청량리동)', 37.59069993824646, 127.0426393212894, 'https://tong.visitkorea.or.kr/cms/resource/35/3057935_image2_1.jpg', NULL, NULL, '김희수아트센터는 수림문화재단이 재단 설립자 동교 김희수 선생(1924~2012)의 교육·문화 정신을 기리기 위해 건립한 복합문화공간으로, 2016년 5월 24일 개관했다. 옛 영화진흥위원회 건물을 그 상징성을 고려하여 예술적이고 현대적인 감각이 넘쳐나는 공간으로 재구성했으며 홍릉 일대의 자연과 어우러져 아름답다. 3층 건물의 내부 공간은 설립자기념홀을 비롯한 공연장, 갤러리, 강의실 및 작업 공간, 연습실, 자료실, 수장고, 옥상정원, 카페테리아 등을 갖췄다. 많은 사람이 전시와 공연을 통해 문화 예술을 향유하고, 예술창작자들이 성장할 수 있는 플랫폼 역할을 하는 문화공간이다.
동교 김희수는 20여 년간 중앙대학교 이사장을 지낸 재일교포 사업가이다. 인간·미래·문화·창조의 기치를 내걸고 대한민국을 세계 최고 문화국가로 만들기 위해 2009년 수림문화재단을 설립했다. 수림문화재단은 예술가의 창작 지원을 위해 수림문화상, 수림문학상을 제정해 시상하고 있다.', '2026-06-29 14:34:12.483');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (31, '129554', '구리타워', 31, 6, '경기도 구리시 왕숙천로 49 (토평동)', 37.5888632453693, 127.160053754351, 'https://tong.visitkorea.or.kr/cms/resource/74/3303974_image2_1.jpg', '09:00~23:00', '연중무휴', '구리시의 랜드마크인 구리타워에는 비밀이 있다. 타워의 정체는 바로 구리자원회수시설의 굴뚝이라는 사실이다. 지상 100m 높이의 전망대에서 48각의 유리를 통해 눈부신 구리와 서울의 풍경을 조망할 수 있다. 또한, 전망대 하늘갤러리에서 지역 예술인의 개성 넘치는 작품들을 연중무휴 감상할 수 있다.

(출처 : 구리시 자원회수시설)', '2026-06-29 14:34:12.486');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (32, '228874', '구리한강시민공원(코스모스공원)', 31, 6, '경기도 구리시 코스모스길14번길 249 (토평동)', 37.5744784637, 127.1328627799, 'https://tong.visitkorea.or.kr/cms/resource/23/4066023_image2_1.jpg', '[공원]상시 개방[가족힐링 캠핑장]- 1월~5월 10:00~18:00- 6월~9월 09:00~21:00- 10월~12월 10:00~18:00※ 가족힐링 캠핑장의 경우 선착순 이용', '연중무휴', '구리한강시민공원에 조성된 꽃단지는 시민들이 즐거운 시간을 함께 나눌 수 있는 곳이다. 공원에는 등수국터널, 유채·코스모스단지, 가족힐링 캠핑장, 원형 단지(자연학습장), 산책로 등으로 이루어져 있다. 
가족힐링캠핑장은 한강변에 위치하여 야영과 취사는 할 수 없지만, 그늘목, 화장실, 음수대 등 다양한 시설을 갖추고 있어 가족나들이를 위해 많이 찾는 곳이다. 
봄의 향기가 그윽한 5월이 되면 정성스럽게 가꾸어 온 유채꽃을 선보이는 구리 한강 유채꽃축제가 열린다. 5월 가정의 달을 맞이하여 어린이를 위한 다채로운 행사가 펼쳐지며, 넓은 잔디 광장을 무대로 인기가수 라이브 콘서트 등 축하 공연도 선보인다.
가을 강바람이 시원한 코스모스가 만발한 구리한강시민공원에서 코스모스 축제가 열린다. 아름다운 코스모스 물결과 함께 다양한 볼거리와 행사로 가족, 연인과 함께하시면 깊어가는 가을의 정취를 느낄 수 있으며, 이미 많은 관광객이 매년 찾을 정도로 유명한 수도권의 축제로 자리 잡고 있다.', '2026-06-29 14:34:12.486');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (34, '129549', '곤충생태관', 31, 6, '경기도 구리시 검배로 200', 37.590201, 127.160558, 'https://tong.visitkorea.or.kr/cms/resource/89/3430689_image2_1.jpg', '[동절기(11월~2월)] - 10:00~17:00 (입장 마감 17:00)[하절기(3월-10월)]- 10:00~18:00 (입장 마감 16:30)', '매주 월요일 / 1월 1일 / 설·추석 당일 (단, 휴관일이 공휴일인 경우 다음날 휴관)', '2001년에 개관한 경기도 구리시 수택동에 위치한 곤충생태관은 곤충을 관찰하며 체험할 기회를 제공하는 생태문화 공간이다. 이곳은 하수 처리장에서 수질 기준에 적합하도록 처리된 방류수를 조경수와 화장실 용수, 청소용수, 소방용수로 사용하여 물 절약을 실천하고 생활폐기물 폐열을 활용하여 난방을 하는 에너지 절약을 실천하고 있다. 곤충생태관은 전시 및 생태관 시설과 사육시설, 식초 식물 재배 시설 등으로 구성되어 있다. 전시물로는 살아있는 나비와 장수풍뎅이, 물방개 등 36여 종의 살아있는 곤충, 타란툴라, 민물고기 등 곤충 이외의 특별한 동물을 전시하고 있다. 또한 나비표본을 포함한 330여 종의 표본을 볼 수 있다. 곤충생태관에는 다양한 교육, 체험 프로그램이 있다. 대표적인 프로그램으로는 절지동물의 겨울나기, 자연에서 찾은 생체모방 기술 등이 있으며, 홈페이지를 통해 신청 가능하다.', '2026-06-29 14:34:12.487');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (39, '779594', '한반도지형(강원고생대 국가지질공원)', 32, 8, '강원특별자치도 영월군 한반도면 한반도로 555', 37.2199280571, 128.3575534938, 'http://tong.visitkorea.or.kr/cms/resource/34/2922034_image2_1.jpg', '상시 개방', '연중무휴', '한반도를 빼닮아 붙여진 이름으로 한반도 지형을 감싸고 흐르는 감입곡류하천의 침식작용에 의해 생겨났다. 이곳에서는 이 지역에서 관찰되는 석회암, 감입곡류하는 서강, 한반도 지형이 만들어진 과정, 돌리네, 석회암의 쓰임새 등을 볼 수 있다.

(출처 : 강원고생대 국가지질공원)', '2026-06-29 14:34:12.489');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (44, '125989', '보은 삼년산성', 33, 3, '충청북도 보은군 보은읍 성주1길 104', 36.4887273864, 127.7421281216, 'https://tong.visitkorea.or.kr/cms/resource/93/4058793_image2_1.png', '상시 개방', '연중무휴', '충북 보은군 보은읍 성주 1길 104에는 신라시대 산성인 삼년산성이 있다. 둘레 1.7㎞, 넓이 8~10m, 높이 13~20m 규모의 삼년산성은 난공불락의 요새다. 성벽 아래에 서면 정육각형 벽돌로 깎아 쌓은 정교한 솜씨와 높고 튼튼한 기품에 압도된다. 삼년산성이라는 이름은 성을 쌓는 데 3년이 걸렸기 때문이라고도 하고, 삼국시대 보은의 지명이 삼년군이었기 때문이라고도 한다. 백제 성왕을 공격한 신라의 관산성 전투부대가 이곳에 주둔했었다. 태종무열왕이 당나라 사신을 접견한 곳도, 고려 왕건이 패퇴해 물러간 곳도 이곳이다. 삼국통일의 유리한 거점이었던 성곽에는 당시의 치열했던 전투는 간곳없고 돌에 낀 이끼에 평화가 느껴진다. 주차장에서 10여 분을 오르면 산성 탐방이 시작되는 서문에 닿는다. 웅장한 성벽이 양쪽으로 서 있는데, 거대한 문은 어디 가고 문을 달았던 자리만이 덩그러니 남아 있다. 조선시대 학자 김생의 글씨가 새겨진 암벽과 물이 사라진 연못이 평화로이 하늘을 올려다보고 있다. 성벽을 따라 발길을 옮기면 고즈넉한 성벽 너머 먼 산 능선들이 정답게 이어진다.', '2026-06-29 14:34:12.491');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (1, '147656', '전주 경기전', 37, 12, '전북특별자치도 전주시 완산구 태조로 44 (풍남동3가)', 35.8141717863, 127.1500212472, 'https://tong.visitkorea.or.kr/cms/resource_photo/45/3365745_image2_1.jpg', '[3월~5월]- 09:00~19:00 (입장 마감 18:00)[6월~8월]- 09:00~20:00 (입장 마감 19:00)[9월~10월]- 09:00~19:00 (입장 마감 18:00)[11월~2월]- 09:00~18:00 (입장 마감 17:00)', '연중무휴', '태조 이성계의 어진을 봉안하고 제사하는 전각인 전주 경기전은 1991년 1월 9일 사적으로 지정되었다. 1410년(태종 11)에 임금은 전주, 경주, 평양에 태조 이성계의 어진을 봉안하고 제사하는 전각을 짓고 어용전(御容殿)이라 하였다. 조선 왕조의 발상지라 여기는 전주에 건립한 태조 진전으로 경기전이라는 명칭은 세종 때 붙인 이름이다. 건물은 정유재란 때 소실되었던 것을 1614년(광해군 6)에 중건하였다. 보호 면적은 49,590㎡이다. 경기전의 경역은 정전(正殿)과 조경묘(肇慶廟)로 나뉜다. 정전은 태조 이성계의 어진을 봉안한 곳으로, 정면 3칸, 측면 3칸 규모이다. 지대석(地臺石)과 면석(面石) 및 갑석(甲石)을 갖춘 기단 위에 세운 다포계(多包系) 형식의 맞배집으로, 그 전면 가운데에는 1칸 규모의 기단을 돌출시켜 쌓고 그 위에 첨각(添閣)을 세워 배례청을 시설했다. 마치 능침(陵寢)의 정자각(丁字閣)과 같은 형상이다. 이 첨각 기단의 3면에 벽돌을 깐 보도를 연결하였다. 조경묘는 정전 북쪽에 있다. 태조의 22대조이며 전주이 씨의 시조인 신라 사공공(司空公) 이한(李翰) 부부의 위패를 봉안하기 위하여 1771년(영조 47)에 지은 것이다. 이곳에 남아 있는 경기전 조경묘 도형의 그림을 보면 지금은 없어진 전사청(典祀廳)·동재·서재·수복방·제기고 등 부속건물들과 별전이 따로 있는 광범위한 성역이었다.

경기전은 전주한옥마을에 방문했다면 꼭 들러야 할 곳 중 하나다. 드라마 촬영 명소로도 유명한 대나무숲, 고풍스러운 돌담길, 세월의 흔적을 간직한 소나무 숲과 매화나무는 고즈넉한 한옥들과 어우러져 아름다운 풍경을 선보이고 홍살문을 지나 정전으로 향하는 길에 보이는 풍경은 경건하기까지 하다. 

(출처 : 비짓전주)

◎ 한류의 매력을 만나는 여행 정보
도심 한가운데 있는 조선 시대의 고풍스러운 공간으로 정전, 돌담, 대나무숲 등이 사극의 분위기를 한껏 살린다. 먹거리, 놀 거리가 풍부한 전주한옥마을 안에 있어 전동성당과 함께 돌아보기 좋으며 주변에 한복대여소가 많아 한복을 입고 돌아보기를 추천한다.', '2026-06-29 14:34:12.473');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (12, '250358', '서울 우정총국', 1, 23, '서울특별시 종로구 우정국로 59 (견지동)', 37.5744228499, 126.9827287456, NULL, '상시 개방', '연중무휴', '서울 우정총국은 근대적인 우편 업무를 시작한 관청이다. 1884년 4월 일본과 미국에서 신식 우편 제도를 시찰하고 돌아온 홍영식이 건의하여 만들었다. 이 건물은 1884년 11월에 전의감 부속 건물을 수리하여 만든 우정총국 청사이다. 그해 12월 4일 우정총국의 개업을 축하하는 자리에 김옥균, 박영효, 서광범, 홍영식 등이 민씨 정권을 제거하고 신정부를 조직하는 갑신정변을 일으켰다. 이때 본채를 제외한 부속 건물은 모두 불에 탔고, 우정총국의 우편 업무도 중단되었다. 1893년에야 전우총국(電郵總局)이란 이름으로 우편 업무를 다시 시작하였고, 공무아문 역체국, 농상공부 통신부, 통신원 등으로 이어나갔다. 그러나 일본에 통신권을 빼앗긴 1905년 이후에는 한어학교, 중동야학교, 경성 중앙우체국장 관사 등으로 사용되었다. 해방 후에는 개인 주택이었다가 1972년부터 체신기념관이 되었다. 기념관 기능에 따라 일부를 고쳐 옛날 모습을 제대로 간직하고 있지는 못지만, 기념관 안에는 우표와 문헌, 유물들이 보존되어 있다.', '2026-06-29 14:34:12.479');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (56, '126517', '서울 문묘와 성균관', 1, 23, '서울특별시 종로구 성균관로 31 (명륜3가)', 37.5854861328543, 126.996705105892, 'https://tong.visitkorea.or.kr/cms/resource/39/3421439_image2_1.jpg', '- 하절기(3월~10월) 09:00~18:00- 동절기(11월~2월) 09:00~17:00', '연중무휴', '서울 문묘와 성균관은 종로구 명륜동 성균관대학교 안에 있는 유적으로 1398년 조선 태조가 창건했다. 문묘는 유교를 집대성한 성인 공자를 비롯하여 옛 성현들의 위패를 모시고 제사를 드리는 사당이고 성균관은 고려시대 국자감의 전통을 이어받은 조선시대 최고의 국립 교육기관이다. 중국 당나라 때 공자가 문선왕으로 추봉 됨에 따라 문선왕묘라고 부르다가 원나라 이후 문묘라고 하였다. 전묘후학의 건물 배치 형식으로 제사를 드리는 제향 구역인 문묘는 앞에, 교육을 실시하는 강학 구역인 성균관은 뒤에 두었다. 제사를 담당한 제향 관련 건물로는 대성전을 비롯하여 동무·서무, 비각, 삼문(신삼문), 동삼문, 제기고, 전사청, 수복청, 향관청, 포주 등이 있다. 교육을 담당한 강학 관련 건물로는 명륜당을 비롯하여 동재·서재, 존경각, 육일각, 진사식당, 정록청, 비복청, 서리청, 비천당 등이 있다. 주요 건물인 대성전, 명륜당, 동무·서무, 삼문(신삼문)은 보물로 지정되고 나머지 유적들은 1964년 11월 10일 사적으로 지정되었다. 명륜당 앞쪽에는 천연기념물로 지정된 은행나무가 있다. 조선시대에 제향과 유학 교육을 담당한 유교의 중심지로, 역사적으로 중요한 의미가 있으며 건축사 연구를 위한 자료로도 가치가 큰 유적이다.', '2026-06-29 14:38:30.611');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (58, '126510', '종묘 [유네스코 세계유산]', 1, 23, '서울특별시 종로구 종로 157 (훈정동)', 37.5709802173, 126.9951311023, 'https://tong.visitkorea.or.kr/cms/resource_photo/57/4063057_image2_1.jpg', '[2월~5월]- 09:00~18:00 (입장 마감 17:00)[6월~8월]- 09:00~18:30 (입장 마감 17:30)[9월~10월]- 09:00~18:00 (입장 마감 17:00)[11월~1월]- 09:00~17:30 (입장 마감 16:30)', '매주 화요일 (단, 화요일이 공휴일인 경우 개방하며, 그 다음 첫 번째 평일에 휴관)', '종묘(宗廟)는 조선과 대한제국의 역대 왕과 왕비, 황제와 황후의 신주를 모시고 제사를 지내는 국가 사당이다. 종묘에는 본래의 건물인 정전과 별도의 사당인 영녕전을 비롯하여 여러 부속건물이 있다. 조선 건국 후 1395년(태조 4) ‘궁궐을 기준으로 왼쪽에 종묘, 오른쪽에 사직을 세운다’는 예에 따라 현재의 자리에 종묘를 창건하였다. 창건 당시에는 현재의 정전만 있어서 ‘대묘, 태묘, 종묘’라고 불렀다. 
조선은 제후국으로 5묘제(五廟制)의 예에 따라 개국시조(태조)와 재위 중인 왕의 4대 조상(고조·증조·조·부)을 모시는 제도로 종묘에 신주를 모셨다. 그러다가 세종대에 5묘제에 따라 태조를 제외하고 4대가 지난 왕의 신주를 두고 여러 차례 논의한 끝에 정전 옆에 새로운 별묘(別廟)를 지어 그 이름을 ‘영녕전’이라 하였다.
4대가 지난 왕의 신주는 모두 영녕전으로 옮겨 모셨다가, 연산군 대에 ‘세실(世室, 대대로 정전에 신주를 모심)’과 ‘조천(祧遷, 영녕전으로 신주를 옮김)’의 예로 신주를 모시게 되었다. 이러한 예에 따라 3년상(27개월)이 끝난 왕과 왕비의 부묘례(祔廟禮, 신주를 종묘에 모시는 의식) 때 정전에 처음 신주가 모셔지고, 이후 ‘세실’ 또는 ‘조천’으로 정하여 정전과 영녕전에 각각 신주를 모시게 되었다. 
모시는 신주가 늘어나면서 신실이 몇 차례 증축이 되어 현재의 정전 19칸, 영녕전 16칸의 규모가 되었다. 그 밖에 종묘 경내에는 망묘루(望廟樓, 종묘서(宗廟署)의 관원들이 제례에 관한 업무를 보던 곳), 향대청(香大廳, 향과 축문을 보관하는 곳), 재궁(齋宮, 왕과 세자가 제사를 올릴 준비를 하던 곳), 전사청(典祀廳, 제사의 음식을 마련하는 곳) 등의 건물이 있다.', '2026-06-29 14:38:30.612');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (63, '2765222', '연산군유배지', 2, 1, '인천광역시 강화군 교동면 교동동로471번길 6-62', 37.7834732474445, 126.290387103403, 'https://tong.visitkorea.or.kr/cms/resource/82/3522982_image2_1.jpg', '상시 개방', '연중무휴', '강화군 교동면에 위치한 연산군 유배지에는 연산군이 유배될 당시 모습과 유배하면서 머물던 초가집이 조형물로 만들어져 있다. 연산군은 조선 제10대의 임금(재위 1494년~1506년)이었으나 많은 신진 사류를 죽이는 무오사화와 갑자사화를 일으키고 생모 윤 씨의 폐비에 찬성했던 윤필상 등 수십 명을 살해하였다. 결국 중종반정에 의해 왕위에서 폐위되어 강화도 교동으로 유배되었으며 1506년 11월 이곳에서 사망했다. 연산군 유배지 안에는 교동도 유배 문학관에서는 강화도와 교동도의 역사와 교동도에 유배 온 왕과 왕족들에 대한 이야기를 자세하게 안내하고 있다. 인근에 둘러볼 만한 곳으로는 교동시장이 있다.', '2026-06-29 14:38:30.614');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (64, '2492108', '교동도 대룡시장', 2, 1, '인천광역시 강화군 교동면 교동남로 35', 37.7802669895, 126.2809399586, 'http://tong.visitkorea.or.kr/cms/resource/76/3532576_image2_1.jpg', NULL, NULL, '대룡시장은 6·25 때 황해도 연백군에서 교동도로 잠시 피난 온 주민들이 한강하구가 분단선이 되어 고향에 다시 돌아갈 수 없게 되자 생계를 유지하기 위해 고향에 있는 연백시장의 모습을 재현한 골목시장이다. 50여 년간 교동도 경제발전의 중심지였으며 지금은 시장을 만든 실향민 어르신 대부분이 돌아가시고 인구가 급격히 줄어들면서 시장의 규모도 상당히 줄었다. 그러나 2014년 7월 교동대교 개통과 함께 1960년대 영화세트장 같은 모습의 대룡시장을 카메라에 담기 위한 관광객들의 필수코스가 되었다. 지난 3월 말부터 교동기가아일랜드 (일명 ‘교동제비집’)이 운영되고 있는데 교동제비집은 관광객들에게 IT 기반의 관광안내는 물론 자전거, 스마트워치 대여 서비스를 제공하며 ‘VR 영상 체험’, ‘교동신문 만들기’ 등 다양한 체험 프로그램을 마련되어 있다.', '2026-06-29 14:38:30.614');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (72, '3074742', '마이아트뮤지엄', 1, 1, '서울특별시 강남구 테헤란로 518 (대치동)', 37.50759111766119, 127.0605793803119, 'https://tong.visitkorea.or.kr/cms/resource/06/3511006_image2_1.jpg', NULL, NULL, '현대인들이 보다 쉽게 문화예술을 즐길 수 있도록 도심 속 예술이 있는 감성공간이라는 비전 아래 다양하고 수준 높은 전시를 즐길 수 있는 강남 도심 속의 미술관이다. 대형 미술 전시공간으로 로비 라운지, 아트샵, 카페, 세미나 룸인 오픈살롱, 컬처살롱, 교육 공간 에듀살롱, 레스토랑 등 각종 편의시설이 갖추어졌다. 어렵게 느껴졌던 예술을 마이아트뮤지엄이 편안하고 가깝게 느낄 수 있도록 일상 속에서 누구나 손쉽게 예술적 품격을 향유할 수 있는 공간이 되고자 한다.', '2026-06-29 14:38:30.617');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (75, '126747', '남산골한옥마을', 1, 24, '서울특별시 중구 퇴계로34길 28 (필동2가)', 37.5597775194, 126.9932865315, 'http://tong.visitkorea.or.kr/cms/resource/94/2932494_image2_1.bmp', '- 하절기(04~10월) 09:00~21:00<br>
- 동절기(11~03월) 09:00~20:00', '매주 월요일(단, 월요일이 공휴일일 경우 익일 휴관)', '1998년 조성된 남산골한옥마을은 남산 북측 옛 수도방위사령부 부지 총 79,934m²(24,180평)에 한옥 5동, 전통공예관, 천우각, 전통정원, 서울남산국악당, 새천년타임캡슐 광장으로 구성되어 시민과 관광객을 맞이하고 있다. 번화한 도심 한가운데에서 한국 전통문화를 소재로 한 다양한 체험거리를 만나볼 수 있으며, 남산 자락을 따라 전통조경 양식으로 조성된 계곡과 정자, 각종 화초가 만들어내는 아름다운 풍경을 만날 수 있다. 전통정원 가장 높은 곳에는 서울정도 600년을 기념하고 400년 후 서울정도 천년을 기대하며 1994년 당대의 기억을 매설한 서울천년타입캡슐 광장이 조성되어 있다. 옛 가옥을 복원해 놓은 남산골한옥마을 남산골한옥마을 안으로 들어서면 연못 청학지와 그 곁으로 천우각이 있다. 천우각 광장을 지나 돌계단을 오르면 서울 곳곳에 있던 한옥이 이전·복원되어 옛사람들의 생활방식을 볼 수 있게 한 예스러운 공간이 나타난다.
모두 다섯 채의 한옥으로서 삼각동 도편수 이승업 가옥, 삼청동 오위장 김춘영 가옥, 관훈동 민 씨 가옥, 제기동 해풍부원군 윤택영 재실, 옥인동 윤 씨 가옥이 있다. 이 중 건물 이전이 불가능할 정도로 낡은 옥인동 윤 씨 가옥만 새 자재를 사용해 복원했고 나머지 건물은 종래의 집 부재를 그대로 이전했다. 남산골한옥마을에서 즐기는 다양한 체험거리 남산골한옥마을에는 다양한 체험거리가 마련되어 있다. 한옥 다섯 채를 활용하여 한옥실내 공간을 체험하면서 동시에 한국 전통문화프로그램을 접할 수 있다. 한복 입기, 한지 접기, 한글 쓰기, 전통차 마시기를 체험할 수 있고, 전통예절학교와 한방체험도 운영하고 있다. 토요일과 일요일 양일에는 전통혼례가 실제로 치러지고 전통혼례체험도 운영하고 있다. 그 밖에도 천우각 맞은편 원두막에서는 짚공예 시연이 이루어지고 있으며, 천우각 무대에서는 태권도 시범공연과 체험 행사에 참여할 수 있다. 피금정 마당에서는 제기차기, 윷놀이, 비석치기 등과 같은 민속놀이를 즐길 수 있어 가족이 함께 즐거운 시간을 보낼 수 있다. 또한 남산골한옥마을 곳곳을 동행하며 설명해주는 전통문화유산해설사가 상주해 있어 도움을 받을 수도 있다.', '2026-06-29 14:38:30.618');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (77, '125551', '고양 서삼릉 [유네스코 세계유산]', 31, 2, '경기도 고양시 덕양구 서삼릉길 233-126 (원당동)', 37.6630660206, 126.8669756845, NULL, '[2월~5월] 09:00~18:00 (입장마감 17:00)<br>
[6월~8월] 09:00~18:30 (입장마감 17:30)<br>
[9월~10월] 09:00~18:00 (입장마감 17:00)<br>
[11월~1월] 09:00~17:30 (입장마감 16:30)', '매주 월요일<br>※ 매주 월요일 ※ 단, 월요일이 공휴일인 경우 개방하며, 그 다음 첫 번째 평일에 휴관', '서삼릉(西三陵)은 ‘서쪽에 있는 3기의 능’이라는 뜻으로 경기 고양시에 위치한 조선왕릉 중 서오릉 다음으로 큰 왕릉군이다. 1537년(중종 32) 중종의 두 번째 왕비 장경왕후의 희릉(禧陵)이 현 서울 서초구 헌릉과 인릉 서쪽 언덕에서 현재의 자리로 옮겨졌고, 1545년(인종 1) 중종의 정릉이 희릉 서쪽 언덕에 조성되자 능의 이름을 희릉과 합쳐 정릉이라 하였다. 그러나 1562년(명종 17) 정릉이 현 서울 강남구로 옮겨지면서 다시 희릉이 되었다. 이후 인종의 효릉(孝陵), 소현세자의 소현묘(昭顯墓, 이후 소경원(昭慶園)), 철종의 예릉(睿陵)이 조성되었다. 그러다가 일제강점기 때 전국에 있던 왕을 비롯한 왕실가족의 태실(胎室)과 왕자·왕녀·후궁의 묘와 문효세자의 효창원(孝昌園)이 서삼릉 경내로 옮겨졌다. 1945년 광복 후 의소세손의 의령원(懿寧園)이 옮겨졌고, 도시화 개발 시기에 왕실 후궁들의 묘와 폐비 윤씨의 회묘(懷墓)가 경내로 옮겨지면서 지금의 서삼릉이 되었다.', '2026-06-29 14:38:30.619');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (79, '127877', '쥬쥬랜드', 31, 2, '경기도 고양시 덕양구 원당로458번길 7-42 (관산동)', 37.6901876548, 126.8553176477, 'http://tong.visitkorea.or.kr/cms/resource/41/3018541_image2_1.jpg', '10:00~18:00', '매주 월요일 (단, 월요일이 공휴일인 경우 운영)', '쥬쥬랜드는 동물과 로봇, 그리고 사람을 주제로 하는 가족형 종합 테마파크로 서로 간의 조화를 추구하는 공간이다. 자연친화적인 환경에서 실내와 실외에서 다양한 동식물과의 교감을 통해 자연과 공존하는 방법을 배울 수 있는 곳이다. 또한 차세대 산업인 로봇기술을 체험하고, 관심을 갖고 혁신적인 미래형 인재에 한걸음 더 나아가는 동기를 제공한다. 개방형 동물원으로 아이들과 동물들에게 먹이 주기 체험을 할 수 있고, 로봇공연을 진행하고 있다. 어디에서도 경험할 수 없었던 새로운 생태교육의 장으로 도심을 벗어나 자연과 교감하고, 일상 속에 녹아든 IT 기술을 체험하며 공존의 가능성과 가치를 확인할 수 있는 곳이다.', '2026-06-29 14:38:30.62');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (81, '127197', '일산호수공원', 31, 2, '경기도 고양시 일산동구 호수로 595 (장항동)', 37.657058, 126.763855, 'https://tong.visitkorea.or.kr/cms/resource_photo/83/3553283_image2_1.jpg', '상시 개방', '연중무휴', '일산호수공원은 일산신도시 택지개발사업과 연계하여 조성한 근린공원이다. 국내 최대의 인공호수를 만들어 도시인이 접할 수 없는 자연생태계를 재현하고 다양한 주변경관 및 호수를 이용한 레크레이션 공간을 제공하고 있다. 특히 호수를 중심으로 한 4.7㎞의 자전거도로와 메타세쿼이아길 등 9.1㎞의 산책로는 시민들이 특별히 좋아하는 장소이다. 이외에도 생태자연학습장, 조형예술품, 선인장전시관 등이 다양한 생태문화시설이 조성되어 있다. 또한 매년 고양국제꽃박람회, 가을꽃축제, 호수예술축제 등이 개최되는 등 국내는 물론 세계적인 명소로 자리 잡아가고 있는 공원이다.

◎ 한류의 매력을 만나는 여행 정보 - 드라마 
도시인들이 접하기 어려운 자연을 인공적으로 만든 공원으로 동양 최대의 인공 호수, 인공섬, 잔디광장 등을 비롯해 100여 종의 야생화와 20만여 그루의 수목이 있어 휴식을 취하기 좋다. 고아인이 복잡한 마음을 가라앉히며 산책하다 정재훈을 만나 기운을 차린 곳이다.', '2026-06-29 14:38:30.62');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (49, '125552', '고양 서오릉 [유네스코 세계유산]', 31, 2, '경기도 고양시 덕양구 서오릉로 334-32', 37.6235552311, 126.9007662973, 'https://tong.visitkorea.or.kr/cms/resource/69/4075769_image2_1.jpg', '[2월~5월/9월~10월]- 07:00~18:00- 입장 마감 17:00[6월~8월]- 07:00~18:30- 입장 마감 17:30[11월~1월]- 07:00~17:30- 입장 마감 16:30※ 기관 사정에 따라 관람 시간이 단축 및 조정이 있을 수 있으므로 자세한 사항은 홈페이지 참조 및 전화 문의 요망', '매주 월요일(단, 월요일이 공휴일인 경우 개방하며 그 다음 첫 번째 평일에 휴관)', '서오릉(西五陵)은 ‘서쪽에 있는 5기의 능’이라는 뜻으로 경릉(敬陵), 창릉(昌陵), 익릉(翼陵), 명릉(明陵), 홍릉(弘陵)의 다섯 능을 말한다. 서오릉은 구리 동구릉(東九陵) 다음으로 규모가 큰 조선왕실의 왕릉군이다. 1457년(세조 3) 세조의 첫째 아들 의경세자(추존 덕종)의 의묘(懿墓, 경릉)가 처음 조성되었고 1470년(성종 1) 예종의 창릉(昌陵)이 왕릉으로서 최초로 조성되었다. 이후 순회세자의 순창원(順昌園), 인경왕후의 익릉(翼陵), 숙종의 명릉(明陵), 정성왕후의 홍릉( 弘陵)이 차례로 조성되어 조선시대에는 5기의 능과 1기의 원이 조성되었다. 그러다가 1970년대 영빈 이씨의 수경원(綏慶園)과 옥산부대빈 장씨의 대빈묘(大嬪墓)가 옮겨져 지금의 서오릉이 되었다.', '2026-06-29 14:34:12.492');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (84, '2546181', '양주시립회암사지박물관', 31, 18, '경기도 양주시 회암사길 11 (율정동)', 37.8412745188, 127.1029879178, 'http://tong.visitkorea.or.kr/cms/resource/58/3559458_image2_1.jpg', NULL, NULL, '경기도 북부에 위치한 양주시는 600여 년의 유구한 역사와 전통을 자랑하는 유서 깊은 문화의 고장으로 유·무형의 중요한 문화유산을 간직하고 있다. 그중에서도 회암동 천보산 자락에 위치한 회암사는 유교사회를 지향했던 조선시대에 왕실의 적극적 후원을 입은 조선최대의 왕실사찰로서 한국 불교사에서 중요한 자리를 차지하고 있다. 
지금은 비록 찬란했던 당시의 모습을 볼 수 없지만, 절터에 남아있는 유구를 통해 당시 회암사의 위상을 상상해 보는 것은 어렵지 않다. 양주시에서는 이러한 회암사지를 경기북부 최고의 관광지와 역사교육의 장으로 조성하기 위해 회암사지 종합정비계획을 수립했다. 종합정비계획에 따라 연차적으로 회암사지 발굴조사, 박물관 건립, 유적 및 단지정비 등의 사업을 추진하였으며, 양주시립회암사지박물관은 그 사업의 일환으로 2012년 10월 19일 개관한 이래 현재에 이르렀다.
양주시립회암사지박물관은 고려 말·조선 초 최대 왕실사찰이었던 회암사의 역사와 위상을 재조명하고, 유물수집·보관·연구·전시·교육기능을 통해 박물관으로써의 역할을 올바르게 수행함은 물론, 대국민서비스를 강화함으로써 보다 발전적인 역사·문화중심기관의 역할을 할 수 있는 전문박물관으로 운영하고자 한다. 아울러 국내·외 기관과의 문화교류 창구로 활용하여 문화예술 도시로서의 이미지를 창출하는데 기여하는 양주시의 대표 박물관으로 운영하고자 한다.', '2026-06-29 14:38:30.621');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (85, '3345603', '2025 양주관아지에서 만나는 특별한 주말', 31, 18, '경기도 양주시 부흥로1399번길 15 (유양동)', 37.78510751, 127.0295156915, 'http://tong.visitkorea.or.kr/cms/resource/99/3546299_image2_1.jpg', NULL, NULL, '양주시는 지역의 역사적 가치를 시민과 공유하고 문화유산을 친근하게 체험할 수 있도록 「양주관아지에서 만나는 특별한 주말」 프로그램을 운영한다. 이번 프로그램은 전통과 현대가 조화를 이루는 다채로운 체험과 공연으로 구성되어 주말을 맞아 가족, 친구, 연인 등 다양한 계층이 함께 즐길 수 있는 열린 문화마당이다. 주요 내용으로는 전통놀이와 한복 체험, 전통 공예 만들기 등 참여형 전통문화 체험과 양주관아지 해설 투어, 독립운동 이야기 등 역사적 가치를 되새기는 해설 프로그램이 마련되어 있다. 또한 전통연희 공연과 지역 예술가들의 무대가 함께 어우러져 관람객에게 다채로운 볼거리를 제공한다. 이와 함께 어린이와 가족 단위 방문객을 위한 맞춤형 체험도 준비되어 있어 누구나 즐길 수 있다. 시는 이번 프로그램을 통해 시민들이 문화유산의 의미를 직접 체험하고, 양주관아지의 역사적 정체성을 더욱 가까이 느낄 수 있는 계기가 될 것으로 기대하고 있다.', '2026-06-29 14:38:30.622');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (14, '129259', '태종대(횡성)', 32, 18, '강원특별자치도 횡성군 강림면 태종로 287', 37.3513443471, 128.1091803059, 'http://tong.visitkorea.or.kr/cms/resource/86/3577686_image2_1.jpg', '상시 개방', '연중무휴', '태종대는 강림면 치악산 국립공원 매표소 바로 위에 위치한 곳으로 태종 이방원과 스승이었던 운곡 원천석에 대한 이야기가 전해오고 있다. 고려 말 4처사의 한 사람이었던 운곡 원천석은 조선조 태조인 이방원의 스승이었다. 운곡은 태조가 고려를 전복시키고 조선을 세우고 또한 그의 아들들의 피비린내 나는 왕권 다툼에 실망과 분노를 느낀 나머지 모든 관직을 거부하고 개성을 떠나 이곳 강림리에 은거하고 있었다. 험한 산골이었던 이곳에 방원이 임금으로 등극하기 전인 1415년 옛 스승인 운곡을 찾아 다시 관직에 앉히고 정사를 의논하고자 이곳을 찾았다. 그러나 강직하고 절개가 곧았던 운곡은 방원과의 만남을 꺼려 일부러 치악산 골짜기로 몸을 숨겨 만나 주지 않았다. 방원이 자기를 찾아다니는 것을 안 운곡은 개울가에서 빨래를 하는 노파에게 자신을 찾는 사람이 오거든 횡지암 쪽으로 자신이 갔다고 일러 주라고 신신당부를 하고는 운곡은 반대 방향으로 피신했다. 방원은 노파가 가르쳐 주는 곳으로 스승인 운곡을 찾았으나 끝내 운곡을 찾지 못하고 돌아갔다. 그 당시 방원이 머물던 곳을 ‘주필대’라고 불러오다가 나중 방원이 태종으로 등극하자 ‘태종대’로 부르게 되었다. 나중에 태종이 임금이 되어 다시 운곡을 부르자 차마 어명을 어길 수 없던 그는 상주 차림으로 옷을 갈아입고는 대궐에 들어가 태종의 형제간 살육의 비인도적인 처사에 대해 무언의 시위를 벌이기도 했다.', '2026-06-29 14:34:12.48');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (48, '129689', '속리산조각공원', 33, 3, '충청북도 보은군 속리산면 사내리', 36.5329, 127.825, NULL, '상시 개방', '연중무휴', '속리산조각공원은 1997년 10월 속리산관광협회에 의해 조성됐으며, 속리산을 찾는 탐방객에게 볼거리와 문화 관광 서비스를 제공하고 안락한 휴식공간이 되고 있다. 
속리산국립공원 잔디공원 내에 조성된 공원으로 넓이는 약 2만 4000㎡이며, 김석우의 ‘하늘과 땅의 교감’, ‘양현조의 동심의 고향’, 이상필의 ‘정’ 등 충청권의 대표적인 작가 27명의 작품 27점이 전시되어 있어, 속리산을 찾는 관광객에게 예술작품을 감상할 수 있게 한다. 또한 방문객의 편의를 위해 화장실과 식수대 등의 편의시설을 갖추었으며, 여름철에는 공원 내로 흐르는 계곡을 물놀이장으로 개방한다.
속리산조각공원을 찾았다면 유네스코 세계문화유산에 지정된 법주사와 조각공원에서 법주사까지 이어지는 산책로 오리숲(2㎞) 길을 함께 하면 좋다. 또한 속리산조각공원이 위치하고 있는 속리에는 천연기념물인 정이품송이 있으며, 다양한 민화를 볼 수 있는 에밀레박물관도 함께 둘러볼 수 있다.', '2026-06-29 14:34:12.492');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (104, '129694', '병영성홍교', 38, 1, '전남광주통합특별시 강진군 병영면 성동리', 34.7217376443, 126.811560839, 'http://tong.visitkorea.or.kr/cms/resource/40/3537740_image2_1.jpg', '상시 개방', '연중무휴', '병영은 조선 태종 17년(1417)에 남해 지역의 외침을 방어하기 위하여 설치되어 500여 년 동안 호남을 지켜온 군사 요충지였으며 홍교는 병영의 관문이었다. 이 홍교는 일명 배진강 다리라고도 하는데, 장방형 화강석재 74개를 26열로 정교하게 무지개처럼 쌓고 잡석을 채워 보강한 다음 점토로 다리 위를 다졌다. 홍예의 상단 중앙에 돌출시킨 용두는 여의주를 입에 물고 풍운조화를 일으키려는 듯 머리를 치켜들고 있다. 그 모습은 매우 해학적이며 그 의장 또한 만인월교의 외경 신앙을 함축성 있게 시사하고 있는 듯하다. 축조 연대는 숙종 무인(1698년)에 가선동추 경술(1739년)에 숭록대부가 된 류한계의 금의환향을 기념하여 양한조가 감독, 준공하였다는 내용으로 미루어 18세기에 건축된 것으로 추정되는데 수작이다.', '2026-06-29 14:42:03.887');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (95, '2606158', '창경궁 명정전', 1, 23, '서울특별시 종로구 창경궁로 185 (와룡동)', 37.57888092158742, 126.9964488355471, 'https://tong.visitkorea.or.kr/cms/resource/30/2616930_image2_1.jpg', '09:00~21:00 (입장마감 20:00)', '매주 월요일', '명정전(明政殿)은 창경궁의 정전으로 왕의 즉위식, 신하들의 하례, 과거시험, 궁중연회 등 중요한 국가행사를 치르던 곳으로, ‘명정’은 ‘정사를 밝힌다 ‘라는 뜻이다. 명정전은 1484년(성종 15)에 지어졌고, 임진왜란 때 소실되었다가 1616년(광해군 8)에 재건되었는데, 현재 궁궐의 정전 가운데 가장 오래된 건물이다. 경복궁의 근정전과 창덕궁의 인정전은 중층 규모이지만 명정전은 단층으로 지어졌다. 이는 창경궁이 정치공간이 아닌 생활공간으로 지은 궁궐이기 때문으로 보인다.
명정전 앞마당, 즉 조정(朝廷)에는 박석을 깔고 중앙에는 삼도(三道)를 두어 궁궐의 격식을 갖추었다. 조정에는 품계석이 있는데, 조회나 행사 때 문무백관들이 품계석에 새겨진 각자의 품계에 맞춰 국왕을 중심으로 우측에는 무신, 좌측에는 문신이 선다. 또한 삼도 가운데 중앙에 있는 어도는 국왕이 이동하는 길이다. 명정전으로 오르는 계단 가운데 있는 경사진 돌을 답도라 하는데 그 위로 국왕이 탄 가마가 지나갔다. 명정전은 1985년 국보로 지정되었다.', '2026-06-29 14:38:30.626');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (98, '827642', '헌인릉 생태경관보전지역(오리나무림)', 1, 15, '서울특별시 서초구 헌인릉길 36-10 (내곡동)', 37.4642401896, 127.0810118065, 'http://tong.visitkorea.or.kr/cms/resource/20/3499820_image2_1.jpg', '[2월~5월] 09:00~18:00 (입장마감 17:00)<br>
[6월~8월] 09:00~18:30 (입장마감 17:30)<br>
[9월~10월] 09:00~18:00 (입장마감 17:00)<br>
[11월~1월] 09:00~17:30 (입장마감 16:30)', '매주 월요일<br>※ 단, 월요일이 공휴일인 경우 개방하며, 그 다음 첫 번째 평일에 휴관', '헌인릉 생태경관보전지역은 대모산의 남사면 하단 산자락 헌인릉 아래쪽으로 17,000여 평의 오리나무가 군락을 이루고 있는 숲이다. 대모산 남사면의 넓은 유역으로부터 유입되는 지하수로 인해 수위가 높고, 저지대로 토심이 깊어 양호한 환경조건을 갖추어 서울시에서 보기 드문 대규모 오리나무 군집이 형성되어 있다. 또한, 오리나무가 자라는 지역 곳곳에는 물웅덩이와 소규모 수로가 잔재하여 다양한 습지성 초본식물들이 번성하고 서울시 보호종인 오색딱따구리, 제비, 꾀꼬리, 박새 등이 서식하는 등 생물다양성이 풍부하다. 오리나무림, 노란물봉선, 둥굴레, 붓꽃 등 다양한 습지식물이 살고 있고 걷기 쉽도록 목재 데크로 만들어 놓아 습지에 사는 식물들을 쉽게 관찰할 수 있다. 생태경관보전지역으로 지정되면 이 지역 내에서 야생 동식물을 포획하거나 토석을 채취하는 등 생태계 보전에 해를 끼치는 모든 행위가 금지된다.', '2026-06-29 14:38:30.627');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (99, '1604941', '창덕궁 낙선재', 1, 23, '서울특별시 종로구 율곡로 99 (와룡동)', 37.5777031595, 126.9902446339, NULL, '[2월~5월] 09:00~18:00 (입장마감 17:00)<br>
[6월~8월] 09:00~18:30 (입장마감 17:30)<br>
[9월~10월] 09:00~18:00 (입장마감 17:00)<br>
[11월~1월] 09:00~17:30 (입장마감 16:30)', '매주 월요일<br>※ 단, 정기휴일이 공휴일 및 대체공휴일과 겹칠 경우에는 개방하며, 그 다음의 첫 번째 비공휴일이 정기휴일임', '낙선재는 창덕궁과 창경궁 경계에 위치하고 있다. 낙선재 일원은 조선 24대 헌종이 후궁 경빈 김씨를 맞이하면서 1847년(헌종 13)에 창경궁 낙선당 터에 낙선재를 지었고, 이듬해에 석복헌(錫福軒)과 수강재(壽康齋)를 지었다. 낙선재는 헌종의 서재 겸 사랑채로 사용하였고, 석복헌은 경빈의 처소, 수강재는 당시 대왕대비였던 순원황후 김씨(순조의 왕비)의 처소로 사용되었다. 특히 이곳은 대한제국의 마지막 황후 순정황후 윤씨와 의민황태자비(이방자 여사), 덕혜옹주 등 대한제국 마지막 황실 가족이 생활하다가 세상을 떠난 곳이기도 하다.
낙선재 일원은 단청을 하지 않은 소박한 모습이고, 낙선재 뒤로는 후원을 만들었다. 건물과 후원 사이에는 작은 석축들을 계단식으로 쌓아 화초를 심었고, 그 사이사이에 세련된 굴뚝과 괴석들을 배열했다. 궁궐의 품격과 여인의 공간 특유의 아기자기함이 어우러진 대표적인 정원이다.', '2026-06-29 14:38:30.628');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (168, '2724392', '은평한옥마을', 1, 22, '서울특별시 은평구 연서로50길 7-10 (진관동)', 37.6413948373, 126.9392252587, 'http://tong.visitkorea.or.kr/cms/resource/24/3530324_image2_1.JPG', '상시 개방', '연중무휴', '은평한옥마을은 은평구 진관동에 있는 현대식 한옥마을이다. 북촌과 서촌에 이어 새롭게 만들어졌다. 국립공원 북한산, 그리고 진관사와 어우러진 역사 문화 마을이다. 
은평한옥마을은 개인에게 한옥만을 지을 수 있게 토지를 분양해서 소유주의 취향에 따라 한옥마다 모양과 나무색이 달라서 보는 즐거움이 있다. 또한, 산책로와 카페 등 편의시설을 갖추고 있어 나들이를 즐기기에 적당하다. 
이곳은 주민들이 거주하는 민가 지역이므로 상업시설을 제외한 대부분의 곳은 한옥마을 주민들이 거주하거나 개인 사유지이기에 한옥 내부 관람은 불가하다. 다만 일부 가옥의 경우 소유주의 허락을 받으면 내부 관람이 가능하다.', '2026-06-29 14:43:18.717');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (92, '125449', '남한산성도립공원 [유네스코 세계유산]', 31, 5, '경기도 광주시 남한산성면 남한산성로 731', 37.4766684605, 127.1883850251, 'http://tong.visitkorea.or.kr/cms/resource/56/2612856_image2_1.jpg', '[남한산성 행궁]<br>
하절기(4월~10월) 10:00~18:00 <br>
동절기(11월~3월) 10:00~17:00 <br>
※ 관람시작시간 30분전 매표 시작, 관람마감시간 30분전 매표 마감 <br>', '매주 월요일', '과거 한양을 지키던 4대 요새 중 하나인 남한산성을 품은, 남한산성도립공원이 있다. 북쪽의 개성, 남쪽의 수원, 서쪽의 강화, 동쪽의 광주였다. 동쪽의 광주에는 남한산성이 있었다. 서울에서 동남쪽으로 24km, 성남시에서 북동쪽으로 6km 떨어져 있는 남한산에 위치하고 있으며, 길이는 총 12.4km(본성 8.9km, 외성 3.2km, 신남 산성 0.2km), 높이는 7.3m이다. 원래 2천여 년 전, 고구려 동명왕의 아들 백제의 시조 온조의 왕성이었다는 기록이 있고, 나당전쟁이 한창이던 신라 문무왕 13년(673)에 한산주에 쌓은 주장성이라는 기록도 있다. 그 옛 터를 활용하여 후대에도 여러 번 고쳐 쌓다가, 조선조 광해군 때(1621) 본격적으로 축성하였다 한다. 석축으로 쌓은 남한산성의 둘레는 약 12km이다. 자연석을 써 큰돌을 아래로, 작은 돌을 위로 쌓았다. 동서남북에 각각 4개의 문과 문루, 16개의 암문을 내었으며 동서남북 4곳에 장대가 있었다. 성 안에는 수어청을 두고 관아과 창고, 행궁을 건립했다. 유사시에 거처할 행궁은 상궐 73칸, 하궐 154칸, 좌전 26칸으로, 모두 252칸을 지었다. 80개의 우물, 45개의 샘을 만들고 광주읍의 행정처도 산성 안으로 옮겼다. 이쯤 되면 남한산성의 중요성과 성안이 유치 가능 인구도 짐작해 볼 수 있을 것이다. 산성이 축조되고 처음으로 시행(인조 17년, 1639)된 기동 훈련에 참가한 인원만 해도 12,700명이었다. 그러나 지금 성내에 남아 있는 건물은 불과 몇 안 된다. 동·남문과 서장대, 현절사, 연무관, 장경사, 지수당, 영월정, 침괘정, 숭렬전 이서 장군사당, 보, 루, 돈대 등이 남아있다. 그중 4대 문과 수어장대, 서문 중간쯤의 일부 성곽은 원형이 잘 보존되어 있다. 남한산성은 사적과 도립공원으로 지정되어 있다.', '2026-06-29 14:38:30.625');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (105, '2650800', '사의재저잣거리', 38, 1, '전남광주통합특별시 강진군 강진읍 사의재길 27', 34.644048467, 126.7706552189, 'http://tong.visitkorea.or.kr/cms/resource/57/3538057_image2_1.jpg', '09:00~18:00', '연중무휴', '사의재(四宜齋)는 다산 정약용이 1801년 강진에 유배 와서 처음 묵은 곳이다. 사의재는 이곳 주막집(동문매반가) 주인 할머니의 배려로 골방 하나를 거처로 삼은 다산이 몸과 마음을 새롭게 다잡아 교육과 학문연구에 헌신키로 다짐하면서 붙인 이름으로 ‘네 가지를 올바로하는 이가 거처하는 집’이라는 뜻을 담고 있다. 다산은 생각과 용모와 언어와 행동, 이 네 가지를 바로 하도록 자신을 경계하였던 것이다. ‘생각을 맑게 하되 더욱 맑게, 용모를 단정히 하되 더욱 단정히, 말을 적게 하되 더욱 적게, 행동을 무겁게 하되 더욱 무겁게’ 할 것을 스스로 주문하였다. 
사의재는 창조와 희망의 공간이다. 사려 깊은 주막 할머니의 ‘어찌 그냥 헛되이 사시려 하는가? 제자라도 가르쳐야 하지 않겠는가?’라는 얘기에 자신 스스로 편찬한 「아학편」을 주 교재로 교육을 베풀고, 「경세유표」와 「애절양」 등을 이곳에서 집필하였다. 다산은 주막 할머니와 그 외동딸의 보살핌을 받으며 1801년 겨울부터 1805년 겨울까지 이곳에 머물렀다.
강진군은 오랜 고증을 거쳐 동문 안쪽 우물가 주막터를 원형 그대로 2007년에 복원하였다. 현재는 동문매반가(주막)와 한옥체험관을 운영 중에 있다.', '2026-06-29 14:42:03.888');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (110, '2657495', '강화전쟁박물관', 2, 1, '인천광역시 강화군 강화읍 해안동로1366번길 18', 37.7336321177, 126.5160613555, 'http://tong.visitkorea.or.kr/cms/resource/28/3532928_image2_1.jpg', NULL, NULL, '강화전쟁박물관은 강화에서 일어난 전쟁과 관련한 유물을 전시하고 있다. 강화도는 지정학적 위치 때문에 항쟁의 역사가 많은 곳이다. 선사시대부터 근현대에 이르기까지 강화에서 일어난 각종 전쟁 유물 120점을 전시하고 있다. 총 네 개의 주제로 구성된 전시관에서 제1전시실은 선사시대부터 삼국시대 주제관으로, 돌화살촉, 고리자루칼 등을 전시하고 있고, 제2전시실은 고려시대의 철제은입사투구, 철투구, 철도자 등을 전시하고 있다. 제3전시실에서는 신미양요 때 어재연 장군이 광성보에 걸고 싸웠던 깃발인 수자기와 면제갑옷 등을 볼 수 있다. 제4전시실에는 조선시대 주력 화포인 불랑기포, 항일 의병들이 사용한 화승총 등 근현대 유물이 전시돼 있다. 이 밖에도 항일 의병을 체험하는 코너와 포토존도 있다.', '2026-06-29 14:42:03.889');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (111, '126484', '경희궁', 1, 23, '서울특별시 종로구 새문안로 45', 37.5703879399457, 126.968491756842, 'https://tong.visitkorea.or.kr/cms/resource/37/3482237_image2_1.jpg', '09:00~18:00 (입장 마감 17:30)', '매주 월요일 / 1월 1일', '사적으로 지정된 경희궁은 조선 후기의 대표적인 이궁이다. 1617년(광해군 9)부터 짓기 시작하여 1623년(광해군 15)에 완성되었다. 경희궁의 처음 명칭은 경덕궁(慶德宮)이었으나 원종의 시호인 경덕(敬德)과 같은 발음이라 하여 1760년(영조 36) 경희궁으로 바뀌었다. 경희궁은 도성의 서쪽에 있다고 하여 서궐(西闕)이라고도 불렸는데 이는 창덕궁과 창경궁을 합하여 동궐(東闕)이라고 불렀던 것과 대비되는 별칭이다. 임진왜란으로 경복궁이 불탄 후 대원군이 중건하기 전까지는 동궐인 창덕궁과 창경궁이 법궁이 되었고 서궐인 이곳 경희궁이 이궁으로 사용되었다. 인조 이후 철종에 이르기까지 10대에 걸쳐 임금들이 이곳 경희궁을 이궁으로 사용하였는데, 특히 영조는 치세의 절반을 이곳에서 보냈다. 경희궁에는 정전인 숭정전을 비롯하여 편전인 자정전, 침전인 융복전, 회상전 등 100여 동의 크고 작은 건물이 있었다. 1820년대 무렵에 제작되었다고 추정하는 『서궐도안』을 보면 그 규모와 구성을 짐작할 수 있다. 그러나 경복궁을 중건하면서 경희궁에 있던 건물의 상당수를 옮겨갔으며 특히 일제가 대한제국을 강점하면서 경희궁은 본격적인 수난을 맞이했다. 1910년 일본인을 위한 학교인 경성중학교가 들어서면서 숭정전 등 경희궁에 남아있던 중요한 전각들이 대부분 훼손되었고 그 면적도 절반 정도로 축소되었다. 이로 인해 경희궁은 궁궐의 모습을 잃어버렸으나 지속적인 발굴조사와 연구를 통해 숭정전 일곽과 몇몇 전각들을 복원하여 현재에 이르고 있다.', '2026-06-29 14:42:03.889');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (148, '2638478', '서울도시건축전시관', 1, 24, '서울특별시 중구 세종대로 119', 37.566882960193, 126.976702166851, 'https://tong.visitkorea.or.kr/cms/resource/92/2639292_image2_1.jpg', '10:00~18:00 (입장마감 17:30)', '매주 월요일 (단, 월요일이 공휴일인 경우 다음날 휴관) / 1월 1일 / 설날·추석', '서울도시건축전시관은 서울시가 2015년 광복 70주년을 맞아 일제강점기의 잔재였던 옛 국세청 별관 건물을 철거하고 그 자리의 역사적 가치를 회복해 시민들에게 되돌려주는 ‘세종대로 일대 역사 문화 특화 공간 조성 사업’의 일환으로 설립한 전시관이다. 국내 최초로 설립된 도시건축 분야 전문 전시관이다. 지상층에 시민광장을 만들었고 지하 3개 층을 전시관으로 조성했으며 지하층은 지하 보행로를 통해 시민청과 연결된다. 서울도시건축전시관은 서울의 도시발전과정과 미래 비전을 제시하고 시민 모두가 도시건축을 가까이하고 문화적 자산으로 인식할 수 있도록 도시·건축·공간 분야의 플랫폼이다. 또 하나의 시민 소통 공간, 문화향유 공간으로 서울이라는 도시의 형성 과정과 배경, 역사성과 지역성에 대한 이해를 돕는다.', '2026-06-29 14:42:03.9');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (156, '2553876', '세운상가', 1, 23, '서울특별시 종로구 청계천로 159 (장사동)', 37.5693347773, 126.9952555258, 'http://tong.visitkorea.or.kr/cms/resource/60/3569460_image2_1.jpg', '점포별 상이', '점포별 상이', '세운전자상가는 국내 최초의 종합전자상가이자 오랜 전통의 전자상가이다. 서울의 중심 종로에 위치해 있으며 도심전자산업지역의 메카로서 전기전자부품, 전기재료, 컴퓨터 반도체, 음향기기, 전자제품, CCTV, 오락기기, 노래방기기, 조명기기 등 다양한 전자상품을 취급하고 기기와 제품을 다룰 수 있는 장인들이 이곳에 있다. 오래된 전통만큼 TG삼보컴퓨터, 한글과컴퓨터, 코맥스와 같은 국내 굴지의 기업들이 여기서 시작한 것으로 알려져 있다. 세운상가 부지는 1945년 일본이 미국 등 연합군의 폭격에 대비해 아무런 건물도 짓지 않는 공터인 소개공지 조성 사업을 벌이고 있었던 곳이다. 한국전쟁 이후 집을 잃은 이재민들이 대규모 판잣집을 짓고 이 지역에 살기 시작했으나 1966년 대한민국 최초의 도심재개발 사업지역이 되어 건축가 김수근이 설계하고 2년 만인 1968년 세운상가로 탄생했다. 건물은 총 4층이며, 층별로 가전제품 유통상가, 생활가전제품 도매상가, 전기 및 전자부품 전문상가, 전자부품 및 제품 수리 매장이 있다.<br><br>◎ 한류의 매력을 만나는 여행 정보 - 드라마 <빈센조>
드라마 ‘빈센조’에서 이탈리아 마피아 변호사 빈센조(송중기)가 금이 숨겨진 ‘금가프라자’를 지키기 위해 세입자들과 손을 잡고 거대한 세력에 맞서는 이야기가 펼쳐진다. 극 중 ‘금가프라자’로 등장하는 건물이 바로 서울의 세운상가다. 레트로한 분위기를 지닌 세운상가는 드라마 속 장면들을 더욱 인상깊게 만들어준다.', '2026-06-29 14:43:18.714');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (116, '298106', '금곡사(강진)', 38, 1, '전남광주통합특별시 강진군 군동면 까치내로 261-21', 34.6660877777, 126.7777790571, 'http://tong.visitkorea.or.kr/cms/resource/90/3558390_image2_1.jpg', '09:00~18:00', '연중무휴', '금곡사는 신라 말 밀봉대사가 창건하여 성문사라 칭하다가 이 주위에 금광이 있다 하여 후에 금곡사라 개칭하였다. 선조 25년(1592) 임진왜란 때 승병들의 훈련 장소로 쓰였으나 왜구의 침략으로 불에 탔다. 이후 폐사와 중창을 반복하여 현재에 이르고 있다. 사찰 옆 개울가에 그 깊이를 알 수 없는 동굴이 있는 것을 보면 이곳이 금광이었던 것이 사실인 것 같다. 금곡사에는 백제 계통의 고려 양식인 보물 제829호 삼층석탑이 있는데 1985년 복원작업을 하던 중 석가세존 진신사리 32과가 발견되어 세상의 이목을 받기도 했다. 이 탑은 석탑으로서는 5m가 넘는 거탑으로 그 형식 면에서는 전형적인 고려 양식을 고수하면서도 기단부 구성이나 옥개석의 우동마루 등 일부에서는 약간의 백제 계 석탑의 분위기가 가미되어 있다. 조성 연대는 고려 초반기로 추정된다. 가뭄에도 마르지 않고 물의 양이 일정한 약수터에서 풀로 만든 대롱으로 물을 빨아먹으면 신경통이 사라진다는 전설이 있기도 하다. 아마도 임진왜란 때 왜구를 격파한 이 고장 출신 김억추장군의 전설에서 비롯된 것일 것이다.
매년 봄이 되면 금곡사로 가는 군동면 호계리에서 작천면 군자리에 이르는 19㎞ 구간은 연분홍빛 벚꽃터널이 펼쳐져 장관을 이룬다. 금곡사 벚꽃 길은 1992년부터 2년에 걸쳐 강진군 공무원들이 휴일을 반납해가며 직접 만든 곳이다.', '2026-06-29 14:42:03.891');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (119, '126747', '남산골한옥마을', 1, 24, '서울특별시 중구 퇴계로34길 28 (필동2가)', 37.5597775194, 126.9932865315, 'http://tong.visitkorea.or.kr/cms/resource/94/2932494_image2_1.bmp', '- 하절기(04~10월) 09:00~21:00<br>
- 동절기(11~03월) 09:00~20:00', '매주 월요일(단, 월요일이 공휴일일 경우 익일 휴관)', '1998년 조성된 남산골한옥마을은 남산 북측 옛 수도방위사령부 부지 총 79,934m²(24,180평)에 한옥 5동, 전통공예관, 천우각, 전통정원, 서울남산국악당, 새천년타임캡슐 광장으로 구성되어 시민과 관광객을 맞이하고 있다. 번화한 도심 한가운데에서 한국 전통문화를 소재로 한 다양한 체험거리를 만나볼 수 있으며, 남산 자락을 따라 전통조경 양식으로 조성된 계곡과 정자, 각종 화초가 만들어내는 아름다운 풍경을 만날 수 있다. 전통정원 가장 높은 곳에는 서울정도 600년을 기념하고 400년 후 서울정도 천년을 기대하며 1994년 당대의 기억을 매설한 서울천년타입캡슐 광장이 조성되어 있다. 옛 가옥을 복원해 놓은 남산골한옥마을 남산골한옥마을 안으로 들어서면 연못 청학지와 그 곁으로 천우각이 있다. 천우각 광장을 지나 돌계단을 오르면 서울 곳곳에 있던 한옥이 이전·복원되어 옛사람들의 생활방식을 볼 수 있게 한 예스러운 공간이 나타난다.
모두 다섯 채의 한옥으로서 삼각동 도편수 이승업 가옥, 삼청동 오위장 김춘영 가옥, 관훈동 민 씨 가옥, 제기동 해풍부원군 윤택영 재실, 옥인동 윤 씨 가옥이 있다. 이 중 건물 이전이 불가능할 정도로 낡은 옥인동 윤 씨 가옥만 새 자재를 사용해 복원했고 나머지 건물은 종래의 집 부재를 그대로 이전했다. 남산골한옥마을에서 즐기는 다양한 체험거리 남산골한옥마을에는 다양한 체험거리가 마련되어 있다. 한옥 다섯 채를 활용하여 한옥실내 공간을 체험하면서 동시에 한국 전통문화프로그램을 접할 수 있다. 한복 입기, 한지 접기, 한글 쓰기, 전통차 마시기를 체험할 수 있고, 전통예절학교와 한방체험도 운영하고 있다. 토요일과 일요일 양일에는 전통혼례가 실제로 치러지고 전통혼례체험도 운영하고 있다. 그 밖에도 천우각 맞은편 원두막에서는 짚공예 시연이 이루어지고 있으며, 천우각 무대에서는 태권도 시범공연과 체험 행사에 참여할 수 있다. 피금정 마당에서는 제기차기, 윷놀이, 비석치기 등과 같은 민속놀이를 즐길 수 있어 가족이 함께 즐거운 시간을 보낼 수 있다. 또한 남산골한옥마을 곳곳을 동행하며 설명해주는 전통문화유산해설사가 상주해 있어 도움을 받을 수도 있다.', '2026-06-29 14:42:03.892');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (120, '126485', '남산공원(서울)', 1, 24, '서울특별시 중구 삼일대로 231 (예장동)', 37.5556863093, 126.9922311881, 'http://tong.visitkorea.or.kr/cms/resource/56/3539656_image2_1.jpg', '상시개방', '연중무휴', '남산공원은 서울 도심에 위치하여 시민에게 맑은 공기를 제공하는 자연 휴식처이다. N서울타워와 남산케이블카 등의 시설 이용과 산책, 운동, 휴식 등 다양한 활동이 가능한 여가 생활의 중심지이기도 하다. 
남산공원의 정식 명칭은 남산도시자연공원이다. 남산은 서울의 중심부에 있는 서울의 상징으로 본래 이름은 인경산이었으나 조선조 태조가 도읍지를 개성에서 서울로 옮겨 온 뒤에 남쪽에 있는 산이므로 ‘남산’으로 지칭되었다. 그리고 풍수지리상 안산으로 중요한 산이기도 하다. 1991년부터 8년간 ‘남산제모습 가꾸기’ 사업으로 공원 내 부정적 시설 89동을 이전하고 야외식물원을 조성하는 등 중구 예장동, 회현동, 용산구 한남동 일대를 대대적으로 복원, 정비하여 시민들에게 휴식과 맑은 공기를 제공하며 여가생활의 중심지로 거듭난 공원이다. 
남산타워 전망대를 오르는 길에 남산공원의 명물 ‘사랑의 자물쇠’가 있다. 연인들의 사랑을 지켜준다는 의미로 이미 많은 자물쇠가 걸려있다. 수많은 자물쇠에 적혀있는 문구들을 읽으면서 가는 것도 소소한 재미가 있다.
2005년 5월 1일부터 남산공원에 일반승용차, 택시 통행이 금지되었다. 남산 서울타워까지 명동, 충무로, 동대입구역에서 순환버스나 남산케이블카를 이용하거나 산책 겸 도보로 오르는 방법도 있다.', '2026-06-29 14:42:03.892');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (124, '1849416', '대한민국역사박물관', 1, 23, '서울특별시 종로구 세종대로 198 (세종로)', 37.5741339024, 126.977573668, 'http://tong.visitkorea.or.kr/cms/resource/89/3082989_image2_1.JPG', NULL, NULL, '대한민국역사박물관은 19세기말 개항기부터 오늘날까지의 대한민국의 행보를 기록한 박물관으로, 2012년 12월 26일에 개관한 최초의 국립 근현대사 박물관이다. 박물관은 고난과 역경을 딛고 발전한 대한민국의 역사를 전시, 교육, 조사∙연구, 자료의 수집을 통해 국민과 공유하고자 설립되었다. 박물관은 대한민국의 역사를 시대별로 4개의 전시실로 나누어 설명하고 있다. 제1전시실에서는 ‘대한민국의 태동’, 제2전시실에서는 ‘대한민국의 기초 확립’, 제3전시실에서는 ‘대한민국의 성장과 발전’, 그리고 제4전시실에서는 ‘대한민국의 선진화, 세계로의 도약’을 주제로 전시가 구성되어 있다. 어린이 박물관에서는 어린이가 직접 체험하면서 근현대사를 배울 수 있다. 또한, 근현대사 전반에 걸친 다양한 주제의 특별 전시를 통해 대한민국 근현대사에 대한 심층적인 내용을 살펴볼 수 있다. 박물관에서 다양한 교육 프로그램과 문화행사도 운영하고 있다.', '2026-06-29 14:42:03.894');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (129, '2514045', '윤봉길의사기념관', 1, 15, '충청남도 예산군 덕산면 덕산온천로 183-5', 36.6865252872, 126.6513693512, 'http://tong.visitkorea.or.kr/cms/resource/18/3039818_image2_1.jpg', NULL, NULL, '예산 덕산온천 인근 충의사(매헌 윤봉길 의사 유적) 내에는 윤봉길의사기념관이 들어서 있다. 매헌윤봉길의사기념관은 서울에 있고, 윤봉길의사기념관은 예산에 있다.
이 기념관이 있는 충의사는 윤봉길 의사(1908~1932)가 태어나서 중국으로 가기 전까지 거주하던 곳이기도 하며, 지금은 사적지화 되어 윤 의사의 생가가 보존되고 그를 기리는 사당 및 기념비, 동상 등이 들어서 있다. 
기념관에는 이곳에서 태어나 농촌 계몽운동을 하다가 중국으로 건너가서 1932년에 상하이 훙커우 공원에서 일본군 행사에 폭탄을 투척하여 일본군에 큰 피해를 입히고 우리나라의 독립 의지를 세계에 보여준 후 일본에서 사형당하기까지 윤 의사의 일생을 표현한 그림, 전시물, 영상, 디오라마 등이 전시되어 있다. 또한 윤 의사가 남긴 뒤 보존되어 보물로 지정된 유품들도 전시되어 있다. 그리고 관람 전 큐브 활동지를 만들어 관람 후기를 작성한 뒤 귀가하여 그림봉투 화분으로 활용할 수 있는 프로그램도 있다.
주변에는 충의사, 덕산온천 외에 보부상유품전시관(예덕상무사), 내포보부상촌, 덕산 메타세쿼이아길, 가야산, 덕숭산, 수덕사, 옥계저수지, 남연군묘 등이 있어 연계하여 관광할 수 있다.', '2026-06-29 14:42:03.895');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (132, '1198901', '배재학당역사박물관', 1, 24, '서울특별시 중구 서소문로11길 19 (정동)', 37.5638516791, 126.9728160596, 'http://tong.visitkorea.or.kr/cms/resource/19/3533219_image2_1.jpg', NULL, NULL, '배재학당역사박물관은 교육, 종교, 정치, 사회, 문화 등 다양한 분야에서 한국 근대사를 새롭게 조명할 자료와 담론이 모여드는 공간이다. 배재학당은 1885년 미국인 선교사 아펜젤러가 세운 한국 최초의 서양식 근대 교육기관이다. 고종황제는 1887년 ''유용한 인재를 기르고 배우는 집''이라는 뜻으로 이곳에 배재학당이란 이름을 하사하였다. 2008년 배재학당역사박물관으로 새롭게 태어난 배재학당 동관은 1916년 준공된 유서 깊은 근대 건축물로, 아펜젤러가 초기부터 영어 수업을 비롯한 전인 교육을 실천했던 공간이자 김소월, 주시경, 나도향 등 수많은 근대 지식인들을 배출한 신교육의 발상지며, 신문화의 요람이다. 배재학당역사박물관에는 근대 교육의 면모를 확인할 수 있는 귀한 소장품들과 함께, 상설 전시실, 기획 전시실, 체험 교실 등을 갖추고 다양한 분야에서 한국 근대사를 새롭게 조명할 자료를 소장하여 전시한다.', '2026-06-29 14:42:03.896');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (134, '128952', '강진 병영마을 옛 담장', 38, 1, '전남광주통합특별시 강진군 병영면 지로리', 34.7148913023, 126.8182354193, 'http://tong.visitkorea.or.kr/cms/resource/46/3537746_image2_1.jpg', '상시 개방', '연중무휴', '강진 병영 마을은 옛 병마절도사의 영(營)이란 명칭에서 유래된 마을로 오랜 역사 속에서 그 명맥을 이어오고 있다. 주위의 수인산, 성자산, 옥녀봉, 별락산, 화방산 등 크고 작은 산으로 둘러싸여 분지 형태의 천연 요새로, 일찍이 전라도의 군수권을 통괄했던 병영성이 이곳에 들어섰으며 빠른 상업의 발달을 이룬 곳이다. 이곳에는 사적으로 지정된 ‘병영 성지’가 남아있어 그 역사를 증언하고 있다. 병영 마을의 담장은 전체적으로 돌과 흙을 번갈아 쌓은 토석담으로 하부는 비교적 큰 화강석을, 중단 이후로는  어른 주먹 크기 정도의 비교적 작은 돌을 사용하여 쌓아 올렸다. 담 위에는 기와로 지붕 처리를 하였다.

또한 담장 역할을 하는 부속채도  담장과 같은 높이와 방식으로  축조되어 서로가 조화를  잘 이루고 있다. 담장의 높이는 2m 정도로 높은 편이고 이는 병영 마을이라는 특성과 무관하지 않은 것으로 보이며 마을 안길이 직선형으로 되어있어 담장이 한층 정연해 보인다. 특히, 하멜 일행이 1656년부터 1663년까지 7년간 이곳에 머무는 동안 그들로부터 습득한 것으로 전해오는 담쌓기 방식인, 중단 위쪽으로 얇은 돌을 약 15° 정도 눕혀서 촘촘하게 쌓고, 다음층에는 다시 엇갈려 쌓는 일종의 빗살 무늬 형식(이곳에서는 이 형식을 ‘하멜식 담쌓기’라 부른다) 은 타 지방과 다른 독특한 방식을 보여주고 있다.', '2026-06-29 14:42:03.897');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (140, '128871', '흥국사(고양)', 31, 2, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '흥국사의 창건은 지금으로부터 1300여 년 전 전인 서기 661년(신라 문무왕 원년)에 당대 최고의 고승인 원효스님이 북한산 원효암에서 수행 중 북서쪽에서 상서로운 기운이 일어나는 것을 보고 산을 내려와 이곳에 이르게 되었다. 서기를 발하고 계신 석조 약사여래 부처님을 보신 원효스님이 인연도량이라 생각하여 본전에 약사부처님을 모시고 ‘상서로운 빛이 일어난 곳이라 앞으로 많은 성인들이 배출될 것이다’하시며 절이름을 흥성암이라 하고 오늘의 흥국사를 창건했다.
그 이후 사찰의 역사를 가늠해 볼 수 있는 자료가 없어 자세한 자취는 알 수 없으나 서기 1686년(숙종 12)에 중창한 사실과 영조시대에 크게 발전하였다는 기록이 있다. 특히, 서기 1758년(영조 34)에 미타전 아미타불을 개금 중수(복장연기문)하였고, 서기 1770년(영조 46) 생모 숙빈 최씨 묘원인 소녕원에 행차하다가 많은 눈을 만나게 되어 이곳에 들르게 된 영조대왕이 하루를 머물고 아침에 일어나 지었던 시가 비문에 전해진다.
이후 서기 1785년에 승도대장·관선·가선·법헌스님 등이 중창하였고, 1792년(정조 16)에는 관선·법선스님 등이 후불탱을 조성·봉안했다. 1867(고종 4)년에는 화주 곽명스님이 약사전을 중건하였으며, 1876년(고종 13)에는 화주 설허스님이 칠성각을 중건하였다.', '2026-06-29 14:42:03.898');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (89, '129194', '가나아트파크', 31, 18, NULL, NULL, NULL, NULL, '[평일]<br>
- 10:00~18:00 (입장마감 17:00)<br>
[주말 및 공휴일]<br>
- 4월~9월 10:00~19:00 (입장마감 18:00)<br>
- 10월~3월 10:00~18:00 (입장마감 17:00)', '매주 월요일 (단, 공휴일 제외)', '가나아트파크는 1984년 국내 최초 사립미술관인 토탈미술관이 그 전신으로서, 2005년 모회사 가나아트센터에서 인수하여 조각공원을 중심으로 설립되었다. 이후 가나아트파크는 2006년 미술관(우치다 시게루 설계)과 공연장(반 시게루 설계), 어린이체험관, 가나 제1아틀리에(장 미셸 빌모트 설계)를 개관했다. 2007년 블루(Blue)·레드(Red)·옐로우(Yellow) 스페이스가 신축 및 개관 전을 열었으며, 뒤이어 2008년 가나 제2아틀리에가 열렸다.
2013년 가나아트파크 미술관이 ‘가나어린이미술관’으로, 블루스페이스가 국내 최초 ‘피카소어린이미술관’으로 탈바꿈하면서, 가나아트파크는 어린이를 비롯하여 전 계층을 아우르는 예술복합공간으로 자리매김하였다.
2016년 가나아트파크는 개관 10주년을 맞이하여 예술아카데미 ‘눈코입 미술관’과 ‘호기심 미술관 탐험’을 운영하였으며, 가나아틀리에 입주 작가가 참여한 ‘나도 예술가’ 프로그램이 체험공방에서 진행되었다.
가나아트파크는 신진·중견·원로 작가들에게는 보다 나은 창작 공간과 전시 기회를 부여하고, 대중에게는 미술을 비롯한 다양한 예술 장르를 수용함으로써, ‘인간과 자연 그리고 예술이 공존하는 예술복합공간’을 실현하고자 한다.', '2026-06-29 14:38:30.624');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (19, '125761', '구룡사', 32, 9, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '신라 문무왕 8년(668년)에 의상대사가 창건한 사찰로 대웅전 자리에 9마리의 용이 살고 있는 연못을 메우고 사찰을 창건하여 구룡사[九龍寺]라 하였으나, 조선 중기에 거북바위 설화와 관련하여 현재의 명칭인 구룡사[龜龍寺]로 개칭하였다고 전해진다. 또한 ''치악산구룡사사적'' 에 따르면 신라말의 고승 도선국사에 의해 창건되었다고 기록하고 있다. 현재는 강희 45년 글자가 새겨진 와당이 출토되어 숙종 32년(1706년)에 구룡사가 중건되었음을 알 수 있다. 대웅전 앞 좌우에는 서상원과 보광루, 적묵당, 심검당의 승사가 있으며 이밖에도 원통문, 국사단, 사천왕문, 범종각, 응진전 등이 있다. 절 입구에는 조선시대에 만들어진 부도군이 있고, 또 구룡사의 전설을 말해주는 거북바위와 폭포아래에 용소가 있다. 또한 조선시대에 만든 황장금표가 있는데 이것은 치악산 일대의 송림에 대한 무단벌채를 금하는 표식이다.', '2026-06-29 14:34:12.481');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (94, '125550', '북한산성', 31, 2, NULL, NULL, NULL, NULL, '- 하절기(3월~11월) 04:00~17:00- 동절기(12월~2월) 04:00~16:00※ 자세한 사항은 전화문의 요망', '연중무휴', '북한산성은 고양시 덕양구 북한동과 서울시 강북구, 종로구, 은평구 경계의 북한산 정상 능선을 따라 위치하는 포곡식 석축산성이다. 백제가 수도를 하남 위례성으로 정했을 때 도성을 지키던 북방의 성으로 백제 개루왕 5년(132년)에 북한산성의 명칭으로 축조했다는 기록이 있다. 이 지역은 고구려, 백제, 신라가 서로 차지하기 위해 쟁탈전을 벌였던 곳이며, 조선시대에는 도성을 지키는 중요한 곳이었다. 11세기 초 거란의 침입이 있을 때 현종이 고려 태조의 관을 이곳으로 옮겨 오기도 했다. 고려 고종 19년(1232년)에 몽고군과의 격전이 있었고, 우왕 13년(1387년)에 성을 다시 고쳐지었다. 성의 규모는 대서문, 동서문, 북문 등 13개의 성문과 불을 피우던 곳으로 동장대, 남장대, 북장대가 있었다. 현재 북한산성에는 삼국시대의 토성이 약간 남아 있기는 하나 대개 조선 숙종 때 쌓은 것으로 여장은 허물어졌고, 대서문과 장대지, 우물터, 건물터로 생각되는 방어시설 일부가 남아있다.', '2026-06-29 14:38:30.626');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (50, '125562', '행주산성', 31, 2, NULL, NULL, NULL, NULL, '[주간 개장] - 하절기(3월~10월) 09:00~18:00 (입장 마감 17:00) - 동절기(11월~2월) 09:00~17:00 (입장 마감 16:00) [야간 개장] - 하절기(3월~10월) 매월 2·4째주 토요일 18:00~22:00 (입장 마감 21:00) ※ 야간 개장 동절기(11월~2월)는 미운영', '매주 월요일 (단, 월요일이 공휴일인 경우 그 다음 평일 휴관)', '행주산성은 경기도 고양시 덕양구 행주내동 덕양산의 7, 8부 능선에 쌓은 테뫼식[山頂式] 성으로 흙을 이용해서 쌓은 산성이다. 덕양산 정상부를 에워싼 소규모의 내성[內城]과 북쪽으로 뻗은 골짜기를 에워싼 외성[外城]의 이중구조로 강안의 험한 절벽을 이용하고 동, 북, 서로 전개된 넓은 평야를 감싸고 있다. 성안에서는 삼국시대의 적갈색 연질 토기와 회청색 경질토기 등의 조각을 비롯하여 어골문[魚骨文], 수지문[手指文]이 새겨진 기왓조각도 발견되고 있어 고려 시대까지도 사용된 것으로 보인다. 임진왜란 당시 권율[權慄] 장군이 의병과 승명을 포함한 2천3백 명과 함께 왜군 3만여 명을 크게 물리쳤다. 왜군을 격파하여 나라를 위기에서 벗어나게 하는데 큰 공을 세운 충장공 권율 도원수의 행주대첩을 기념하기 위한 매년 제례행사와 그 밖의 여러 가지 문화 행사가 개최되고 있다. 권율 도원수의 영정이 모셔져 있는 충장사에서 행해지는 이 제례에는 장군의 영혼을 불러들이기 위해 향을 피우고 제례를 지낸다. 선조들의 나라 사랑하는 마음과 지혜를 배울 수 있는 곳이다.', '2026-06-29 14:38:30.609');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (115, '2608977', '국립민속박물관과 국립민속박물관 어린이박물관', 1, 23, NULL, NULL, NULL, NULL, '[국립민속박물관]- 3월~10월 09:00~18:00 (입장 마감 17:00)- 11월~2월 09:00~17:00 (입장 마감 16:00)[국립민속박물관 어린이박물관]- 09:30~16:50※  변동 될 수 있으므로 홈페이지 참조', '1월 1일 / 설·추석 당일', '국립민속박물관은 경복궁 내 본관과 파주관으로 구성된 민속생활사 전문 국립박물관으로 약 4,000여 점의 전통 생활 민속자료를 소장·전시하고 있다. 본관에는 어린이박물관이 함께 운영되며 전시실은 한국인의 하루, 일 년, 일생을 주제로 한 3개의 상설전시와 기획·야외전시로 구성되어 있다. 야외 공간에는 열두 띠 동상, 장승, 연자방아, 1970~80년대 골목을 재현한 ‘추억의 거리’가 있다. 교육프로그램과 전통명절 행사, 외국인 체험 등 다양한 문화 교육 활동이 홈페이지를 통해 운영된다. 어린이박물관은 사전예약제로 1인 1일 1회 관람이 가능하며 전통문화를 쉽고 재미있게 체험할 수 있도록 구성되어 있다.

국립어린이민속박물관은 어린이를 대상으로 한국의 전통문화를 쉽고 재미있게 배울 수 있도록 구성된 체험 중심 박물관이다. 국립민속박물관 본관 제2전시실 옆에 위치해 있으며, 입장료는 무료이다. 하루 30분씩, 1회당 50명씩 입장이 가능하며, 체험은 정해진 시간에 맞춰 운영된다. 월별 운영 시간과 프로그램이 다르기 때문에 방문 전 홈페이지에서 확인이 필요하다. 다양한 전시와 활동을 통해 어린이들이 전통문화를 자연스럽게 익히고 체험할 수 있는 교육공간이다.', '2026-06-29 14:42:03.891');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (155, '2930901', '성수동 카페거리', 1, 16, NULL, NULL, NULL, NULL, '점포 별로 상이함', '점포 별로 상이함', '오래된 공장지대, 구두 공방 골목으로 대표되던 성수동 연무장길이 트렌디한 카페와 문화공간으로 거듭났다. 지금도 자동차 정비공장과 인쇄 공장, 수제화 거리의 활기는 여전하지만, 요란하게 돌아가는 공장사이에 글로벌 외식 업체와 편집숍 카페들이 들어서면서 성수동만의 독특한 분위기가 형성됐다. 대림창고는 성수동 골목의 변화를 이끈 주인공으로 현재 카페거리 곳곳에 들어선 창고형 카페의 원조라 할 수 있다. 이곳은 옛 창고의 붉은 벽돌 구조와 오래된 간판, 광활한 실내 공간을 살리고 감각적인 인테리어를 더해 패션쇼와 전시를 위한 공간으로 꾸며 오래된 성수동 건축의 새로운 가능성을 보여주었다. 이 외에도 하루가 다르게 새로운 카페와 베이커리, 레스토랑과 복합 문화 공간이 문을 열고 손님맞이에 분주하다.', '2026-06-29 14:43:18.714');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (173, '2764331', '인왕산 국사당', 1, 23, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '인왕산 기슭에 위치한 국사당은 무속신앙에서 섬기는 여러 신을 모신 당집으로 굿판을 벌이기 쉽도록 인가에서 멀리 떨어진 산속에 세운 굿당에 속한다. 조선시대에 나라에서 남산을 신격화한 목덕대왕에게 제사를 지내던 곳으로 ‘목면신사’라고도 불렸다. 경대부는 물론 일반 백성도 이곳에서 제사를 지낼 수 없었다. 국사당은 나중에 굿당으로 변하였는데, 헌종 대 학자 이규경(1788~)이 지은 『오주연문장전산고(五洲衍文長箋散稿)』란 책에는 ‘국사당’이라는 명칭과 함께 현존하는 무신도의 기록이 있다. 국사당은 원래 남산 꼭대기에 있었으나 일제강점기 때 일본인들이 조선신궁(朝鮮神宮)을 지으면서 이전을 강요하자 건물을 해제하여 현재의 인왕산 기슭에 옮겨 원형대로 복원한 것이다. 인왕산을 택한 이유는 이곳이 풍수지리설에서 명당에 속하고 현재 무속신으로 모셔지는 조선 태조와 무학대사가 기도하던 자리이기 때문이다. 앞면 3칸, 옆면 2칸이고 양끝의 2칸은 이곳으로 이전한 후 새로 지은 것이다. 1칸은 4쪽의 여닫이문으로 되어 있고 지붕은 옆에서 볼 때 사람 인(人) 자 모양인 맞배지붕이다. 내부의 3면에는 무신도가 걸려있고 마루에는 제상을 차리고 굿을 하는 공간으로 이루어져 있다. 일반 건물보다 구조는 간단한 편이나 그 규모는 더 크다. 1925년경에 새로 지어진 국사당은 영·정조 때의 건축기법을 바탕으로 한 원래의 국사당을 그대로 복원한 것이다. 내부의 대들보가 아치형으로 된 것이 특이한 이 건물은 전체적으로 구조가 간결하면서도 목재의 짜임새가 튼튼한 것이 목공의 솜씨가 돋보인다. 인왕산 국사당은 다른 당집에 비해 건물이 견고하고 많은 무신도를 볼 수 있다. 사당 안에는 국가민속문화유산으로 지정된 무신도가 걸려 있는데, 그 솜씨가 다른 무신도에 비해 뛰어나다. 지금도 이곳 국사당을 무대로 내림굿, 치병굿, 재수굿 같은 굿판이 벌어지고 있다.', '2026-06-29 14:43:18.719');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (117, '129501', '낙산공원', 1, 23, NULL, NULL, NULL, NULL, '상시 개방 ※ 낙산 전시관 09:00~17:00', '연중무휴', '낙산공원은 대학로와 동대문으로부터 이어지며 역사와 문화를 함께 즐길 수 있는 공원이다. 낙산은 지형이 낙타의 등처럼 생겨 낙타산이라고도 했고, 궁에 우유를 보급하던 왕실 목장이 있어 타락산이라고도 불렀다. 1960년대 이후 시민아파트와 밀집된 주택으로 낙산 본래의 모습이 사라지게 되었고, 서울시가 낙산 복원계획을 수립하였다. 이 계획의 일환으로 공원화 사업이 진행되어 2002년 7월 낙산공원으로 개원하였다. 낙산공원 중앙광장에는 낙산전시관과 중앙무대, 매점 등이 있어서 쉬어가기 좋고 광장 바로 아래 주차장이 있어서 중앙광장으로 오기도 편하다. 낙산전시관은 낙산공원 입구에 있는 시설물로 낙산의 유래, 역사적 인물, 한양도성의 사진 자료 및 모형이 전시되어 낙산공원을 방문하는 시민들에게 다양한 정보를 제공한다. 주말에는 낙산과 서울한양도성에 관한 공원 이용 프로그램이 운영되며, 누구나 무료로 이용할 수 있다. 광장 한쪽으로는 낙산정이 있다. 낙산정은 낙산을 복원하면서 만든 정자로 서울의 전경이 한눈에 보이는 전망 좋은 곳이다.  
서울한양도성과 푸른 숲이 어우러져 아름다운 정취를 느낄 수 있는 시민의 휴식 공간으로 자리매김하였으며, 서울에서 가장 아름다운 야경을 볼 수 있는 곳으로 각광받고 있다. 언덕 정상에서 주택과 벽화가 있는 이화동 벽화마을로 갈 수 있고 흥인지문과 한양도성길로 가는 동대문 코스, 외부 성곽 벽면 전체를 보면서 걸을 수 있는 한성대 입구 방면 코스 등 다양한 코스가 있다. ◎ 한류의 매력을 만나는 여행 정보 - 애니메이션 
넷플릭스 애니메이션 ‘케이팝 데몬 헌터스’에서 루미와 진우가 대화를 나누며 걷던 장소 중 하나가 바로 이곳이다. 성곽 너머로 펼쳐지는 서울의 도시 풍경이 인상적으로 담겨, 애니메이션 속 감성을 더욱 깊이 있게 전한다. 실제로 방문하면 고즈넉한 성곽길과 함께 서울의 전경을 한눈에 내려다볼 수 있어 특별한 경험을 선사한다.', '2026-06-29 14:42:03.891');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (190, '264386', '팔달문', 31, 13, NULL, NULL, NULL, NULL, '하절기(3~10월) 09:00~18:00 <br />
동절기(11~2월) 09:00~17:00', '연중무휴', '팔달문은 수원 화성의 남문이다. 정조는 팔달八達의 의미를 ‘산 이름이 팔달이어서 문도 팔달이며, 사방팔방에서 배와 수레가 모인다.’는 뜻으로 풀이했다. 팔달문 주변은 삼남 지방으로 통하는 길목이어서 화성 축성 전에도 사람들의 발길이 잦았다. 장안문과 마찬가지로 문 밖에 항아리 모양의 옹성甕城을 만들고, 방어를 위해 좌우에 적대를 세웠다. 규모와 형식은 장안문과 같다. 1794년 2월 28일 장안문과 같은 날에 터 닦는 일을 시작했지만 대체로 장안문보다 공정별로 약 1주일 늦게 완성하였다. 강원도 출신 목수 윤사범이 다포를 짜 맞추는 일을 담당했는데, 이 목수는 훗날 창덕궁 인정전을 짓는 공사를 담당해 근 100년 만에 화성에서 재현했던 다포 건축 기술을 이어 나갔다. 팔달문은 축성 당시의 건축물뿐만 아니라 공사 감독과 석공의 이름을 새긴 실명판, 현판까지 원형이 잘 남아 있다. 2013년 처음으로 문루 전체를 수리했는데 훼손된 목재를 최대한 재사용하였다. 부재에 남겨져 있는 전통 기술의 흔적까지 보존한 사례로 손꼽힌다. 

(출처 : 수원문화재단)', '2026-06-29 14:43:18.723');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (160, '1131275', '매헌시민의 숲', 1, 15, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '매헌시민의 숲은 우리나라 최초로 숲 개념을 도입한 공원으로 도심에서 보기 힘든 울창한 숲을 이루고 있는 공원이다. 86아시안 게임과 88올림픽을 앞두고 당시 서울의 관문이었던 양재 톨게이트 주변 환경을 개선하고자 1986년에 공원으로 조성되었다. 공원에는 소나무, 느티나무, 당단풍, 칠엽수, 잣나무 등 70종 25만 주의 수목이 식재되어 있다. 매헌로를 기준으로 북측 구역에는 매헌윤봉길의사기념관, 바닥분수, 어린이놀이터 등이 있어 아이들과 나들이를 하러 가족들이 많이 찾는다. 남측 구역에는 유격 백마부대 충혼탑과 1987년 미얀마 안다만해협 상공에서 북한의 테러로 폭파된 대한항공 858편의 위령탑, 1995년 삼풍백화점 붕괴로 사망한 희생자와 유족들을 위로하기 위해 세운 위령탑, 우면산 산사태 희생자 추모비 등이 있다. 특히, 매헌시민의 숲 제3구역은 서초구에서 문화예술공원으로 조성하였는데, 놀이마당, 야외공연장, 각종 기획전시장, 조각공원, 만남의 광장 등으로 구성되어 있다. 이곳에서 공연과 전시회등이 열리고 있어 문화자치구를 자랑하는 서초구의 새로운 명소로 각광받고 있다. 이렇게 공간마다 색다른 분위기를 연출하고 있어 시민들에게 많은 사랑을 받고 있는 공간이다.', '2026-06-29 14:43:18.715');
INSERT INTO public.spots (id, content_id, name, area_code, sigungu_code, address, latitude, longitude, image_url, opening_hours, closed_days, description, created_at) VALUES (76, '126491', '장충단공원', 1, 24, NULL, NULL, NULL, NULL, '상시 개방', '연중무휴', '장충단공원은 항일운동과 관련된 애국충정이 깃든 민족공원이다. 남산의 동북쪽 기슭에 있는 이 공원은 조선 영조 때 도성의 남쪽을 수비하던 남소영이 있던 자리이다.
1895년 8월 20일, 명성황후가 일본의 자객들에 의해 경복궁에서 시해당하는 사건이 발생했다. 당시 궁내부 대신 이경직, 시위대장 홍계훈 등 많은 장병이 일본인들을 물리치다가 죽음을 맞았다. 이에 고종 황제는 그들의 영령을 위로하고자 1900년 11월 장충단이라는 사당을 짓고 1908년까지 매년 춘추로 제사를 올렸다.
원래 장충단은 지금의 신라호텔 영빈관 자리에 있었다. 그러나 사당은 한국전쟁 중 소실되었고 장충단에 세워졌던 비만 남아 1969년 현재의 자리로 옮겨졌다. 1919년 일제가 민족정기를 말살하기 위해 박문사라는 절을 세우고 장충단 자리에 공원을 조성했는데, 광복 후 모두 철거되었다.
1984년 9월 22일 근린공원이 된 장충단공원은 자연공원인 남산공원의 일부로 흡수, 합병되었다. 나머지 구역은 장충단공원이라는 예전의 이름 그대로 불리고 있다. 장충단공원 일대는 장충단비, 수표교, 승정전, 관성묘, 와룡묘 등 문화재를 비롯하여 3·1운동 기념비, 한국유림독립운동파리장서비, 만해 한용운 시비와 유관순, 이준, 김용환 선생 동상 등이 있다.', '2026-06-29 14:38:30.618');


